		public static void CheckCodes()
		{
			bool flag = true;
			flag &= Global.CheckAllProtoBufContract(Assembly.GetExecutingAssembly());
			flag &= Global.CheckAllProtoBufContract(Assembly.Load("Tmsk.Contract"));
			flag &= Global.CheckDuplicateEnum(typeof(TCPGameServerCmds));
			flag &= Global.CheckDuplicateEnum(typeof(SaleGoodsConsts));
			flag &= Global.CheckDuplicateEnum(typeof(MagicActionIDs));
			flag &= Global.CheckDuplicateEnum(typeof(GongNengIDs));
			flag &= Global.CheckDuplicateEnum(typeof(SceneUIClasses));
			flag &= Global.CheckDuplicateEnum(typeof(ExtPropIndexes));
			flag &= Global.CheckDuplicateEnum(typeof(ItemCategories));
			flag &= Global.CheckDuplicateEnum(typeof(ActivityTypes));
			flag &= Global.CheckDuplicateFieldValue(typeof(RoleParamName));
			flag &= Global.PrepareProtoBufMetadata(Assembly.GetExecutingAssembly());
			if (!(flag & Global.PrepareProtoBufMetadata(Assembly.Load("Tmsk.Contract"))))
			{
				Console.WriteLine("代码检查发现问题,请尽快反馈给研发部\n\n");
			}
		}

		public static bool CheckDuplicateEnum(Type type)
		{
			bool result = true;
			HashSet<int> hashSet = new HashSet<int>();
			Array enumValues = type.GetEnumValues();
			foreach (object obj in enumValues)
			{
				int num = (int)obj;
				if (!hashSet.Add(num) && !Global.DontCheckEnumNames.Contains(obj.ToString()))
				{
					LogManager.WriteLog(1000, string.Format("枚举类型[{0}]定义常量值[{1}]重复", type.ToString(), num), null, true);
					result = false;
				}
			}
			return result;
		}

		public static bool CheckDuplicateFieldValue(Type type)
		{
			bool result = true;
			HashSet<string> hashSet = new HashSet<string>();
			FieldInfo[] fields = type.GetFields();
			foreach (FieldInfo fieldInfo in fields)
			{
				string text = fieldInfo.GetValue(null).ToString();
				if (!hashSet.Add(text))
				{
					LogManager.WriteLog(1000, string.Format("类型[{0}]定义常量值[{1}]重复", type.ToString(), text), null, true);
					result = false;
				}
			}
			return result;
		}

		public static bool CheckAllProtoBufContract(Assembly assembly)
		{
			bool result = true;
			foreach (Type type in assembly.GetTypes())
			{
				bool flag = false;
				Dictionary<int, string> dictionary = new Dictionary<int, string>();
				object[] customAttributes = type.GetCustomAttributes(typeof(ProtoContractAttribute), false);
				if (customAttributes.Length > 0)
				{
					foreach (MemberInfo memberInfo in type.GetMembers(BindingFlags.DeclaredOnly | BindingFlags.Instance | BindingFlags.Public))
					{
						if (memberInfo.MemberType == MemberTypes.Constructor)
						{
							ConstructorInfo constructorInfo = memberInfo as ConstructorInfo;
							if (null != constructorInfo)
							{
								if (constructorInfo.GetParameters().Length == 0)
								{
									flag = true;
								}
							}
						}
						else if (memberInfo.MemberType == MemberTypes.Field || memberInfo.MemberType == MemberTypes.Property)
						{
							object[] customAttributes2 = memberInfo.GetCustomAttributes(typeof(ProtoMemberAttribute), false);
							foreach (object obj in customAttributes2)
							{
								ProtoMemberAttribute protoMemberAttribute = obj as ProtoMemberAttribute;
								if (null != protoMemberAttribute)
								{
									string a;
									if (dictionary.TryGetValue(protoMemberAttribute.Tag, out a) && a != memberInfo.Name)
									{
										result = false;
										Console.WriteLine("Protobuf定义{2}的Tag值{0}有重复:{1}", protoMemberAttribute.Tag, memberInfo.Name, type.ToString());
										break;
									}
									dictionary.Add(protoMemberAttribute.Tag, memberInfo.Name);
								}
							}
						}
					}
					if (!flag)
					{
						result = false;
						Console.WriteLine("Protobuf要求{0}结构必须有默认构造函数", type.ToString());
					}
				}
			}
			return result;
		}

		public static bool PrepareProtoBufMetadata(Assembly assembly)
		{
			bool flag = true;
			foreach (Type type in assembly.GetTypes())
			{
				ProtoContractAttribute protoContractAttribute = Attribute.GetCustomAttribute(type, typeof(ProtoContractAttribute)) as ProtoContractAttribute;
				if (protoContractAttribute != null)
				{
					try
					{
						flag &= RuntimeTypeModel.Default.CanSerialize(type);
					}
					catch (Exception ex)
					{
						flag = false;
						LogManager.WriteLog(1000, string.Format("{0}\r\n{1}", type.ToString(), ex.ToString()), null, true);
					}
				}
			}
			return flag;
		}

		public static void CheckConfigPathType()
		{
			Global.ConfigPathStructType = 2;
			if (!Directory.Exists(Global.GameResPath("Config")) || !Directory.Exists(Global.ResPath("Map")) || !Directory.Exists(Global.MapConfigResPath("MapConfig")) || !Directory.Exists(Global.IsolateResPath("Config")))
			{
				Global.ConfigPathStructType = 1;
				if (!Directory.Exists(Global.GameResPath("Config")) || !Directory.Exists(Global.ResPath("Map")) || !Directory.Exists(Global.MapConfigResPath("MapConfig")) || !Directory.Exists(Global.IsolateResPath("Config")))
				{
					Global.ConfigPathStructType = 0;
					if (!Directory.Exists(Global.GameResPath("Config")) || !Directory.Exists(Global.ResPath("Map")) || !Directory.Exists(Global.MapConfigResPath("MapConfig")) || !Directory.Exists(Global.IsolateResPath("Config")))
					{
						LogManager.WriteLog(1000, "配置文件目录结构不正确", null, true);
					}
				}
			}
		}

