		public static string GetXElementNodePath(XElement element)
		{
			string result;
			try
			{
				string text = element.Name.ToString();
				element = element.Parent;
				while (null != element)
				{
					text = element.Name.ToString() + "/" + text;
					element = element.Parent;
				}
				result = text;
			}
			catch (Exception)
			{
				result = "";
			}
			return result;
		}

