		public static double GetDirectionByTan(double targetX, double targetY, double currentX, double currentY)
		{
			return Global.GetDirectionByAspect((int)targetX, (int)targetY, (int)currentX, (int)currentY);
		}

		public static double GetDirectionByAspect(int targetX, int targetY, int currentX, int currentY)
		{
			int num = 0;
			if (targetX < currentX)
			{
				if (targetY < currentY)
				{
					num = 5;
				}
				else if (targetY == currentY)
				{
					num = 6;
				}
				else if (targetY > currentY)
				{
					num = 7;
				}
			}
			else if (targetX == currentX)
			{
				if (targetY < currentY)
				{
					num = 4;
				}
				else if (targetY > currentY)
				{
					num = 0;
				}
			}
			else if (targetX > currentX)
			{
				if (targetY < currentY)
				{
					num = 3;
				}
				else if (targetY == currentY)
				{
					num = 2;
				}
				else if (targetY > currentY)
				{
					num = 1;
				}
			}
			return (double)num;
		}

		public static double GetAngle(double y, double x)
		{
			return Math.Atan2(y, x) / 3.1415926535897931 * 180.0;
		}

		public static void GetAngleRangeAngle(double centerAngle, double angleLimit, out double loAngle, out double hiAngle)
		{
			loAngle = 0.0;
			hiAngle = 0.0;
			if (angleLimit <= 0.0 || angleLimit >= 360.0)
			{
				loAngle = 0.0;
				hiAngle = 360.0;
			}
			else
			{
				hiAngle = centerAngle + angleLimit / 2.0;
				if (hiAngle >= 360.0)
				{
					hiAngle -= 360.0;
				}
				loAngle = centerAngle - angleLimit / 2.0;
				if (loAngle < 0.0)
				{
					loAngle = 360.0 + loAngle;
				}
			}
		}

		public static void GetAngleRangeByDirection(int direction, double angleLimit, out double loAngle, out double hiAngle)
		{
			loAngle = 0.0;
			hiAngle = 0.0;
			if (angleLimit <= 0.0 || angleLimit >= 360.0)
			{
				loAngle = 0.0;
				hiAngle = 360.0;
			}
			else
			{
				double num = 45.0 * (double)direction;
				hiAngle = num + angleLimit / 2.0;
				if (hiAngle >= 360.0)
				{
					hiAngle -= 360.0;
				}
				loAngle = num - angleLimit / 2.0;
				if (loAngle < 0.0)
				{
					loAngle = 360.0 + loAngle;
				}
			}
		}

		public static double GetCircleAngle(Point p0, Point p1)
		{
			double result;
			if (p0 == p1)
			{
				result = 0.0;
			}
			else
			{
				double num = Math.Atan2(Math.Abs(p1.Y - p0.Y), Math.Abs(p1.X - p0.X)) * 180.0 / 3.1415926535897931;
				if (p1.X >= p0.X && p0.Y < p1.Y)
				{
					num = 90.0 - num;
				}
				else if (p1.X >= p0.X && p0.Y >= p1.Y)
				{
					num = 90.0 + num;
				}
				else if (p1.X < p0.X && p0.Y >= p1.Y)
				{
					num = 270.0 - num;
				}
				else if (p1.X < p0.X && p0.Y < p1.Y)
				{
					num = 270.0 + num;
				}
				result = num;
			}
			return result;
		}

		public static bool InAngleRange(double angle, double loAngle, double hiAngle)
		{
			bool result;
			if (hiAngle > loAngle)
			{
				result = (angle >= loAngle && angle <= hiAngle);
			}
			else
			{
				result = ((angle >= loAngle && angle < 360.0) || (angle >= 0.0 && angle <= hiAngle));
			}
			return result;
		}

		public static bool InCircleByAngle(Point target, Point center, double radius, double loAngle, double hiAngle)
		{
			bool result;
			if (target.X == center.X && target.Y == center.Y)
			{
				result = true;
			}
			else
			{
				double circleAngle = Global.GetCircleAngle(center, target);
				result = (Global.InAngleRange(circleAngle, loAngle, hiAngle) && Math.Pow(target.X - center.X, 2.0) + Math.Pow(target.Y - center.Y, 2.0) <= Math.Pow(radius, 2.0));
			}
			return result;
		}

		public static bool InCircle(Point target, Point center, double radius)
		{
			double num = Math.Pow(target.X - center.X, 2.0) + Math.Pow(target.Y - center.Y, 2.0);
			double num2 = Math.Pow(radius, 2.0);
			return num <= num2;
		}

		public static bool InCircleByGridNum(int mapCode, Point target, Point center, double radiusGridNum)
		{
			GameMap gameMap = GameManager.MapMgr.DictMaps[mapCode];
			int num = (int)(center.X / (double)gameMap.MapGridWidth);
			int num2 = (int)(center.Y / (double)gameMap.MapGridHeight);
			int num3 = (int)(target.X / (double)gameMap.MapGridWidth);
			int num4 = (int)(target.Y / (double)gameMap.MapGridHeight);
			if (num3 >= num && (double)num3 <= (double)num + radiusGridNum)
			{
				if (num4 >= num2 && (double)num4 <= (double)num2 + radiusGridNum)
				{
					return true;
				}
			}
			return false;
		}

		public static bool InPolygon(Point target, Point[] range)
		{
			int num = 0;
			int num2 = 0;
			for (int i = 0; i < range.Length; i++)
			{
				num = ((i == range.Length - 1) ? 0 : (num + 1));
				if (range[i].Y != range[num].Y && ((target.Y >= range[i].Y && target.Y < range[num].Y) || (target.Y >= range[num].Y && target.Y < range[i].Y)) && target.X < (range[num].X - range[i].X) * (target.Y - range[i].Y) / (range[num].Y - range[i].Y) + range[i].X)
				{
					num2++;
				}
			}
			return num2 % 2 > 0;
		}

		public static Point GetExtensionPoint(Point start, Point end, int Lenght)
		{
			double num = Math.Sqrt(Math.Pow(end.Y - start.Y, 2.0) + Math.Pow(end.X - start.X, 2.0)) / (double)Lenght;
			return new Point(start.X + (end.X - start.X) / num, start.Y + (end.Y - start.Y) / num);
		}

		public static double GetTwoPointDistance(Point start, Point end)
		{
			return Math.Sqrt(Math.Pow(end.X - start.X, 2.0) + Math.Pow(end.Y - start.Y, 2.0));
		}

		public static double GetTwoPointDistanceSquare(Point start, Point end)
		{
			return Math.Pow(end.X - start.X, 2.0) + Math.Pow(end.Y - start.Y, 2.0);
		}

		public static Point[] GetRectRange(double angle, Point start, Point end, int radius)
		{
			Point[] result;
			if ((angle >= 45.0 && angle <= 135.0) || (angle >= -135.0 && angle <= -45.0))
			{
				result = new Point[]
				{
					new Point(start.X - (double)radius, start.Y),
					new Point(start.X + (double)radius, start.Y),
					new Point(end.X + (double)radius, end.Y),
					new Point(end.X - (double)radius, end.Y)
				};
			}
			else
			{
				result = new Point[]
				{
					new Point(start.X, start.Y - (double)radius),
					new Point(start.X, start.Y + (double)radius),
					new Point(end.X, end.Y + (double)radius),
					new Point(end.X, end.Y - (double)radius)
				};
			}
			return result;
		}

		public static double GetAnimationTimeConsuming(Point start, Point end, int zoomX, int zoomY, double unitCost)
		{
			return Math.Sqrt(Math.Pow((end.X - start.X) / (double)zoomX, 2.0) + Math.Pow((end.Y - start.Y) / (double)zoomY, 2.0)) * unitCost;
		}

		public static bool Bresenham(List<ANode> s, int x1, int y1, int x2, int y2, NodeGrid nodeGrid)
		{
			bool flag = Math.Abs(y2 - y1) > Math.Abs(x2 - x1);
			if (flag)
			{
				int num = x1;
				x1 = y1;
				y1 = num;
				num = x2;
				x2 = y2;
				y2 = num;
			}
			bool flag2 = false;
			if (x1 > x2)
			{
				int num = x1;
				x1 = x2;
				x2 = num;
				num = y1;
				y1 = y2;
				y2 = num;
				flag2 = true;
			}
			int num2 = x2 - x1;
			int num3 = Math.Abs(y2 - y1);
			int num4 = num2 / 2;
			int i = x1;
			int num5 = y1;
			while (i <= x2)
			{
				if (flag)
				{
					if (null != s)
					{
						s.Add(new ANode(num5, i));
					}
				}
				else if (null != s)
				{
					s.Add(new ANode(i, num5));
				}
				num4 -= num3;
				if (num4 < 0)
				{
					if (y1 < y2)
					{
						num5++;
					}
					else
					{
						num5--;
					}
					num4 += num2;
				}
				i++;
			}
			if (flag2)
			{
				s.Reverse();
			}
			List<ANode> linearPath = Global.GetLinearPath(s, nodeGrid);
			bool result = linearPath.Count == s.Count;
			s.Clear();
			for (int j = 0; j < linearPath.Count; j++)
			{
				s.Add(linearPath[j]);
			}
			return result;
		}

		private static List<ANode> GetLinearPath(List<ANode> s, NodeGrid nodeGrid)
		{
			List<ANode> list = new List<ANode>();
			for (int i = 0; i < s.Count; i++)
			{
				if (!nodeGrid.isWalkable(s[i].x, s[i].y))
				{
					break;
				}
				list.Add(s[i]);
			}
			return list;
		}

		public static Point GetExtensionPointByObs(GameClient client, Point start, Point end, int Lenght)
		{
			GameMap gameMap = GameManager.MapMgr.DictMaps[client.ClientData.MapCode];
			Point result;
			if (start.X >= (double)gameMap.MapWidth || start.X < 0.0 || start.Y >= (double)gameMap.MapHeight || start.Y < 0.0)
			{
				result = new Point(-1.0, -1.0);
			}
			else
			{
				Point extensionPoint = Global.GetExtensionPoint(start, end, Lenght);
				List<ANode> list = new List<ANode>();
				Global.Bresenham(list, (int)(end.X / (double)gameMap.MapGridWidth), (int)(end.Y / (double)gameMap.MapGridHeight), (int)(extensionPoint.X / (double)gameMap.MapGridWidth), (int)(extensionPoint.Y / (double)gameMap.MapGridHeight), gameMap.MyNodeGrid);
				if (list.Count <= 0)
				{
					result = new Point(-1.0, -1.0);
				}
				else
				{
					extensionPoint = new Point((double)(list[list.Count - 1].x * gameMap.MapGridWidth), (double)(list[list.Count - 1].y * gameMap.MapGridHeight));
					result = extensionPoint;
				}
			}
			return result;
		}

		public static Point GetAPointIn4Direction(Point p, int offset, NodeGrid nodeGrd, int mapWidth, int mapHeight, int gridWidth, int gridHeight)
		{
			int num = (int)p.X;
			int num2 = (int)p.Y;
			num = Global.GMax(0, num);
			num2 = Global.GMax(0, num2);
			num = Global.GMin(mapWidth, num);
			num2 = Global.GMin(mapHeight, num2);
			Point result;
			if (nodeGrd.isWalkable(num / gridWidth, num2 / gridHeight))
			{
				result = new Point((double)num, (double)num2);
			}
			else
			{
				num = (int)p.X - offset;
				num2 = (int)p.Y;
				num = Global.GMax(0, num);
				num2 = Global.GMax(0, num2);
				num = Global.GMin(mapWidth, num);
				num2 = Global.GMin(mapHeight, num2);
				if (nodeGrd.isWalkable(num / gridWidth, num2 / gridHeight))
				{
					result = new Point((double)num, (double)num2);
				}
				else
				{
					num = (int)p.X + offset;
					num2 = (int)p.Y;
					num = Global.GMax(0, num);
					num2 = Global.GMax(0, num2);
					num = Global.GMin(mapWidth, num);
					num2 = Global.GMin(mapHeight, num2);
					if (nodeGrd.isWalkable(num / gridWidth, num2 / gridHeight))
					{
						result = new Point((double)num, (double)num2);
					}
					else
					{
						num = (int)p.X;
						num2 = (int)p.Y - offset;
						num = Global.GMax(0, num);
						num2 = Global.GMax(0, num2);
						num = Global.GMin(mapWidth, num);
						num2 = Global.GMin(mapHeight, num2);
						if (nodeGrd.isWalkable(num / gridWidth, num2 / gridHeight))
						{
							result = new Point((double)num, (double)num2);
						}
						else
						{
							num = (int)p.X;
							num2 = (int)p.Y + offset;
							num = Global.GMax(0, num);
							num2 = Global.GMax(0, num2);
							num = Global.GMin(mapWidth, num);
							num2 = Global.GMin(mapHeight, num2);
							if (nodeGrd.isWalkable(num / gridWidth, num2 / gridHeight))
							{
								result = new Point((double)num, (double)num2);
							}
							else
							{
								result = p;
							}
						}
					}
				}
			}
			return result;
		}

		public static bool InSquare(Point center, Point target, int radius, int Width, int DirectionX, int DirectionY)
		{
			double num = target.X - center.X;
			double num2 = target.Y - center.Y;
			int num3 = (int)Global.GetTwoPointDistance(center, target);
			int num4 = (int)Math.Sqrt((double)(DirectionX * DirectionX + DirectionY * DirectionY));
			bool result;
			if (num4 <= 0)
			{
				result = false;
			}
			else
			{
				int num5 = (int)(num * (double)DirectionX + num2 * (double)DirectionY) / num4;
				int num6 = (int)((double)(num3 * num3) - (double)(num5 * num5));
				if (num6 < 0)
				{
					num6 = 0;
				}
				int num7 = (int)Math.Sqrt((double)num6) - 30;
				result = (-radius / 2 <= num5 && num5 <= radius / 2 && -Width / 2 <= num7 && num7 <= Width / 2);
			}
			return result;
		}

		public static Point GetAPointInCircle(Point center, int r, int ao)
		{
			if (ao > 180)
			{
				ao -= 360;
			}
			double x = center.X;
			double y = center.Y;
			double x2 = x + (double)r * Math.Sin((double)ao * 3.1415926535897931 / 180.0);
			double y2 = y + (double)r * Math.Cos((double)ao * 3.1415926535897931 / 180.0);
			return new Point(x2, y2);
		}

		public static int FindEquipCode(List<GoodsData> goodsList, int category)
		{
			int result;
			if (goodsList == null)
			{
				result = -1;
			}
			else
			{
				lock (goodsList)
				{
					for (int i = 0; i < goodsList.Count; i++)
					{
						if (goodsList[i].Using > 0)
						{
							SystemXmlItem systemXmlItem = null;
							if (GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsList[i].GoodsID, out systemXmlItem))
							{
								if ((category >= 0 && category <= 4) || (category >= 7 && category <= 21))
								{
									return systemXmlItem.GetIntValue("EquipCode", -1);
								}
							}
						}
					}
				}
				result = -1;
			}
			return result;
		}

		public static SafeClientData GetSafeClientDataFromLocalOrDB(int otherRoleID)
		{
			SafeClientData safeClientData = null;
			GameClient gameClient = GameManager.ClientMgr.FindClient(otherRoleID);
			if (null == gameClient)
			{
				byte[] array = null;
				if (TCPProcessCmdResults.RESULT_FAILED != Global.RequestToDBServer3(TCPClientPool.getInstance(), TCPOutPacketPool.getInstance(), 275, string.Format("{0}:{1}", -1, otherRoleID), out array, 0))
				{
					int num = BitConverter.ToInt32(array, 0);
					RoleDataEx roleDataEx = DataHelper.BytesToObject<RoleDataEx>(array, 6, num - 2);
					if (roleDataEx.RoleID < 0)
					{
						return null;
					}
					safeClientData = new SafeClientData();
					safeClientData.RoleData = roleDataEx;
				}
			}
			else
			{
				safeClientData = gameClient.ClientData;
			}
			return safeClientData;
		}

