		public static IObject GetTargetObject(int mapCode, int enemy)
		{
			GSpriteTypes spriteType = Global.GetSpriteType((uint)enemy);
			IObject result;
			if (spriteType == GSpriteTypes.Monster)
			{
				result = GameManager.MonsterMgr.FindMonster(mapCode, enemy);
			}
			else if (spriteType == GSpriteTypes.BiaoChe)
			{
				result = BiaoCheManager.FindBiaoCheByID(enemy);
			}
			else if (spriteType == GSpriteTypes.JunQi)
			{
				result = JunQiManager.FindJunQiByID(enemy);
			}
			else if (spriteType == GSpriteTypes.FakeRole)
			{
				result = JunQiManager.FindJunQiByID(enemy);
			}
			else
			{
				result = GameManager.ClientMgr.FindClient(enemy);
			}
			return result;
		}

		public static Point CalcTargetObjectRealPos(int mapCode, int enemy, Point targetPos)
		{
			Point result = targetPos;
			IObject targetObject = Global.GetTargetObject(mapCode, enemy);
			if (null != targetObject)
			{
				result = targetObject.CurrentPos;
			}
			return result;
		}

		public static void DoInjure(Monster attacker, int enemy, Point targetPos)
		{
			if (!attacker.IsMonsterDongJie())
			{
				if (GameManager.GridMagicHelperMgrEx.GetObjectAddMapBuffer(attacker.RoleID) <= 0)
				{
					Point point = Global.CalcTargetObjectRealPos(attacker.MonsterZoneNode.MapCode, enemy, targetPos);
					if (attacker.CurrentMagic <= 0 || attacker.MagicFinish != 1)
					{
						SpriteAttack.ProcessAttackByMonster(attacker, enemy, (int)targetPos.X, (int)targetPos.Y, (int)point.X, (int)point.Y, attacker.CurrentMagic, -1, 1.0);
					}
					if (-1 != attacker.LockObject)
					{
						int autoUseSkillID = attacker.GetAutoUseSkillID();
						if (autoUseSkillID != attacker.CurrentMagic)
						{
							if (autoUseSkillID > 0)
							{
								GameManager.MonsterMgr.DoMagicAttack(attacker, autoUseSkillID, attacker.LockObject, false);
							}
						}
					}
				}
			}
		}

