		public static Point GetMapPoint(ObjectTypes objType, int mapCode, int toX, int toY, int radius)
		{
			Point point = new Point((double)toX, (double)toY);
			GameMap gameMap = null;
			Point result;
			if (!GameManager.MapMgr.DictMaps.TryGetValue(mapCode, out gameMap))
			{
				result = point;
			}
			else
			{
				int minV = Math.Max(0, toX - radius);
				int maxV = Math.Min(gameMap.MapWidth - 1, toX + radius);
				int minV2 = Math.Max(0, toY - radius);
				int maxV2 = Math.Min(gameMap.MapHeight - 1, toY + radius);
				Point p = new Point((double)Global.GetRandomNumber(minV, maxV), (double)Global.GetRandomNumber(minV2, maxV2));
				if (!Global.InObs(objType, mapCode, (int)p.X, (int)p.Y, 0, 0))
				{
					result = Global.ForceCorrectPoint(mapCode, p);
				}
				else
				{
					Point agridPointIn4Direction = new Point((double)((int)(p.X / (double)gameMap.MapGridWidth)), (double)((int)(p.Y / (double)gameMap.MapGridHeight)));
					agridPointIn4Direction = Global.GetAGridPointIn4Direction(objType, agridPointIn4Direction, mapCode, 0, false);
					if (Global.InObsByGridXY(objType, mapCode, (int)agridPointIn4Direction.X, (int)agridPointIn4Direction.Y, 0, 0))
					{
						result = point;
					}
					else
					{
						result = new Point(agridPointIn4Direction.X * (double)gameMap.MapGridWidth + (double)(gameMap.MapGridWidth / 2), agridPointIn4Direction.Y * (double)gameMap.MapGridHeight + (double)(gameMap.MapGridHeight / 2));
					}
				}
			}
			return result;
		}

