		public static bool InArea(int centerGridX, int centerGridY, int radius, Point grid)
		{
			int num = (int)Math.Abs(grid.X - (double)centerGridX);
			int num2 = (int)Math.Abs(grid.Y - (double)centerGridY);
			bool result;
			if (num > radius || num2 > radius)
			{
				result = false;
			}
			else
			{
				num2 = radius - num;
				int num3 = centerGridY - num2;
				int num4 = centerGridY + num2;
				result = (grid.Y >= (double)num3 && grid.Y <= (double)num4);
			}
			return result;
		}

