		{
			int num = gridX;
			int num2 = gridY;
			switch (direction)
			{
			case 0:
				num = gridX;
				num2 = gridY + 1;
				break;
			case 1:
				num = gridX + 1;
				num2 = gridY + 1;
				break;
			case 2:
				num = gridX + 1;
				num2 = gridY;
				break;
			case 3:
				num = gridX + 1;
				num2 = gridY - 1;
				break;
			case 4:
				num = gridX;
				num2 = gridY - 1;
				break;
			case 5:
				num = gridX - 1;
				num2 = gridY - 1;
				break;
			case 6:
				num = gridX - 1;
				num2 = gridY;
				break;
			case 7:
				num = gridX - 1;
				num2 = gridY + 1;
				break;
			}
			return new Point((double)num, (double)num2);
		}

		public static List<Point> GetGridPointByDirection(int direction, int gridX, int gridY, int nNum)
		{
			List<Point> list = new List<Point>();
			int num = gridX;
			int num2 = gridY;
			for (int i = 0; i < nNum; i++)
			{
				switch (direction)
				{
				case 0:
					num2++;
					break;
				case 1:
					num++;
					num2++;
					break;
				case 2:
					num++;
					break;
				case 3:
					num++;
					num2--;
					break;
				case 4:
					num2--;
					break;
				case 5:
					num--;
					num2--;
					break;
				case 6:
					num--;
					break;
				case 7:
