		public static int[] StringArray2IntArray(string[] sa, int start, int count)
		{
			int[] result;
			if (sa == null)
			{
				result = null;
			}
			else if (start < 0 || start >= sa.Length)
			{
				result = null;
			}
			else if (count <= 0)
			{
				result = null;
			}
			else if (sa.Length - start < count)
			{
				result = null;
			}
			else
			{
				int[] array = new int[count];
				for (int i = 0; i < count; i++)
				{
					string text = sa[start + i].Trim();
					text = (string.IsNullOrEmpty(text) ? "0" : text);
					array[i] = Convert.ToInt32(text);
				}
				result = array;
			}
			return result;
		}

		public static Point StrToPoint(string str)
		{
			Point result;
			if (string.IsNullOrEmpty(str))
			{
				result = new Point(double.NaN, double.NaN);
			}
			else
			{
				str = str.Trim();
				if (str == "")
				{
					result = new Point(double.NaN, double.NaN);
				}
				else
				{
					string[] array = str.Split(new char[]
					{
						','
					});
					if (array.Length != 2)
					{
						result = new Point(double.NaN, double.NaN);
					}
					else
					{
						try
						{
							string text = array[0].Trim();
							text = (string.IsNullOrEmpty(str) ? "0" : text);
							string text2 = array[1].Trim();
							text2 = (string.IsNullOrEmpty(str) ? "0" : text2);
							return new Point(Convert.ToDouble(text), Convert.ToDouble(text2));
						}
						catch (Exception)
						{
						}
						result = new Point(double.NaN, double.NaN);
					}
				}
			}
			return result;
		}

