		public static int AddGoodsDBCommand(TCPOutPacketPool pool, GameClient client, int goodsID, int goodsNum, int quality, string props, int forgeLevel, int binding, int site, string jewelList, bool useOldGrid, int newHint, string goodsFromWhere, string endTime = "1900-01-01 12:00:00", int addPropIndex = 0, int bornIndex = 0, int lucky = 0, int strong = 0, int ExcellenceProperty = 0, int nAppendPropLev = 0, int nEquipChangeLife = 0, List<int> washProps = null, List<int> elementhrtsProps = null, int juHun_level = 0, bool onLine = true)
		{
			int result;
			if (goodsNum <= 0)
			{
				result = 0;
			}
			else
			{
				int num = 0;
				int num2 = Global.GetGoodsGridNumByID(goodsID);
				num2 = Global.GMax(num2, 1);
				int num3 = (goodsNum - 1) / num2 + 1;
				for (int i = 0; i < num3; i++)
				{
					int goodsNum2 = num2;
					if (i >= num3 - 1 && goodsNum % num2 > 0)
					{
						goodsNum2 = goodsNum % num2;
					}
					num = Global.AddGoodsDBCommand_Hook(pool, client, goodsID, goodsNum2, quality, props, forgeLevel, binding, site, jewelList, useOldGrid, newHint, goodsFromWhere, false, endTime, addPropIndex, bornIndex, lucky, strong, ExcellenceProperty, nAppendPropLev, nEquipChangeLife, false, washProps, elementhrtsProps, "1900-01-01 12:00:00", juHun_level, onLine);
					if (num < 0)
					{
						return num;
					}
				}
				result = num;
			}
			return result;
		}

