		public static int GetGoodsDataPrice(GoodsData goodsData)
		{
			int result;
			if (null == goodsData)
			{
				result = 0;
			}
			else if (goodsData.GCount <= 0)
			{
				result = 0;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem))
				{
					result = 0;
				}
				else
				{
					int intValue = systemXmlItem.GetIntValue("PriceTwo", -1);
					int intValue2 = systemXmlItem.GetIntValue("Categoriy", -1);
					if (intValue2 < 0 || intValue2 > 49)
					{
						if (Global.GetGoodsUsingNum(goodsData.GoodsID) <= 1)
						{
							result = (int)((double)intValue / 5.0) * goodsData.GCount;
						}
						else
						{
							result = (int)((double)intValue / 5.0);
						}
					}
					else
					{
						double[] doubleArrayValue = systemXmlItem.GetDoubleArrayValue("EquipProps", ',');
						if (doubleArrayValue.Length >= 2)
						{
							double num = doubleArrayValue[0];
							if (num <= 0.001)
							{
								result = 0;
							}
							else
							{
								int num2 = (int)((double)intValue / 5.0 * (num - (double)goodsData.Strong) / num);
								if (Global.GetGoodsUsingNum(goodsData.GoodsID) <= 1)
								{
									num2 *= goodsData.GCount;
								}
								result = num2;
							}
						}
						else
						{
							result = 0;
						}
					}
				}
			}
			return result;
		}

