		public static void ResetBagAllGoods(GameClient client, bool notifyClient = true)
		{
			byte[] array = null;
			if (client.ClientData.GoodsDataList != null)
			{
				lock (client.ClientData.GoodsDataList)
				{
					Dictionary<string, GoodsData> dictionary = new Dictionary<string, GoodsData>();
					List<GoodsData> list = new List<GoodsData>();
					List<GoodsData> list2 = new List<GoodsData>();
					for (int i = 0; i < client.ClientData.GoodsDataList.Count; i++)
					{
						if (client.ClientData.GoodsDataList[i].Using <= 0)
						{
							if (RebornEquip.IsRebornType(client.ClientData.GoodsDataList[i].GoodsID))
							{
								list2.Add(client.ClientData.GoodsDataList[i]);
							}
							client.ClientData.GoodsDataList[i].BagIndex = 0;
							int goodsGridNumByID = Global.GetGoodsGridNumByID(client.ClientData.GoodsDataList[i].GoodsID);
							if (goodsGridNumByID > 1)
							{
								GoodsData goodsData = null;
								string key = string.Format("{0}_{1}_{2}_{3}", new object[]
								{
									client.ClientData.GoodsDataList[i].GoodsID,
									client.ClientData.GoodsDataList[i].Binding,
									Global.DateTimeTicks(client.ClientData.GoodsDataList[i].Starttime),
									Global.DateTimeTicks(client.ClientData.GoodsDataList[i].Endtime)
								});
								if (dictionary.TryGetValue(key, out goodsData))
								{
									int num = Global.GMin(goodsGridNumByID - goodsData.GCount, client.ClientData.GoodsDataList[i].GCount);
									goodsData.GCount += num;
									client.ClientData.GoodsDataList[i].GCount -= num;
									client.ClientData.GoodsDataList[i].BagIndex = 1;
									goodsData.BagIndex = 1;
									if (!Global.ResetBagGoodsData(client, client.ClientData.GoodsDataList[i]))
									{
										break;
									}
									EventLogManager.AddGoodsEvent(client, OpTypes.Sort, OpTags.None, goodsData.GoodsID, (long)goodsData.Id, num, goodsData.GCount, "整理背包");
									EventLogManager.AddGoodsEvent(client, OpTypes.Sort, OpTags.None, client.ClientData.GoodsDataList[i].GoodsID, (long)client.ClientData.GoodsDataList[i].Id, -num, client.ClientData.GoodsDataList[i].GCount, "整理背包");
									if (goodsData.GCount >= goodsGridNumByID)
									{
										if (client.ClientData.GoodsDataList[i].GCount > 0)
										{
											dictionary[key] = client.ClientData.GoodsDataList[i];
										}
										else
										{
											dictionary.Remove(key);
											list.Add(client.ClientData.GoodsDataList[i]);
										}
									}
									else if (client.ClientData.GoodsDataList[i].GCount <= 0)
									{
										list.Add(client.ClientData.GoodsDataList[i]);
									}
								}
								else
								{
									dictionary[key] = client.ClientData.GoodsDataList[i];
								}
							}
						}
					}
					for (int i = 0; i < list.Count; i++)
					{
						client.ClientData.GoodsDataList.Remove(list[i]);
					}
					for (int i = 0; i < list2.Count; i++)
					{
						client.ClientData.GoodsDataList.Remove(list2[i]);
						int idleSlotOfRebornGoods = RebornEquip.GetIdleSlotOfRebornGoods(client);
						list2[i].BagIndex = idleSlotOfRebornGoods;
						list2[i].Site = 15000;
						if (client.ClientData.RebornGoodsDataList == null)
						{
							List<GoodsData> list3 = new List<GoodsData>();
							list3.Add(list2[i]);
							client.ClientData.RebornGoodsDataList = list3;
						}
						else
						{
							client.ClientData.RebornGoodsDataList.Add(list2[i]);
						}
						string cmdData = string.Format("{0}:{1}:{2}:{3}:{4}:{5}:{6}:{7}:{8}", new object[]
						{
							client.ClientData.RoleID,
							3,
							list2[i].Id,
							list2[i].GoodsID,
							list2[i].Using,
							list2[i].Site,
							list2[i].GCount,
							list2[i].BagIndex,
							""
						});
						if (TCPProcessCmdResults.RESULT_OK != Global.ModifyGoodsByCmdParams(client, cmdData, "客户端修改", null))
						{
						}
					}
					client.ClientData.GoodsDataList.Sort((GoodsData x, GoodsData y) => y.GoodsID - x.GoodsID);
					int num2 = 0;
					for (int i = 0; i < client.ClientData.GoodsDataList.Count; i++)
					{
						if (client.ClientData.GoodsDataList[i].Using <= 0)
						{
							if (GameManager.Flag_OptimizationBagReset)
							{
								bool flag2 = client.ClientData.GoodsDataList[i].BagIndex > 0;
								client.ClientData.GoodsDataList[i].BagIndex = num2++;
								if (flag2)
								{
									if (!Global.ResetBagGoodsData(client, client.ClientData.GoodsDataList[i]))
									{
										break;
									}
								}
							}
							else
							{
								client.ClientData.GoodsDataList[i].BagIndex = num2++;
								if (!Global.ResetBagGoodsData(client, client.ClientData.GoodsDataList[i]))
								{
									break;
								}
							}
						}
					}
					array = DataHelper.ObjectToBytes<List<GoodsData>>(client.ClientData.GoodsDataList);
				}
				if (notifyClient)
				{
					TCPOutPacket tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(Global._TCPManager.TcpOutPacketPool, array, 0, array.Length, 235);
					Global._TCPManager.MySocketListener.SendData(client.ClientSocket, tcpOutPacket, true);
				}
			}
		}

