		public static long DateTimeTicks(string strDateTime)
		{
			try
			{
				DateTime dateTime;
				if (!DateTime.TryParse(strDateTime, out dateTime))
				{
					return 0L;
				}
				return dateTime.Ticks;
			}
			catch (Exception)
			{
			}
			return 0L;
		}

