		public static bool IsTimeLimitGoods(GoodsData goodsData)
		{
			return !string.IsNullOrEmpty(goodsData.Endtime) && !Global.DateTimeEqual(goodsData.Endtime, "1900-01-01 12:00:00");
		}

		public static bool CanExchangeCategoriy(GoodsData goodsData)
		{
			SystemXmlItem systemXmlItem = null;
			bool result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem))
			{
				result = false;
			}
			else
			{
				int intValue = systemXmlItem.GetIntValue("Categoriy", -1);
				result = ((intValue < 800 || intValue >= 816) && intValue != 901 && (intValue < 910 || intValue > 928) && intValue != 940 && intValue != 702);
			}
			return result;
		}

		public static bool IsGoodsTimeOver(GoodsData goodsData)
		{
			bool result;
			if (!Global.IsTimeLimitGoods(goodsData))
			{
				result = false;
			}
			else
			{
				long num = TimeUtil.NOW() * 10000L;
				long num2 = Global.DateTimeTicks(goodsData.Endtime);
				result = (num >= num2);
			}
			return result;
		}

		public static bool IsGoodsNotReachStartTime(GoodsData goodsData)
		{
			bool result;
			if (!Global.IsTimeLimitGoods(goodsData))
			{
				result = false;
			}
			else
			{
				long num = TimeUtil.NOW() * 10000L;
				long num2 = Global.DateTimeTicks(goodsData.Starttime);
				result = (num < num2);
			}
			return result;
		}

