		public static int GetGoodsLimitNum(GameClient client, int goodsID)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem))
			{
				result = 0;
			}
			else
			{
				if (601 == systemXmlItem.GetIntValue("Categoriy", -1))
				{
					int[] vipUseBindTongQianGoodsIDNum = Global.GetVipUseBindTongQianGoodsIDNum();
					if (vipUseBindTongQianGoodsIDNum != null && vipUseBindTongQianGoodsIDNum.Length == 4)
					{
						if (0 == Global.GetVipType(client))
						{
							return vipUseBindTongQianGoodsIDNum[0];
						}
						if (1 == Global.GetVipType(client))
						{
							return vipUseBindTongQianGoodsIDNum[1];
						}
						if (3 == Global.GetVipType(client))
						{
							return vipUseBindTongQianGoodsIDNum[2];
						}
						if (6 == Global.GetVipType(client))
						{
							return vipUseBindTongQianGoodsIDNum[3];
						}
					}
				}
				int intValue = systemXmlItem.GetIntValue("ID", -1);
				if (5001 == intValue || 7037 == intValue)
				{
					int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
					int vipLevel = client.ClientData.VipLevel;
					int[] array = null;
					if (5001 == intValue)
					{
						array = GameManager.systemParamsList.GetParamValueIntArrayByName("VIPJiPinGuoShiAdd", ',');
					}
					else if (7037 == intValue)
					{
						array = GameManager.systemParamsList.GetParamValueIntArrayByName("VIPJinTiaoAdd", ',');
					}
					if (vipLevel > 0 && array != null && array[vipLevel] > 0)
					{
						return systemXmlItem.GetIntValue("DayLimit", -1) + array[vipLevel];
					}
				}
				result = systemXmlItem.GetIntValue("DayLimit", -1);
			}
			return result;
		}

		public static int GetGoodsPriceByMoneyType(int goodsID, int moneyType)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem))
			{
				result = 0;
			}
			else
			{
				string name = "";
				if (moneyType <= 14)
				{
					if (moneyType != 1)
					{
						if (moneyType != 8)
						{
							switch (moneyType)
							{
							case 13:
								name = "JinYuanPrice";
								break;
							case 14:
								name = "JunGongPrice";
								break;
							}
						}
						else
						{
							name = "PriceTwo";
						}
					}
					else
					{
						name = "PriceOne";
					}
				}
				else if (moneyType != 20)
				{
					if (moneyType != 30)
					{
						if (moneyType == 90)
						{
							name = "ZhanHunPrice";
						}
					}
					else
					{
						name = "JiFenPrice";
					}
				}
				else
				{
					name = "LieShaPrice";
				}
				result = Math.Max(0, systemXmlItem.GetIntValue(name, -1));
			}
			return result;
		}

