		public static TCPProcessCmdResults SplitGoodsByCmdParams(GameClient client, TMSKSocket socket, int nID, int roleID, int id, int site, int goodsID, int newNum, bool sendErroMsg = true)
		{
			TCPManager tcpmanager = Global._TCPManager;
			TCPClientPool tcpClientPool = Global._TCPManager.tcpClientPool;
			TCPOutPacketPool tcpOutPacketPool = Global._TCPManager.TcpOutPacketPool;
			newNum = Global.GMax(newNum, 1);
			GoodsData goodsData = null;
			if (site == 0)
			{
				goodsData = Global.GetGoodsByDbID(client, id);
			}
			else if (site == -1000)
			{
				goodsData = Global.GetPortableGoodsDataByDbID(client, id);
			}
			else if (site == 15000)
			{
				goodsData = RebornEquip.GetRebornGoodsByDbID(client, id);
			}
			else if (site == 15001)
			{
				goodsData = RebornEquip.GetRebornStoreGoodsByDbID(client, id);
			}
			else if (site == 16000)
			{
				goodsData = MountHolyStampManager.GetMountHolyGoodsByDbID(client, id);
			}
			TCPProcessCmdResults result;
			if (null == goodsData)
			{
				if (sendErroMsg)
				{
					LogManager.WriteLog(2, string.Format("定位物品对象1失败, CMD={0}, Client={1}, RoleID={2}, GoodsDbID={3}", new object[]
					{
						(TCPGameServerCmds)nID,
						Global.GetSocketRemoteEndPoint(socket, false),
						roleID,
						id
					}), null, true);
				}
				result = TCPProcessCmdResults.RESULT_OK;
			}
			else if (goodsData.GoodsID != goodsID)
			{
				if (sendErroMsg)
				{
					LogManager.WriteLog(2, string.Format("监测到复制物品的操作立即断开, CMD={0}, Client={1}, RoleID={2}, GoodsDbID={3}", new object[]
					{
						(TCPGameServerCmds)nID,
						Global.GetSocketRemoteEndPoint(socket, false),
						roleID,
						id
					}), null, true);
				}
				result = TCPProcessCmdResults.RESULT_FAILED;
			}
			else if (Global.IsTimeLimitGoods(goodsData))
			{
				result = TCPProcessCmdResults.RESULT_OK;
			}
			else if (newNum >= goodsData.GCount)
			{
				result = TCPProcessCmdResults.RESULT_OK;
			}
			else
			{
				int goodsGridNumByID = Global.GetGoodsGridNumByID(goodsID);
				if (goodsGridNumByID <= 1)
				{
					result = TCPProcessCmdResults.RESULT_OK;
				}
				else
				{
					int goodsUsingNum = Global.GetGoodsUsingNum(goodsID);
					if (goodsUsingNum > 1)
					{
						result = TCPProcessCmdResults.RESULT_OK;
					}
					else
					{
						if (site == 0)
						{
							if (!Global.CanAddGoods(client, goodsID, newNum, goodsData.Binding, "1900-01-01 12:00:00", false, false))
							{
								if (sendErroMsg)
								{
									GameManager.ClientMgr.NotifyImportantMsg(tcpmanager.MySocketListener, tcpOutPacketPool, client, GLang.GetLang(127, new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 1);
								}
								return TCPProcessCmdResults.RESULT_OK;
							}
						}
						else if (site == -1000)
						{
							if (!Global.CanPortableAddGoods(client, goodsID, newNum, goodsData.Binding))
							{
								if (sendErroMsg)
								{
									GameManager.ClientMgr.NotifyImportantMsg(tcpmanager.MySocketListener, tcpOutPacketPool, client, GLang.GetLang(128, new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
								}
								return TCPProcessCmdResults.RESULT_OK;
							}
						}
						else if (site == 15000)
						{
							if (!RebornEquip.CanAddGoodsDataList2(client, goodsID, newNum, goodsData.Binding, "1900-01-01 12:00:00", false))
							{
								if (sendErroMsg)
								{
									GameManager.ClientMgr.NotifyImportantMsg(tcpmanager.MySocketListener, tcpOutPacketPool, client, GLang.GetLang(127, new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 1);
								}
								return TCPProcessCmdResults.RESULT_OK;
							}
						}
						else if (site == 15001)
						{
							if (!RebornEquip.CanPortableAddGoods(client))
							{
								if (sendErroMsg)
								{
									GameManager.ClientMgr.NotifyImportantMsg(tcpmanager.MySocketListener, tcpOutPacketPool, client, GLang.GetLang(128, new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
								}
								return TCPProcessCmdResults.RESULT_OK;
							}
						}
						string[] array = null;
						string strcmd = Global.FormatUpdateDBGoodsStr(new object[]
						{
							roleID,
							id,
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							goodsData.GCount - newNum,
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*",
							"*"
						});
						TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer(tcpClientPool, tcpOutPacketPool, 10006, strcmd, out array, client.ServerId);
						if (tcpprocessCmdResults == TCPProcessCmdResults.RESULT_FAILED)
						{
							result = TCPProcessCmdResults.RESULT_OK;
						}
						else if (array.Length <= 0 || Convert.ToInt32(array[1]) < 0)
						{
							result = TCPProcessCmdResults.RESULT_OK;
						}
						else
						{
							goodsData.GCount -= newNum;
							Global.ModRoleGoodsEvent(client, goodsData, -newNum, "物品拆分", false);
							EventLogManager.AddGoodsEvent(client, OpTypes.AddOrSub, OpTags.None, goodsData.GoodsID, (long)goodsData.Id, -newNum, goodsData.GCount, "物品拆分");
							GameManager.ClientMgr.NotifyModGoods(tcpmanager.MySocketListener, tcpOutPacketPool, client, 3, goodsData.Id, goodsData.Using, goodsData.Site, goodsData.GCount, goodsData.BagIndex, 0);
							int num = Global.AddGoodsDBCommand(tcpOutPacketPool, client, goodsID, newNum, 0, "", 0, goodsData.Binding, goodsData.Site, "", false, 0, "物品拆分", goodsData.Endtime, 0, 0, 0, 0, 0, 0, 0, null, null, 0, true);
							if (num < 0)
							{
								if (sendErroMsg)
								{
									LogManager.WriteLog(2, string.Format("拆分物品时, 拆分生成新物品失败, CMD={0}, Client={1}, RoleID={2}, GoodsDbID={3}", new object[]
									{
										(TCPGameServerCmds)nID,
										Global.GetSocketRemoteEndPoint(socket, false),
										roleID,
										id
									}), null, true);
								}
							}
							result = TCPProcessCmdResults.RESULT_OK;
						}
					}
				}
			}
			return result;
		}

