		public static TCPProcessCmdResults ModifyGoodsByCmdParams(GameClient client, string cmdData, string msg = "客户端修改", GoodsData goodsData = null)
		{
			string[] array = cmdData.Split(new char[]
			{
				':'
			});
			TCPProcessCmdResults result;
			if (array.Length != 9)
			{
				result = TCPProcessCmdResults.RESULT_FAILED;
			}
			else
			{
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				int num4 = Convert.ToInt32(array[3]);
				int num5 = Convert.ToInt32(array[4]);
				int num6 = Convert.ToInt32(array[5]);
				int num7 = Convert.ToInt32(array[6]);
				int num8 = Convert.ToInt32(array[7]);
				string text = array[8];
				TCPOutPacketPool tcpOutPacketPool = Global._TCPManager.TcpOutPacketPool;
				TCPClientPool tcpClientPool = Global._TCPManager.tcpClientPool;
				TCPManager tcpmanager = Global._TCPManager;
				TMSKSocket clientSocket = client.ClientSocket;
				if (null == goodsData)
				{
					goodsData = GoodsUtil.GetGoodsDataBySite(client, num3, num6);
					if (null == goodsData)
					{
						goodsData = RebornEquip.GetRebornGoodsByDbID(client, num3);
						if (null == goodsData)
						{
							goodsData = RebornEquip.GetRebornStoreGoodsByDbID(client, num3);
							if (null == goodsData)
							{
								goodsData = FashionManager.GetFashionGoodsDataByDbID(client, num3);
								if (null == goodsData)
								{
									goodsData = Global.GetGoodsByDbID(client, num3);
									if (null == goodsData)
									{
										goodsData = Global.GetPortableGoodsDataByDbID(client, num3);
										if (null == goodsData)
										{
											goodsData = Global.GetJinDanGoodsDataByDbID(client, num3);
											if (null == goodsData)
											{
												goodsData = DamonMgr.GetDamonGoodsDataByDbID(client, num3);
												if (null == goodsData)
												{
													goodsData = CallPetManager.GetPetByDbID(client, num3);
													if (null == goodsData)
													{
														goodsData = OrnamentManager.getInstance().GetOrnamentGoodsDataByDbID(client, num3);
														if (null == goodsData)
														{
															goodsData = JingLingYaoSaiManager.GetPaiZhuDamonGoodsDataByDbID(client, num3);
															if (null == goodsData)
															{
																goodsData = ZuoQiManager.GetMountStoreGoodsDataByDbID(client, num3);
																if (null == goodsData)
																{
																	goodsData = ZuoQiManager.GetMountEquipGoodsDataByDbID(client, num3);
																	if (null != goodsData)
																	{
																	}
																}
															}
														}
													}
												}
											}
										}
									}
								}
							}
						}
					}
				}
				if (null == goodsData)
				{
					result = TCPProcessCmdResults.RESULT_OK;
				}
				else if (goodsData.GoodsID != num4)
				{
					LogManager.WriteLog(2, string.Format("监测到复制物品的操作立即断开, CMD={0}, Client={1}, RoleID={2}", TCPGameServerCmds.CMD_SPR_MOD_GOODS, Global.GetSocketRemoteEndPoint(clientSocket, false), num), null, true);
					result = TCPProcessCmdResults.RESULT_FAILED;
				}
				else
				{
					if (num5 != goodsData.Using)
					{
						if (num5 > 0 && num2 != 1)
						{
							LogManager.WriteLog(1000, string.Format("非法的道具使用状态修改,当前using={0},修改命令={1}", goodsData.Using, cmdData), null, true);
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
					if (num2 == 5 && (goodsData.Site != 0 || goodsData.Using > 0))
					{
						LogManager.WriteLog(2, string.Format("检测到出售装备物品或者仓库物品, CMD={0}, Client={1}, RoleID={2}", TCPGameServerCmds.CMD_SPR_MOD_GOODS, Global.GetSocketRemoteEndPoint(clientSocket, false), num), null, true);
						result = TCPProcessCmdResults.RESULT_FAILED;
					}
					else
					{
						int gcount = goodsData.GCount;
