		public static bool HasEnoughGoodsDayUseNum(GameClient client, int goodsID, int willUseNum = 1)
		{
			int goodsLimitNum = Global.GetGoodsLimitNum(client, goodsID);
			if (goodsLimitNum > 0)
			{
				int todayGoodsLimitByID = Global.GetTodayGoodsLimitByID(client, goodsID);
				if (todayGoodsLimitByID + willUseNum > goodsLimitNum)
				{
					string goodsNameByID = Global.GetGoodsNameByID(goodsID);
					List<int> erGuoTouGoodsIDList = Global.GetErGuoTouGoodsIDList();
					if (erGuoTouGoodsIDList.IndexOf(goodsID) >= 0)
					{
						GameManager.LuaMgr.Error(client, StringUtil.substitute(GLang.GetLang(131, new object[0]), new object[]
						{
							goodsLimitNum,
							goodsNameByID
						}), 0);
						return false;
					}
					GameManager.LuaMgr.Error(client, StringUtil.substitute(GLang.GetLang(132, new object[0]), new object[]
					{
						goodsNameByID,
						goodsLimitNum
					}), 0);
					return false;
				}
				else
				{
					List<int> erGuoTouGoodsIDList = Global.GetErGuoTouGoodsIDList();
					if (erGuoTouGoodsIDList.IndexOf(goodsID) >= 0)
					{
						int erGuoTouTodayNum = Global.GetErGuoTouTodayNum(client);
						if (erGuoTouTodayNum + willUseNum > goodsLimitNum)
						{
							string goodsNameByID = Global.GetGoodsNameByID(erGuoTouGoodsIDList[0]);
							GameManager.LuaMgr.Error(client, StringUtil.substitute(GLang.GetLang(133, new object[0]), new object[]
							{
								goodsLimitNum,
								goodsNameByID
							}), 0);
							return false;
						}
					}
				}
			}
			return true;
		}

		public static void AddGoodsLimitNum(GameClient client, int goodsID, int usedNum)
		{
			if (Global.GetGoodsLimitNum(client, goodsID) > 0)
			{
				GoodsLimitData goodsLimitData = Global.GetGoodsLimitByID(client, goodsID);
				if (null == goodsLimitData)
				{
					goodsLimitData = new GoodsLimitData
					{
						GoodsID = goodsID,
						DayID = TimeUtil.NowDateTime().DayOfYear,
						UsedNum = usedNum
					};
					Global.UpdateGoodsLimitByID(client, goodsLimitData);
				}
				else
				{
					int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
					if (dayOfYear != goodsLimitData.DayID)
					{
						goodsLimitData.DayID = dayOfYear;
						goodsLimitData.UsedNum = usedNum;
					}
					else
					{
						goodsLimitData.UsedNum += usedNum;
					}
				}
				string text = string.Format("{0}:{1}:{2}:{3}", new object[]
				{
					client.ClientData.RoleID,
					goodsLimitData.GoodsID,
					goodsLimitData.DayID,
					goodsLimitData.UsedNum
				});
				GameManager.DBCmdMgr.AddDBCmd(10099, text, null, client.ServerId);
				client.sendCmd(3003, text, false);
			}
		}

		public static bool CanUseGoods(GameClient client, int goodsID, bool errHint = true, bool isForEquipLoad = false)
		{
			SystemXmlItem systemXmlItem = null;
			bool result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem))
			{
				result = false;
			}
			else if (!Global.IsCanEquipOrUseByOccupation(client, goodsID))
			{
				result = false;
			}
			else
			{
				string empty = string.Empty;
				if (!SingletonTemplate<GoodsCanUseManager>.Instance().CheckCanUse_ByToType(client, goodsID, out empty))
				{
					if (errHint && !string.IsNullOrEmpty(empty))
					{
						GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, empty, GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					}
					result = false;
				}
				else
				{
					string stringValue = systemXmlItem.GetStringValue("ToType");
					string stringValue2 = systemXmlItem.GetStringValue("ToTypeProperty");
					int intValue = systemXmlItem.GetIntValue("ToSex", -1);
					if (intValue >= 0)
					{
						if (client.ClientData.RoleSex != intValue)
						{
							string stringValue3 = systemXmlItem.GetStringValue("Title");
							string text = (intValue == 0) ? GLang.GetLang(134, new object[0]) : GLang.GetLang(135, new object[0]);
							GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(136, new object[0]), new object[]
							{
								stringValue3,
								text
							}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
							return false;
						}
					}
					int intValue2 = systemXmlItem.GetIntValue("ToZhuanSheng", -1);
					int intValue3 = systemXmlItem.GetIntValue("ToLevel", -1);
					if (client.ClientData.ChangeLifeCount < intValue2)
					{
						string stringValue3 = systemXmlItem.GetStringValue("Title");
						GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(137, new object[0]), new object[]
						{
							intValue3,
							stringValue3
						}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 39);
						result = false;
					}
					else
					{
						if (client.ClientData.ChangeLifeCount == intValue2)
						{
							if (intValue3 > 0)
