									{
										intValue3,
										stringValue3
									}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 39);
									return false;
								}
							}
						}
						result = true;
					}
				}
			}
			return result;
		}

		public static bool CanUseGoodsByExtraTypeProperty(GameClient client, string toType, string toTypeProperty, bool errHint = true, bool isForEquipLoad = false)
		{
			bool result;
			if ("-1" == toType || toType.Length <= 0)
			{
				result = true;
			}
			else
			{
				string[] array = toType.Split(new char[]
				{
					','
				});
				string[] array2 = toTypeProperty.Split(new char[]
				{
					','
				});
				if (array.Length != array2.Length)
				{
					result = true;
				}
				else
				{
					for (int i = 0; i < array.Length; i++)
					{
						string text = array[i];
						string gateValue = array2[i];
						if (!Global.IsRoleReachLimit(client, text, gateValue, isForEquipLoad))
						{
