		public static bool IsRoleReachLimit(GameClient client, string type, string gateValue, bool isForEquipLoad = false)
		{
			bool result;
			if (StringUtil.IsEqualIgnoreCase(type, "VIP"))
			{
				result = Global.IsVip(client);
			}
			else if (StringUtil.IsEqualIgnoreCase(type, "FEIANQUANQU"))
			{
				GameMap gameMap = null;
				result = (GameManager.MapMgr.DictMaps.TryGetValue(client.ClientData.MapCode, out gameMap) && null != gameMap && !gameMap.InSafeRegionList(client.CurrentGrid));
			}
			else if (StringUtil.IsEqualIgnoreCase(type, "CanNotBeyondLevel"))
			{
				string[] array = gateValue.Split(new char[]
				{
					'|'
				});
				if (array.Length != 2)
				{
					result = false;
				}
				else
				{
					int num = Global.SafeConvertToInt32(array[0]);
					int num2 = Global.SafeConvertToInt32(array[1]);
					result = (client.ClientData.ChangeLifeCount <= num && (client.ClientData.ChangeLifeCount != num || client.ClientData.Level < num2));
				}
			}
			else
			{
				int num3 = Global.SafeConvertToInt32(gateValue);
				int num4 = num3 - 1;
				if (StringUtil.IsEqualIgnoreCase(type, "JingMai"))
				{
					num4 = GameManager.ClientMgr.GetJingMaiLevelValue(client);
				}
				else if (StringUtil.IsEqualIgnoreCase(type, "MaxAttack"))
				{
					if (isForEquipLoad)
					{
						num4 = client.ClientData.BaseBattleAttributesOfLastTime[0];
					}
					else
					{
						num4 = (int)RoleAlgorithm.GetMaxAttackV(client);
					}
				}
				else if (StringUtil.IsEqualIgnoreCase(type, "MaxMAttack"))
				{
					if (isForEquipLoad)
					{
						num4 = client.ClientData.BaseBattleAttributesOfLastTime[1];
					}
					else
					{
						num4 = (int)RoleAlgorithm.GetMaxMagicAttackV(client);
					}
				}
				else if (!StringUtil.IsEqualIgnoreCase(type, "MaxDSAttack"))
				{
					if (StringUtil.IsEqualIgnoreCase(type, "UseYuanBao"))
					{
						num4 = client.ClientData.UserMoney;
					}
					else if (StringUtil.IsEqualIgnoreCase(type, "AddIntoBH"))
					{
						num4 = client.ClientData.Faction;
					}
					else if (StringUtil.IsEqualIgnoreCase(type, "WuXue"))
					{
						num4 = GameManager.ClientMgr.GetWuXueLevelValue(client);
					}
					else if (StringUtil.IsEqualIgnoreCase(type, "ChengJiu"))
					{
						num4 = GameManager.ClientMgr.GetChengJiuPointsValue(client);
					}
					else if (StringUtil.IsEqualIgnoreCase(type, "ZhanHunLevel"))
					{
						num4 = GameManager.ClientMgr.GetZhanHunLevelValue(client);
					}
					else if (StringUtil.IsEqualIgnoreCase(type, "RongYuLevel"))
					{
						num4 = GameManager.ClientMgr.GetRongYuLevelValue(client);
					}
				}
				result = (num4 >= num3);
			}
			return result;
		}

		public static bool DoRoleReachLimitAction(GameClient client, string type, string gateValue)
		{
			int num = Global.SafeConvertToInt32(gateValue);
			int val = num;
			return !StringUtil.IsEqualIgnoreCase(type, "UseYuanBao") || GameManager.ClientMgr.SubUserMoney(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, Math.Max(0, val), "DoRoleReachLimitAction", true, true, false, DaiBiSySType.None);
		}

