		public static bool FilterNPCScriptByID(GameClient client, int npcScriptID, out int errorCode)
		{
			errorCode = 0;
			bool result;
			if (npcScriptID <= 0)
			{
				errorCode = -11001;
				result = true;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.systemNPCScripts.SystemXmlItemDict.TryGetValue(npcScriptID, out systemXmlItem))
				{
					errorCode = -11002;
					result = true;
				}
				else
				{
					int intValue = systemXmlItem.GetIntValue("MinLevel", -1);
					int intValue2 = systemXmlItem.GetIntValue("MaxLevel", -1);
					if (client.ClientData.Level < intValue || client.ClientData.Level > intValue2)
					{
						errorCode = -11003;
						result = true;
					}
					else
					{
						int intValue3 = systemXmlItem.GetIntValue("SexCondition", -1);
						if (-1 != intValue3 && client.ClientData.RoleSex != intValue3)
						{
							errorCode = -11004;
							result = true;
						}
						else
						{
							int intValue4 = systemXmlItem.GetIntValue("OccupCondition", -1);
							int num = Global.CalcOriginalOccupationID(client);
							if (-1 != intValue4 && num != intValue4)
							{
								errorCode = -11005;
								result = true;
							}
							else
							{
								DateTimeRange[] npcscriptTimeLimits = Global.GetNPCScriptTimeLimits(npcScriptID, systemXmlItem);
								if (null != npcscriptTimeLimits)
								{
									int num2 = 0;
									if (!Global.JugeDateTimeInTimeRange(TimeUtil.NowDateTime(), npcscriptTimeLimits, out num2, true))
									{
										errorCode = -11006;
										return true;
									}
								}
								int intValue5 = systemXmlItem.GetIntValue("FilterID", -1);
								if (intValue5 <= 0)
								{
									result = false;
								}
								else
								{
									if (1 == intValue5)
									{
										if (Global.GetLeftMonsterByCopyMapID(client.ClientData.CopyMapID) > 0)
										{
											errorCode = -11007;
											return true;
										}
										int num3 = FuBenManager.FindNextMapCodeByFuBenID(client.ClientData.MapCode);
										if (-1 == num3)
										{
											errorCode = -11008;
											return true;
										}
									}
									else if (2 == intValue5)
									{
										if (Global.GetLeftMonsterByCopyMapID(client.ClientData.CopyMapID) > 0)
										{
											errorCode = -11009;
											return true;
										}
										if (!FuBenManager.CanGetFuBenMapAwards(client))
										{
											errorCode = -11010;
											return true;
										}
										int num4 = GameManager.CopyMapMgr.FindAwardState(client.ClientData.RoleID, client.ClientData.FuBenSeqID, client.ClientData.MapCode);
										if (num4 > 0)
										{
											errorCode = -11011;
											return true;
										}
									}
									else if (3 == intValue5)
									{
										if (!WuXingMapMgr.CanGetWuXingAward(client))
										{
											errorCode = -11012;
											return true;
										}
									}
									else if (4 != intValue5)
									{
										if (5 == intValue5)
										{
											if (client.ClientData.Faction <= 0 || client.ClientData.BHZhiWu != 1)
											{
												errorCode = -11013;
												return true;
											}
										}
									}
									result = false;
								}
							}
						}
					}
				}
			}
			return result;
		}

