		public static bool FilterNPCOperationByID(GameClient client, int npcOperationID, int npcID)
		{
			bool result;
			if (npcOperationID <= 0)
			{
				result = true;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemOperasMgr.SystemXmlItemDict.TryGetValue(npcOperationID, out systemXmlItem))
				{
					result = true;
				}
				else
				{
					int intValue = systemXmlItem.GetIntValue("MinLevel", -1);
					int intValue2 = systemXmlItem.GetIntValue("MaxLevel", -1);
					if (client.ClientData.Level < intValue || client.ClientData.Level > intValue2)
					{
						result = true;
					}
					else
					{
						int intValue3 = systemXmlItem.GetIntValue("SexCondition", -1);
						if (-1 != intValue3 && client.ClientData.RoleSex != intValue3)
						{
							result = true;
						}
						else
						{
							int intValue4 = systemXmlItem.GetIntValue("OccupCondition", -1);
							int num = Global.CalcOriginalOccupationID(client);
							if (-1 != intValue4 && num != intValue4)
							{
								result = true;
							}
							else
							{
								DateTimeRange[] npcoperationTimeLimits = Global.GetNPCOperationTimeLimits(npcOperationID, systemXmlItem);
								if (null != npcoperationTimeLimits)
								{
									int num2 = 0;
									if (!Global.JugeDateTimeInTimeRange(TimeUtil.NowDateTime(), npcoperationTimeLimits, out num2, true))
									{
										return true;
									}
								}
								int intValue5 = systemXmlItem.GetIntValue("FilterID", -1);
								if (intValue5 <= 0)
								{
									result = false;
								}
								else
								{
									if (10 == intValue5)
									{
										if (null != client.ClientData.MyYaBiaoData)
										{
											if (client.ClientData.MyYaBiaoData.YaBiaoID > 0)
											{
												return true;
											}
										}
									}
									else if (11 == intValue5)
									{
										if (client.ClientData.MyYaBiaoData == null || client.ClientData.MyYaBiaoData.YaBiaoID <= 0)
										{
											return true;
										}
									}
									else if (12 == intValue5)
									{
										if (client.ClientData.MyYaBiaoData == null || client.ClientData.MyYaBiaoData.TakeGoods > 0)
										{
											return true;
										}
										long num3 = TimeUtil.NOW();
										if (num3 - client.ClientData.MyYaBiaoData.StartTime >= (long)Global.MaxYaBiaoTicks)
										{
											return true;
										}
										SystemXmlItem systemXmlItem2 = null;
										if (!GameManager.systemYaBiaoMgr.SystemXmlItemDict.TryGetValue(client.ClientData.MyYaBiaoData.YaBiaoID, out systemXmlItem2))
										{
											return true;
										}
										if (npcID != systemXmlItem2.GetIntValue("DestNPC", -1))
										{
											return true;
										}
									}
									result = false;
								}
							}
						}
					}
				}
			}
			return result;
		}

