		public static bool CanTakeNewTask(GameClient client, int taskID, SystemXmlItem systemTask = null)
		{
			bool result;
			if (null != Global.GetTaskData(client, taskID))
			{
				result = false;
			}
			else
			{
				if (null == systemTask)
				{
					if (!GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemTask))
					{
						return false;
					}
				}
				int intValue = systemTask.GetIntValue("ForceNoPub", -1);
				if (1 == intValue)
				{
					result = false;
				}
				else
				{
					string stringValue = systemTask.GetStringValue("PubStartTime");
					string stringValue2 = systemTask.GetStringValue("PubEndTime");
					if (!string.IsNullOrEmpty(stringValue) && !string.IsNullOrEmpty(stringValue2))
					{
						long num = Global.SafeConvertToTicks(stringValue);
						long num2 = Global.SafeConvertToTicks(stringValue2);
						long num3 = TimeUtil.NOW();
						if (num3 < num || num3 > num2)
						{
							return false;
						}
					}
					int intValue2 = systemTask.GetIntValue("SexCondition", -1);
					if (-1 != intValue2)
					{
						if (client.ClientData.RoleSex != intValue2)
						{
							return false;
						}
					}
					int intValue3 = systemTask.GetIntValue("OccupCondition", -1);
					if (-1 != intValue3)
					{
						int num4 = Global.CalcOriginalOccupationID(client);
						if (num4 != intValue3)
						{
							return false;
						}
					}
					int intValue4 = systemTask.GetIntValue("TaskClass", -1);
					if (8 == intValue4)
					{
						if (!GlobalNew.IsGongNengOpened(client, 35, false))
						{
							return false;
						}
					}
					if (9 == intValue4)
					{
						if (!GlobalNew.IsGongNengOpened(client, 41, false))
						{
							return false;
						}
					}
					else if (7 == intValue4)
					{
						if (client.ClientData.Faction <= 0)
						{
							return false;
						}
					}
					else if (intValue4 >= 100 && intValue4 <= 150)
					{
						if (client.ClientData.CompType <= 0)
						{
							return false;
						}
					}
					else if (intValue4 == 0)
					{
						if (client.ClientData.MainTaskID >= taskID)
						{
							return false;
						}
					}
					int intValue5 = systemTask.GetIntValue("CompID", -1);
					if (-1 != intValue5)
					{
						if (client.ClientData.CompType != intValue5)
						{
							return false;
						}
					}
					int level = client.ClientData.Level;
					int changeLifeCount = client.ClientData.ChangeLifeCount;
					int intValue6 = systemTask.GetIntValue("MinLevel", -1);
					int intValue7 = systemTask.GetIntValue("MinZhuanSheng", -1);
					int intValue8 = systemTask.GetIntValue("MaxLevel", -1);
					int intValue9 = systemTask.GetIntValue("MaxZhuanSheng", -1);
					if (changeLifeCount < intValue7 || changeLifeCount > intValue9)
					{
						result = false;
					}
					else if (changeLifeCount == intValue7 && level < intValue6)
					{
						result = false;
					}
					else if (changeLifeCount == intValue9 && level > intValue8)
					{
						result = false;
					}
					else
					{
						int intValue10 = systemTask.GetIntValue("PrevTask", -1);
						if (intValue4 == 0)
						{
							result = (client.ClientData.MainTaskID >= intValue10);
						}
						else
						{
							OldTaskData oldTaskData;
							int num5;
							if (-1 != intValue10)
							{
								oldTaskData = Global.FindOldTaskByTaskID(client, intValue10);
								if (oldTaskData == null)
								{
									return false;
								}
								num5 = Global.GetTaskMaxRedoing(intValue10);
								if (num5 > 0 && oldTaskData.DoCount < num5)
								{
									return false;
								}
							}
							num5 = systemTask.GetIntValue("MaxRedoing", -1);
							oldTaskData = Global.FindOldTaskByTaskID(client, taskID);
							if (null != oldTaskData)
							{
								if (num5 > 0 && oldTaskData.DoCount >= num5)
								{
									return false;
								}
							}
							result = true;
						}
					}
				}
			}
			return result;
		}

		public static int ComputeNPCTaskState(GameClient client, List<TaskData> TaskDataList, int npcID, int completeTaskId = 0)
		{
			int num = 0;
			List<int> list = null;
			if (GameManager.NPCTasksMgr.SourceNPCTasksDict.TryGetValue(npcID, out list))
			{
				for (int i = 0; i < list.Count; i++)
				{
					SystemXmlItem systemXmlItem = null;
					if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(list[i], out systemXmlItem))
					{
						int intValue = systemXmlItem.GetIntValue("TaskClass", -1);
						if ((intValue >= 3 && intValue <= 9) || (intValue >= 100 && intValue <= 150))
						{
							if (!Global.CanTaskPaoHuanTask(client, intValue))
							{
								goto IL_DF;
							}
						}
						else if (intValue == 0)
						{
							if (list[i] <= completeTaskId)
							{
								goto IL_DF;
							}
						}
						if (Global.CanTakeNewTask(client, list[i], null))
						{
							num = 1;
							break;
						}
					}
					IL_DF:;
				}
			}
			int result;
			if (null == TaskDataList)
			{
				result = num;
			}
			else
			{
				lock (TaskDataList)
				{
					for (int i = 0; i < TaskDataList.Count; i++)
					{
						SystemXmlItem systemXmlItem = null;
						if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(TaskDataList[i].DoingTaskID, out systemXmlItem))
						{
							int intValue2 = systemXmlItem.GetIntValue("DestNPC", -1);
							if (intValue2 == npcID)
							{
								if (Global.JugeTaskComplete(client, TaskDataList[i].DoingTaskID, TaskDataList[i].DoingTaskVal1, TaskDataList[i].DoingTaskVal2))
								{
									num = 3;
								}
								else
								{
									num = 2;
								}
							}
						}
					}
				}
				result = num;
			}
			return result;
		}

		public static void ComputeNPCTaskState(GameClient client)
		{
			string uri = string.Format("Map/{0}/npcs.xml", client.ClientData.MapCode);
			XElement xelement = GeneralCachingXmlMgr.GetXElement(Global.ResPath(uri));
			if (null != xelement)
			{
				List<NPCTaskState> list = new List<NPCTaskState>();
				IEnumerable<XElement> enumerable = xelement.Elements("NPCs").Elements<XElement>();
				foreach (XElement xelement2 in enumerable)
				{
					int num = -1;
					if ("" != (string)xelement2.Attribute("Code"))
					{
						num = Convert.ToInt32((string)xelement2.Attribute("Code"));
					}
					if (-1 != num)
					{
						list.Add(new NPCTaskState
						{
							NPCID = num,
							TaskState = 0
						});
					}
				}
				for (int i = 0; i < list.Count; i++)
				{
					list[i].TaskState = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, list[i].NPCID, 0);
				}
				GameManager.ClientMgr.NotifyNPCTaskStateList(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, list);
			}
		}

