		public static void ProcessAutoTaskFindRoad(GameClient client, int taskID)
		{
			SystemXmlItem systemXmlItem = null;
			if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
			{
				int intValue = systemXmlItem.GetIntValue("Teleports", -1);
				if (intValue > 0)
				{
					TaskData taskData = Global.GetTaskData(client, taskID);
					if (taskData != null || systemXmlItem.GetIntValue("PrevTask", -1) == client.ClientData.MainTaskID)
					{
						int num = -1;
						int num2 = -1;
						int num3 = -1;
						Point point = new Point(0.0, 0.0);
						GameMap gameMap = GameManager.MapMgr.DictMaps[client.ClientData.MapCode];
						int direction = client.ClientData.RoleDirection;
						if (null != taskData)
						{
							if (!Global.JugeTaskComplete(client, taskData.DoingTaskID, taskData.DoingTaskVal1, taskData.DoingTaskVal2))
							{
								if (!Global.JugeTaskTargetComplete(systemXmlItem, 1, taskData.DoingTaskVal1))
								{
									Global.GetTaskTargetID(systemXmlItem, 1, out num, out num2, out num3, true);
									if (-1 == num)
									{
										if (systemXmlItem.GetIntValue("TargetMapCode1", -1) >= 0)
										{
											int intValue2 = systemXmlItem.GetIntValue("TargetType1", -1);
											int intValue3 = systemXmlItem.GetIntValue("TargetMapCode1", -1);
											string stringValue = systemXmlItem.GetStringValue("TargetPos1");
											if ("" != stringValue)
											{
												int[] array = Global.String2IntArray(stringValue, ',');
												if (array != null && array.Length == 2)
												{
													point = new Point((double)(array[0] / gameMap.MapGridWidth * gameMap.MapGridWidth + gameMap.MapGridWidth / 2), (double)(array[1] / gameMap.MapGridHeight * gameMap.MapGridHeight + gameMap.MapGridHeight / 2));
													num = intValue3;
													num2 = -1;
												}
											}
										}
									}
								}
								else
								{
									Global.GetTaskTargetID(systemXmlItem, 2, out num, out num2, out num3, true);
									if (-1 == num)
									{
										if (systemXmlItem.GetIntValue("TargetMapCode2", -1) >= 0)
										{
											int intValue2 = systemXmlItem.GetIntValue("TargetType2", -1);
											int intValue4 = systemXmlItem.GetIntValue("TargetMapCode2", -1);
											string stringValue2 = systemXmlItem.GetStringValue("TargetPos2");
											if ("" != stringValue2)
											{
												int[] array = Global.String2IntArray(stringValue2, ',');
												if (array != null && array.Length == 2)
												{
													point = new Point((double)(array[0] / gameMap.MapGridWidth * gameMap.MapGridWidth + gameMap.MapGridWidth / 2), (double)(array[1] / gameMap.MapGridHeight * gameMap.MapGridHeight + gameMap.MapGridHeight / 2));
													num = intValue4;
													num2 = -1;
												}
											}
										}
									}
								}
							}
							else
							{
								num3 = systemXmlItem.GetIntValue("DestNPC", -1);
								SystemXmlItem systemXmlItem2 = null;
								if (GameManager.SystemNPCsMgr.SystemXmlItemDict.TryGetValue(num3, out systemXmlItem2))
								{
									num = systemXmlItem2.GetIntValue("MapCode", -1);
									num2 = 3;
									num3 = systemXmlItem2.GetIntValue("ID", -1);
								}
							}
						}
						else
						{
							num3 = systemXmlItem.GetIntValue("SourceNPC", -1);
							SystemXmlItem systemXmlItem2 = null;
							if (GameManager.SystemNPCsMgr.SystemXmlItemDict.TryGetValue(num3, out systemXmlItem2))
							{
								num = systemXmlItem2.GetIntValue("MapCode", -1);
								num2 = 3;
								num3 = systemXmlItem2.GetIntValue("ID", -1);
							}
						}
						if (-1 != num)
						{
							Point point2 = new Point(-1.0, -1.0);
							if (num2 == 2)
							{
								point2 = GameManager.MonsterZoneMgr.GetMonsterPointByMapCodeAndMonsterID(num, num3);
								point2 = Global.GetMapPoint(ObjectTypes.OT_CLIENT, num, (int)point2.X, (int)point2.Y, 256);
							}
							else if (num2 == 3)
							{
								NPC npc = NPCGeneralManager.FindNPC(num, num3);
								if (null != npc)
								{
									point2 = new Point(npc.GridPoint.X * (double)gameMap.MapGridWidth + (double)(gameMap.MapGridWidth / 2), npc.GridPoint.Y * (double)gameMap.MapGridHeight + (double)(gameMap.MapGridHeight / 2));
									List<Point> gridPointByDirection = Global.GetGridPointByDirection(4, (int)npc.GridPoint.X, (int)npc.GridPoint.Y, 3);
									int count = gridPointByDirection.Count;
									for (int i = 0; i < count; i++)
									{
										int randomNumber = Global.GetRandomNumber(0, gridPointByDirection.Count);
										Point point3 = gridPointByDirection[randomNumber];
										if (!Global.InOnlyObs(ObjectTypes.OT_CLIENT, num, (int)point3.X, (int)point3.Y))
										{
											point2 = new Point(point3.X * (double)gameMap.MapGridWidth + (double)(gameMap.MapGridWidth / 2), point3.Y * (double)gameMap.MapGridHeight + (double)(gameMap.MapGridHeight / 2));
											direction = 0;
											break;
										}
										gridPointByDirection.RemoveAt(randomNumber);
									}
								}
							}
							else
							{
								point2 = point;
							}
							if (point2.X == -1.0 || point2.Y == -1.0)
							{
								LogManager.WriteLog(2, string.Format("根据任务ID传送失败, RoleID={0}, 路径信息格式错误 ,无法自动寻路", client.ClientData.RoleID), null, true);
							}
							else
							{
								GameManager.LuaMgr.GotoMap(client, num, (int)point2.X, (int)point2.Y, direction);
							}
						}
					}
				}
			}
		}

		public static void EnterTaskTargetFuBen(GameClient client, int toMapCode)
		{
			int num = FuBenManager.FindFuBenIDByMapCode(toMapCode);
			if (-1 != num)
			{
				string[] array = Global.ExecuteDBCmd(10049, string.Format("{0}", client.ClientData.RoleID), client.ServerId);
				if (array == null || array.Length < 2)
				{
					GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(141, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
				}
				else
				{
					int fuBenSeqID = Global.SafeConvertToInt32(array[1]);
					Global.UpdateFuBenData(client, num, 1, 0);
					GameMap gameMap = null;
					if (!GameManager.MapMgr.DictMaps.TryGetValue(toMapCode, out gameMap))
					{
						GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(142, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					}
					else
					{
						client.ClientData.FuBenSeqID = fuBenSeqID;
						FuBenManager.AddFuBenSeqID(client.ClientData.RoleID, client.ClientData.FuBenSeqID, 0, num);
						GameManager.ClientMgr.NotifyChangeMap(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, toMapCode, -1, -1, -1, 0);
					}
				}
			}
		}

		public static TCPProcessCmdResults TakeNewTask(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, GameClient client, int roleID, int taskID, int npcID, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SystemXmlItem systemXmlItem = null;
			TCPProcessCmdResults result;
			if (!GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
			{
				LogManager.WriteLog(2, string.Format("外挂接受新任务, 任务不存在, CMD={0}, Client={1}, RoleID={2}, TaskID={3}, NPCID={4}", new object[]
				{
					(TCPGameServerCmds)nID,
					Global.GetSocketRemoteEndPoint(socket, false),
					roleID,
					taskID,
					npcID
				}), null, true);
				result = TCPProcessCmdResults.RESULT_OK;
			}
			else
			{
				int intValue = systemXmlItem.GetIntValue("TaskClass", -1);
				if ((intValue >= 3 && intValue <= 9) || (intValue >= 100 && intValue <= 150))
				{
					if (!Global.CanTaskPaoHuanTask(client, intValue))
					{
						LogManager.WriteLog(2, string.Format("外挂接受新任务, 跑环任务超出次数限制, CMD={0}, Client={1}, RoleID={2}, TaskID={3}, NPCID={4}", new object[]
						{
							(TCPGameServerCmds)nID,
							Global.GetSocketRemoteEndPoint(socket, false),
							roleID,
							taskID,
							npcID
						}), null, true);
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				if (!Global.CanTakeNewTask(client, taskID, systemXmlItem))
				{
					LogManager.WriteLog(2, string.Format("外挂接受新任务, 任务不能再接, CMD={0}, Client={1}, RoleID={2}, TaskID={3}, NPCID={4}", new object[]
					{
						(TCPGameServerCmds)nID,
						Global.GetSocketRemoteEndPoint(socket, false),
						roleID,
						taskID,
						npcID - 2130706432
					}), null, true);
					result = TCPProcessCmdResults.RESULT_OK;
				}
				else
				{
					TaskData taskData = new TaskData
					{
						DbID = -1,
						DoingTaskID = taskID
					};
					int num = -1;
					int somethingTaskNeedGoodsNum = Global.GetSomethingTaskNeedGoodsNum(client, taskID, npcID, npcID - 2130706432, out num);
					if (somethingTaskNeedGoodsNum > 0 && -1 != num)
					{
						if (Global.GetGoodsByID(client, num) == null && !Global.CanAddGoods(client, num, 1, 1, "1900-01-01 12:00:00", true, false))
						{
							taskData.DbID = -100;
							tcpOutPacket = DataHelper.ObjectToTCPOutPacket<TaskData>(taskData, pool, nID);
							return TCPProcessCmdResults.RESULT_DATA;
						}
					}
					int num2 = 1;
					if (Global.GetFocusTaskCount(client) >= Data.TaskMaxFocusCount)
					{
						num2 = 0;
					}
					int num3 = 1;
					if (intValue == 8)
					{
						int randomNumber = Global.GetRandomNumber(1, 10001);
						int num4 = 0;
						int[] array = new int[Data.TaskStarInfo.Count];
						for (int i = 0; i < Data.TaskStarInfo.Count; i++)
						{
							array[i] = Data.TaskStarInfo[i].Probability + num4;
							num4 = array[i];
						}
						for (int j = 0; j < array.Length; j++)
						{
							if (randomNumber <= array[j])
							{
								num3 = Data.TaskStarInfo[j].ID;
								break;
							}
						}
					}
					string strcmd = string.Format("{0}:{1}:{2}:{3}:{4}", new object[]
					{
						roleID,
						npcID,
						taskID,
						num2,
						num3
					});
					string[] array2 = null;
					if (TCPProcessCmdResults.RESULT_FAILED == Global.RequestToDBServer(tcpClientPool, pool, nID, strcmd, out array2, client.ServerId))
					{
						LogManager.WriteLog(2, string.Format("与DBServer通讯失败, CMD={0}", (TCPGameServerCmds)nID), null, true);
						taskData.DbID = -999;
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<TaskData>(taskData, pool, nID);
						result = TCPProcessCmdResults.RESULT_DATA;
					}
					else if (Convert.ToInt32(array2[3]) < 0)
					{
						taskData.DbID = Convert.ToInt32(array2[3]);
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<TaskData>(taskData, pool, nID);
						result = TCPProcessCmdResults.RESULT_DATA;
					}
					else
					{
						if (null == client.ClientData.TaskDataList)
						{
							client.ClientData.TaskDataList = new List<TaskData>();
						}
						taskData.DbID = Convert.ToInt32(array2[3]);
						taskData.DoingTaskVal1 = 0;
						taskData.DoingTaskVal2 = 0;
						taskData.DoingTaskFocus = num2;
						taskData.AddDateTime = Convert.ToInt64(array2[2]);
						taskData.DoneCount = 0;
						taskData.StarLevel = num3;
						int intValue2 = systemXmlItem.GetIntValue("ChenJiuID", -1);
						if (intValue2 <= 0)
						{
							taskData.ChengJiuVal = -1L;
						}
						else if (ChengJiuManager.IsChengJiuCompleted(client, intValue2))
						{
							taskData.ChengJiuVal = -1L;
						}
						else
						{
							taskData.ChengJiuVal = ChengJiuManager.getChengJiuValue(client, (AchievementType)(intValue2 / 10));
						}
						OldTaskData oldTaskData = Global.FindOldTaskByTaskID(client, taskID);
						if (null != oldTaskData)
						{
							taskData.DoneCount = oldTaskData.DoCount;
						}
						Global.ProcessTaskData(client, taskData);
						lock (client.ClientData.TaskDataList)
						{
							client.ClientData.TaskDataList.Add(taskData);
						}
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<TaskData>(taskData, pool, nID);
						if (!tcpMgr.MySocketListener.SendData(client.ClientSocket, tcpOutPacket, true))
						{
						}
						int intValue3 = systemXmlItem.GetIntValue("SourceNPC", -1);
						if (intValue3 >= 0)
						{
							int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue3, 0);
							GameManager.ClientMgr.NotifyUpdateNPCTaskSate(tcpMgr.MySocketListener, pool, client, intValue3 + 2130706432, state);
						}
						ProcessTask.Process(tcpMgr.MySocketListener, pool, client, npcID, npcID - 2130706432, -1, TaskTypes.GetSomething, null, 0, -1L, null);
						systemXmlItem = null;
						if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
						{
							int intValue4 = systemXmlItem.GetIntValue("DestNPC", -1);
							if (-1 != intValue4 && intValue4 != npcID - 2130706432)
							{
								int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue4, 0);
								GameManager.ClientMgr.NotifyUpdateNPCTaskSate(tcpMgr.MySocketListener, pool, client, intValue4 + 2130706432, state);
							}
							string stringValue = systemXmlItem.GetStringValue("PropsName1");
							string stringValue2 = systemXmlItem.GetStringValue("PropsName2");
							int num5 = ("" != stringValue) ? Global.GetGoodsByName(stringValue) : -1;
							int num6 = ("" != stringValue2) ? Global.GetGoodsByName(stringValue2) : -1;
							if (num5 >= 0)
							{
								ProcessTask.Process(tcpMgr.MySocketListener, pool, client, -1, -1, num5, TaskTypes.BuySomething, null, 0, -1L, null);
							}
							if (num6 >= 0)
							{
								ProcessTask.Process(tcpMgr.MySocketListener, pool, client, -1, -1, num6, TaskTypes.BuySomething, null, 0, -1L, null);
							}
						}
						if (ChengJiuManager.IsChengJiuCompleted(client, intValue2))
						{
							ProcessTask.Process(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, -1, -1, -1, TaskTypes.ChengJiuUpdate, null, intValue2, -1L, null);
						}
						result = TCPProcessCmdResults.RESULT_OK;
					}
				}
			}
			return result;
		}

