		public static int GetMaxDailyTaskNum(GameClient client, int taskClass, DailyTaskData dailyTaskData)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int num = 0;
			if (dayOfYear == dailyTaskData.ExtDayID)
			{
				num = dailyTaskData.ExtNum;
			}
			int result;
			if (3 == taskClass)
			{
				if (Global.IsVip(client))
				{
					result = 15 + num;
				}
				else
				{
					result = 10 + num;
				}
			}
			else if (4 == taskClass)
			{
				result = 10 + num;
			}
			else if (5 == taskClass)
			{
				result = 6 + num;
			}
			else if (6 == taskClass)
			{
				result = 1 + num;
			}
			else if (7 == taskClass)
			{
				result = 10 + num;
			}
			else if (8 == taskClass)
			{
				result = 10 + num;
			}
			else if (9 == taskClass)
			{
				result = Global.MaxTaofaTaskNumForMU + num;
			}
			else if (taskClass >= 100 && taskClass <= 150)
			{
				result = CompManager.getInstance().GetMaxDailyTaskNum(taskClass);
			}
			else
			{
				result = 0;
			}
			return result;
		}

		private static void CheckJunGongDailyTask(GameClient client, DailyTaskData dailyTaskData)
		{
			if (null != dailyTaskData)
			{
				if (!string.IsNullOrEmpty(dailyTaskData.RecTime))
				{
					DateTime dateTime;
					if (DateTime.TryParse(dailyTaskData.RecTime, out dateTime))
					{
						int dayOfYear = dateTime.DayOfYear;
						int dayOfYear2 = TimeUtil.NowDateTime().DayOfYear;
						if (dayOfYear != dayOfYear2)
						{
							if (dailyTaskData.ExtDayID != dayOfYear2)
							{
								int num = Math.Min(5, Math.Abs(dayOfYear2 - dayOfYear));
								num--;
								num = Global.GMax(0, num);
								int num2 = num * 6;
								num2 += Global.GMax(0, 6 - dailyTaskData.RecNum);
								dailyTaskData.ExtDayID = dayOfYear2;
								int num3 = dailyTaskData.ExtNum - Global.GMax(0, dailyTaskData.RecNum - 6);
								dailyTaskData.ExtNum = Global.GMin(30, Global.GMax(0, num3 + num2));
								Global.UpdateDBDailyTaskData(client, dailyTaskData, false);
							}
						}
					}
				}
			}
		}

