			else
			{
				for (int i = 0; i < client.ClientData.MyDailyTaskDataList.Count; i++)
				{
					if (client.ClientData.MyDailyTaskDataList[i].TaskClass == taskClass)
					{
						return client.ClientData.MyDailyTaskDataList[i];
