		public static void LoadVipLevelAwardList()
		{
			List<string> list = new List<string>();
			string text = Global.GameResPath("Config/VIP.xml");
			XElement xelement = XElement.Load(text);
			if (null == xelement)
			{
				throw new Exception(string.Format("加载系统xml配置文件:{0}, 失败。没有找到相关XML配置文件!", text));
			}
			IEnumerable<XElement> enumerable = xelement.Elements("Items").Elements<XElement>();
			foreach (XElement xelement2 in enumerable)
			{
				SystemXmlItem systemXmlItem = new SystemXmlItem();
				systemXmlItem.XMLNode = xelement2;
				int num = (int)Global.GetSafeAttributeLong(xelement2, "Type");
				int num2 = (int)Global.GetSafeAttributeLong(xelement2, "GetID");
				if (num2 != 0)
				{
					list.Add(string.Format("{0}_{1}", num, num2));
				}
			}
			Global.VipLevelAwardList = list;
		}

