		public static VipDailyData FindVipDailyDataByPriority(GameClient client, int priority)
		{
			VipDailyData result;
			if (null == client.ClientData.VipDailyDataList)
			{
				result = null;
			}
			else
			{
				for (int i = 0; i < client.ClientData.VipDailyDataList.Count; i++)
				{
					VipDailyData vipDailyData = client.ClientData.VipDailyDataList.ElementAt(i);
					if (vipDailyData.PriorityType == priority)
					{
						return vipDailyData;
					}
				}
				result = null;
			}
			return result;
		}

		public static int GetVipPriorityDailyMaxUseTimes(int priority)
		{
			int num = 0;
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.systemVipDailyAwardsMgr.SystemXmlItemDict.TryGetValue(priority, out systemXmlItem) || null == systemXmlItem)
			{
				result = num;
			}
			else
			{
				num = systemXmlItem.GetIntValue("DailyMaxUseTimes", -1);
				if (num < 0)
