		public static int CanGiveVipDailyAwardForPriority(GameClient client, int priority, int dayID)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.systemVipDailyAwardsMgr.SystemXmlItemDict.TryGetValue(priority, out systemXmlItem) || null == systemXmlItem)
			{
				result = -10000;
			}
			else
			{
				int intValue = systemXmlItem.GetIntValue("VIPlev", -1);
				if (client.ClientData.VipLevel < intValue)
				{
					result = -10002;
				}
				else if (Global.IsVipOnceAwardOfRole(priority))
				{
					result = -10003;
				}
				else
				{
					VipDailyData vipDailyData = Global.FindVipDailyDataByPriority(client, priority);
					if (null == vipDailyData)
					{
						result = 1;
					}
					else
					{
						int vipPriorityDailyMaxUseTimes = Global.GetVipPriorityDailyMaxUseTimes(priority);
						if (vipPriorityDailyMaxUseTimes > 0)
						{
							if (vipDailyData.DayID == dayID)
							{
								if (vipDailyData.UsedTimes >= vipPriorityDailyMaxUseTimes)
								{
									return -10001;
								}
							}
						}
						result = 1;
					}
				}
			}
			return result;
		}

		public static void AddDailyVipData(GameClient client, VipDailyData dailyVipData)
		{
			if (null == client.ClientData.VipDailyDataList)
			{
				client.ClientData.VipDailyDataList = new List<VipDailyData>();
			}
			client.ClientData.VipDailyDataList.Add(dailyVipData);
		}

		public static bool UpdateVipDailyData(GameClient client, int dayID, int priority)
		{
			bool flag = false;
			VipDailyData vipDailyData = Global.FindVipDailyDataByPriority(client, priority);
			if (null == vipDailyData)
			{
				flag = true;
			}
			else if (vipDailyData.DayID == dayID)
			{
				vipDailyData.UsedTimes++;
			}
			else
			{
				vipDailyData.DayID = dayID;
				vipDailyData.UsedTimes = 1;
			}
			if (flag)
			{
				if (null == vipDailyData)
				{
					vipDailyData = new VipDailyData();
				}
				vipDailyData.PriorityType = priority;
				vipDailyData.DayID = dayID;
				vipDailyData.UsedTimes = 1;
				Global.AddDailyVipData(client, vipDailyData);
			}
			string[] array = Global.ExecuteDBCmd(10091, string.Format("{0}:{1}:{2}:{3}", new object[]
			{
				client.ClientData.RoleID,
				vipDailyData.DayID,
				vipDailyData.PriorityType,
				vipDailyData.UsedTimes
			}), client.ServerId);
			bool result;
			if (array == null || array.Length != 3 || 0 != array[0].CompareTo("1"))
			{
				result = false;
			}
			else
			{
				GameManager.ClientMgr.NotifyVipDailyData(client);
				result = true;
			}
			return result;
		}

