		private static List<GoodsData> ParseGoodsDataListFromGoodsStr(string batchGoods, string fileName = "")
		{
			string[] array = batchGoods.Split(new char[]
			{
				'|'
			});
			List<GoodsData> list = new List<GoodsData>();
			for (int i = 0; i < array.Length; i++)
			{
				string[] array2 = array[i].Split(new char[]
				{
					','
				});
				if (array2.Length != 6)
				{
					LogManager.WriteLog(1, string.Format("解析{0}中的奖励项时失败, 物品配置项个数错误", fileName), null, true);
				}
				else
				{
					int[] array3 = Global.StringArray2IntArray(array2);
					GoodsData newGoodsData = Global.GetNewGoodsData(array3[0], array3[1], array3[2], array3[3], array3[4], array3[5], 0, 0, 0, 0, 0);
					list.Add(newGoodsData);
				}
			}
			return list;
		}

