					double num16 = 0.0;
					if (gd.ElementhrtsProps != null && gd.ElementhrtsProps.Count >= 2 && !GoodsUtil.IsEquip(gd.GoodsID) && !MountHolyStampManager.IsHolyStamp(gd.GoodsID))
					{
