		public static int BinaryCount(int num)
		{
			long num2 = (long)((ulong)((num & 1431655765) + (int)((uint)num >> 1 & 1431655765U)));
			num2 = (num2 & 858993459L) + (num2 >> 2 & 858993459L);
			num2 = (num2 & 252645135L) + (num2 >> 4 & 252645135L);
			num2 = (num2 & 16711935L) + (num2 >> 8 & 16711935L);
			num2 = (num2 & 65535L) + (num2 >> 16 & 65535L);
			return (int)num2;
		}

