				if (null != stringBuilder)
				{
					stringBuilder.AppendFormat("怪物属性信息详表#{0},{1}#", monster.MonsterInfo.VSName, monster.RoleID);
					string format = string.Format("Defense={0},MDefense={1},MinAttack={2},MaxAttack={3},", new object[]
					{
						monster.MonsterInfo.Defense,
						monster.MonsterInfo.MDefense,
						monster.MonsterInfo.MinAttack,
						monster.MonsterInfo.MaxAttack
					});
					stringBuilder.AppendFormat(format, new object[0]);
					format = string.Format("VLifeMax={0},HitV={1},Dodge={2},SubAttackInjurePercent={3},", new object[]
					{
						monster.MonsterInfo.VLifeMax,
						monster.MonsterInfo.HitV,
						monster.MonsterInfo.Dodge,
						monster.MonsterInfo.MonsterSubAttackInjurePercent
					});
					stringBuilder.AppendFormat(format, new object[0]);
					for (int i = 0; i < 177; i++)
					{
						if (monster.MonsterInfo.ExtProps[i] > 0.0)
						{
							stringBuilder.AppendFormat("{0}={1:0.00},", (ExtPropIndexes)i, monster.MonsterInfo.ExtProps[i]);
						}
					}
					stringBuilder.Append("#");
					if (null != monster.TempPropsBuffer)
					{
						double num = 0.0;
						for (int i = 0; i < 177; i++)
						{
							num += monster.TempPropsBuffer.GetExtProp(i);
						}
