						{
							stringBuilder.Append("TempPropsBuffer加成#");
							for (int i = 0; i < 177; i++)
							{
								stringBuilder.AppendFormat("{0}={1:0.00},", (ExtPropIndexes)i, monster.TempPropsBuffer.GetExtProp(i));
							}
							stringBuilder.Append("#");
						}
					}
				}
