					}
				}
			}
		}

		public static int CalcTaskZhangJieID(GameClient client, int taskID, out int goodsID)
		{
			int completeTaskZhangJie = client.ClientData.CompleteTaskZhangJie;
			int result = completeTaskZhangJie;
			goodsID = 0;
			int num = GameManager.TaskZhangJieDict.BinarySearch(taskID);
			if (num >= 0)
			{
				SystemXmlItem systemXmlItem = (SystemXmlItem)GameManager.TaskZhangJieDict[num].tag;
				result = systemXmlItem.GetIntValue("ID", -1);
				goodsID = systemXmlItem.GetIntValue("GlGoodsID", -1);
			}
			return result;
		}

		public static void UpdateTaskZhangJieProp(GameClient client, int taskID, bool bInit = false)
		{
			int goodsID = 0;
			int completeTaskZhangJie = client.ClientData.CompleteTaskZhangJie;
			int num = Global.CalcTaskZhangJieID(client, taskID, out goodsID);
			if (bInit)
			{
				client.ClientData.CompleteTaskZhangJie = num;
				foreach (KeyValuePair<int, SystemXmlItem> keyValuePair in GameManager.TaskZhangJie.SystemXmlItemDict)
				{
					if (keyValuePair.Key <= num)
					{
						int intValue = keyValuePair.Value.GetIntValue("GlGoodsID", -1);
						if (intValue > 0)
						{
							Global.RefreshGoodsEquipProps(client, intValue, true);
						}
					}
				}
			}
			else if (completeTaskZhangJie != num)
			{
				client.ClientData.CompleteTaskZhangJie = num;
				Global.RefreshGoodsEquipProps(client, goodsID, true);
			}
		}

		public static long CalcExpForRoleScore(int score, int expModule)
		{
			long result;
			if (score <= 0)
			{
				result = 0L;
			}
			else
			{
				result = (long)((double)expModule * (0.5 + Math.Pow((double)Global.Clamp(score, 0, 100000), 0.34) / 100.0));
			}
			return result;
		}

		public static void RefreshGoodsEquipProps(GameClient client, int goodsID, bool addOrDel)
		{
			SystemXmlItem systemXmlItem = null;
			if (GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem))
			{
				EquipPropItem equipPropItem = GameManager.EquipPropsMgr.FindEquipPropItem(goodsID);
				if (null != equipPropItem)
				{
					if (addOrDel)
					{
						for (int i = 0; i < 177; i++)
						{
							client.ClientData.EquipProp.ExtProps[i] += equipPropItem.ExtProps[i];
						}
					}
					else
					{
						for (int i = 0; i < 177; i++)
						{
							client.ClientData.EquipProp.ExtProps[i] -= equipPropItem.ExtProps[i];
							client.ClientData.EquipProp.ExtProps[i] = Global.GMax(0.0, client.ClientData.EquipProp.ExtProps[i]);
						}
					}
				}
			}
		}

