						if (bAdd)
						{
							client.ClientData.ExcellenceProp[num2] += 0.05;
						}
						else
						{
							client.ClientData.ExcellenceProp[num2] -= 0.05;
						}
					}
					else if (num2 == 31)
					{
						if (bAdd)
						{
							client.ClientData.ExcellenceProp[num2] += 0.05;
						}
						else
						{
							client.ClientData.ExcellenceProp[num2] -= 0.05;
						}
					}
					if (!bAdd)
					{
						client.ClientData.ExcellenceProp[num2] = Global.GMax(0.0, client.ClientData.ExcellenceProp[num2]);
					}
				}
			}
		}

