		public static void EarnExperience(GameClient sprite, long experience)
		{
			if (sprite.ClientData.ChangeLifeCount <= GameManager.ChangeLifeMgr.m_MaxChangeLifeCount)
			{
				long num;
				if (sprite.ClientData.ChangeLifeCount > 0)
				{
					num = (long)((int)Data.LevelUpExperienceList[sprite.ClientData.Level]);
					ChangeLifeDataInfo changeLifeDataInfo = GameManager.ChangeLifeMgr.GetChangeLifeDataInfo(sprite, 0);
					if (changeLifeDataInfo != null && changeLifeDataInfo.ExpProportion > 0L)
					{
						num *= changeLifeDataInfo.ExpProportion;
					}
				}
				else
				{
					num = Data.LevelUpExperienceList[sprite.ClientData.Level];
				}
				if (sprite.ClientData.Level < Data.LevelUpExperienceList.Length - 1 && sprite.ClientData.Experience + experience >= num)
				{
					int level = sprite.ClientData.Level;
					sprite.ClientData.Level++;
					Global.TryToActivateSpecialWuXueLevel(sprite);
					Global.SwitchBossFuBenEnterNum(sprite);
					HuodongCachingMgr.ProcessGetUpLevelGift(sprite, false);
					GlobalNew.RefreshGongNeng(sprite);
					experience = sprite.ClientData.Experience + experience - num;
					sprite.ClientData.Experience = 0L;
					GlobalEventSource.getInstance().fireEvent(new PlayerLevelupEventObject(sprite));
					Global.EarnExperience(sprite, experience);
					VideoLogic.getInstance().GetOrSendPlayerVideoStatus(sprite, sprite.ClientData.RoleCommonUseIntPamams);
				}
				else
				{
					sprite.ClientData.Experience += experience;
					sprite.ClientData.Experience = Global.GMax(0L, sprite.ClientData.Experience);
				}
			}
		}

		public static double ProcessTeamZhuFuExperience(GameClient client)
		{
			double result;
			if (client.ClientData.TeamID < 0)
			{
				result = 0.0;
			}
			else
			{
				TeamData teamData = GameManager.TeamMgr.FindData(client.ClientData.TeamID);
				if (null == teamData)
				{
					result = 0.0;
				}
				else
				{
					int num = 0;
					lock (teamData)
					{
						for (int i = 0; i < teamData.TeamRoles.Count; i++)
						{
							if (teamData.TeamRoles[i].RoleID == client.ClientData.RoleID)
							{
								num++;
							}
							else
							{
								GameClient gameClient = GameManager.ClientMgr.FindClient(teamData.TeamRoles[i].RoleID);
								if (null != gameClient)
								{
									if (gameClient.ClientData.MapCode == client.ClientData.MapCode)
									{
										if (gameClient.ClientData.CopyMapID == client.ClientData.CopyMapID)
										{
											num++;
										}
									}
								}
							}
						}
					}
					result = (double)num * 0.02;
				}
			}
			return result;
		}

