		public static int AddSkillDBCommand(TCPOutPacketPool pool, GameClient client, int skillID, int skillLevel)
		{
			string[] array = null;
			string strcmd = string.Format("{0}:{1}:{2}", client.ClientData.RoleID, skillID, skillLevel);
			TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer(Global._TCPManager.tcpClientPool, pool, 10036, strcmd, out array, client.ServerId);
			int result;
			if (tcpprocessCmdResults == TCPProcessCmdResults.RESULT_FAILED)
			{
				result = -1;
			}
			else
			{
				int num = Convert.ToInt32(array[0]);
				if (array.Length <= 0 || num < 0)
				{
					result = num;
				}
				else
				{
					Global.AddSkillData(client, num, skillID, skillLevel);
					Global.ProcessNumSkillID(client, false);
					GameManager.ClientMgr.NotifySelfAddSkill(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, num, skillID, skillLevel);
					result = num;
				}
			}
			return result;
		}

		public static void ProcessNumSkillID(GameClient client, bool force = false)
		{
			if (null != client.ClientData.SkillDataList)
			{
				if (!force)
				{
					if (null != client.ClientData.NumSkillData)
					{
						return;
					}
				}
				client.ClientData.NumSkillData = null;
				bool flag = false;
				if (client.ClientData.NumSkillID <= 0)
				{
					flag = true;
				}
				lock (client.ClientData.SkillDataList)
				{
					for (int i = 0; i < client.ClientData.SkillDataList.Count; i++)
					{
						int skillID = client.ClientData.SkillDataList[i].SkillID;
						SystemXmlItem systemXmlItem = null;
						if (GameManager.SystemMagicQuickMgr.MagicItemsDict.TryGetValue(skillID, out systemXmlItem))
						{
							if (systemXmlItem.GetIntValue("MagicType", -1) == -1)
							{
								if (flag || client.ClientData.NumSkillID == skillID)
								{
									client.ClientData.NumSkillData = client.ClientData.SkillDataList[i];
									break;
								}
							}
						}
					}
				}
			}
		}

