		public static bool MU_GetUpSkillLearnCondition(GameClient Client, int skillID, SystemXmlItem systemMagic = null)
		{
			if (null == systemMagic)
			{
				if (!GameManager.SystemMagicsMgr.SystemXmlItemDict.TryGetValue(skillID, out systemMagic))
				{
					return false;
				}
			}
			int intValue = systemMagic.GetIntValue("LearnTask", -1);
			bool result;
			if (intValue > 0)
			{
				result = (intValue <= Client.ClientData.MainTaskID);
			}
			else
			{
				string stringValue = systemMagic.GetStringValue("LearnCondition");
				if (string.IsNullOrEmpty(stringValue))
				{
					result = false;
				}
				else
				{
					string[] array = stringValue.Split(new char[]
					{
						','
					});
					if (array.Length != 2)
					{
						result = false;
					}
					else
					{
						int num = Global.SafeConvertToInt32(array[0]);
						int num2 = Global.SafeConvertToInt32(array[1]);
						int changeLifeCount = Client.ClientData.ChangeLifeCount;
						int level = Client.ClientData.Level;
						result = (changeLifeCount > num || (changeLifeCount >= num && (changeLifeCount != num || level >= num2)));
					}
				}
			}
			return result;
		}

