			int num = 0;
			int num2 = 1;
			bool result;
			if (Client.ClientData.ChangeLifeCount > num)
			{
				result = true;
			}
			else
			{
				if (Client.ClientData.ChangeLifeCount == num)
				{
					if (Client.ClientData.Level > num2)
					{
						return true;
					}
				}
				result = false;
			}
			return result;
		}

