		public static void AutoLearnSkills(GameClient client)
		{
			if (null == client.ClientData.SkillDataList)
			{
				client.ClientData.SkillDataList = new List<SkillData>();
			}
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			List<SkillData> skillDataList = client.ClientData.SkillDataList;
			int num = Global.CalcOriginalOccupationID(client);
			foreach (int num2 in GameManager.SystemMagicsMgr.SystemXmlItemDict.Keys)
			{
				SystemXmlItem systemXmlItem = GameManager.SystemMagicsMgr.SystemXmlItemDict[num2];
				if (systemXmlItem.GetIntValue("ToOcuupation", -1) == num)
				{
					int intValue = systemXmlItem.GetIntValue("AutoStart", -1);
					if (1 == intValue)
					{
						string stringValue = systemXmlItem.GetStringValue("LearnCondition");
						if (!string.IsNullOrEmpty(stringValue))
						{
							int intValue2 = systemXmlItem.GetIntValue("ID", -1);
							if (null == Global.GetSkillDataByID(client, intValue2))
							{
								if (Global.MU_GetUpSkillLearnCondition(client, intValue2, systemXmlItem))
								{
									dictionary[intValue2] = 0;
								}
							}
						}
					}
				}
			}
			foreach (int num2 in dictionary.Keys)
			{
				Global.LearnSkill(client, num2);
			}
