		public static bool GenerateNewEquipBornValue(int oldBornValue, SystemXmlItem destXmlItem, out int newBornValue)
		{
			newBornValue = oldBornValue;
			int num = 10000;
			int num2 = (int)(100.0 * destXmlItem.GetDoubleValue("MinBorn"));
			int num3 = (int)(100.0 * destXmlItem.GetDoubleValue("MaxBorn"));
			int num4 = (int)(100.0 * destXmlItem.GetDoubleValue("MaxLowerProportion"));
			double doubleValue = destXmlItem.GetDoubleValue("LowerProbability");
			int num5 = (int)(100.0 * destXmlItem.GetDoubleValue("MaxImproveProportion"));
			double doubleValue2 = destXmlItem.GetDoubleValue("ImproveProbability");
			int maxValue = (int)((doubleValue + doubleValue2) * (double)num) + 1;
			int num6 = Global.GlobalRand.Next(1, maxValue);
			if (num6 <= (int)(doubleValue * (double)num))
			{
				int num7 = Global.GlobalRand.Next(1, num4 + 1);
				newBornValue = oldBornValue - num7;
			}
			else
			{
				int num8 = Global.GlobalRand.Next(1, num5 + 1);
				newBornValue = oldBornValue + num8;
			}
			if (newBornValue < 0)
			{
				newBornValue = 0;
			}
			if (newBornValue > 100)
			{
				newBornValue = 100;
			}
			return true;
		}

		public static int UpdateNewEquipBornValueByGoodsID(int goodsID, int minBornValue, int maxBornValue, out int newBornIndex)
		{
			newBornIndex = 0;
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem) || null == systemXmlItem)
			{
				LogManager.WriteLog(1, string.Format("洗炼物品时，获取物品xml信息失败: GoodsID={0}", goodsID), null, true);
				result = -1900;
			}
			else
			{
				int[] intArrayValue = systemXmlItem.GetIntArrayValue("EquipProps", ',');
				if (intArrayValue.Length < 177)
				{
					result = -1901;
				}
				else
				{
					int num = 0;
					int num2 = 0;
					if (intArrayValue[8] > 0)
					{
						int randomNumber = Global.GetRandomNumber(minBornValue, maxBornValue + 1);
						num2 = Global.SetBornAttackValue(num2, randomNumber, 0);
						num = 0;
					}
					if (intArrayValue[10] > 0)
					{
						int randomNumber = Global.GetRandomNumber(minBornValue, maxBornValue + 1);
						num2 = Global.SetBornAttackValue(num2, randomNumber, 1);
						num = 1;
					}
					newBornIndex = num2;
					result = num;
				}
			}
			return result;
		}

		public static int UpdateNewEquipBornValue(GoodsData goodsData, int minBornValue, int maxBornValue)
		{
			int bornIndex = 0;
			int num = Global.UpdateNewEquipBornValueByGoodsID(goodsData.GoodsID, minBornValue, maxBornValue, out bornIndex);
			int result;
			if (num < 0)
			{
				result = num;
			}
			else
			{
				goodsData.BornIndex = bornIndex;
				result = num;
			}
			return result;
		}

		public static int GetTianShengParamsIndex(int goodsID)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsID, out systemXmlItem))
			{
				result = -1;
			}
			else
			{
				string stringValue = systemXmlItem.GetStringValue("ExecMagic");
				if (stringValue.ToUpper().IndexOf("DB_ADD_YINYONG(") < 0)
				{
					result = -1;
				}
				else
				{
					int num = stringValue.IndexOf(",");
					int num2 = stringValue.IndexOf(")");
					if (num2 <= num + 1)
					{
						result = -1;
					}
					else
					{
						int num3 = Global.SafeConvertToInt32(stringValue.Substring(num + 1, num2 - num - 1));
						result = num3;
					}
				}
			}
			return result;
		}

