		public static int GetBornAttackValue(int bornIndex, int attackType)
		{
			bornIndex >>= attackType * 8;
			return bornIndex & 255;
		}

		public static int SetBornAttackValue(int bornIndex, int attackValue, int attackType)
		{
			attackType = attackValue << attackType * 8;
			bornIndex |= attackType;
			return bornIndex;
		}

		public static void LoadForgeSystemParams()
		{
			bool flag = false;
			Global.ForgeProtectOpen = (int)GameManager.systemParamsList.GetParamValueIntByName("ForgeProtectOpen", -1);
			string paramValueByName = GameManager.systemParamsList.GetParamValueByName("ForgeMaxOpen");
			if (string.IsNullOrEmpty(paramValueByName))
			{
				flag = true;
			}
			else
			{
				string[] array = paramValueByName.Split(new char[]
				{
					','
				});
				Global.ForgeMaxOpen = Global.SafeConvertToInt32(array[0]);
				if (Global.ForgeMaxOpen == 2)
				{
					DateTime dateTime;
					DateTime dateTime2;
					if (array.Length == 3 && DateTime.TryParse(array[1], out dateTime) && DateTime.TryParse(array[2], out dateTime2) && dateTime2 > dateTime)
					{
						Global.ForgeMaxOpenStartTime = dateTime;
						Global.ForgeMaxOpenEndTime = dateTime2;
					}
					else
					{
						flag = true;
					}
				}
			}
			if (flag)
			{
				Global.ForgeMaxOpen = 0;
			}
		}

		public static int GetForgePercent(GameClient client, GoodsData goodsData, int luckyValue)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem))
			{
				result = 0;
			}
			else if (null == systemXmlItem)
			{
				result = 0;
			}
			else if (goodsData.Forge_level >= 20)
			{
				result = 0;
			}
			else
			{
				if (null == Global.ForgeLevelRocksPercent)
				{
					Global.ForgeLevelRocksPercent = GameManager.systemParamsList.GetParamValueIntArrayByName("ForgeGoodsRate", ',');
				}
				int num = Math.Abs(Global.ForgeLevelRocksPercent[goodsData.Forge_level + 1]);
				int vipLevel = client.ClientData.VipLevel;
				int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("VIPQiangHuaAdd", ',');
				if (vipLevel > 0 && paramValueIntArrayByName != null && paramValueIntArrayByName[vipLevel] > 0)
				{
					num += paramValueIntArrayByName[vipLevel];
				}
				num += luckyValue;
				result = Global.GMin(100, num);
			}
			return result;
		}

