			subForgeGoodsID = 0;
			needNum = 0;
			needYL = 0;
			string paramValueByName = GameManager.systemParamsList.GetParamValueByName("SubForgeGoodsIDs");
			int num = goodsData.AddPropIndex + 1;
			string[] array = paramValueByName.Split(new char[]
			{
				','
			});
			bool result;
			if (num >= array.Length)
			{
				result = false;
			}
			else
			{
				string[] array2 = array[num].Split(new char[]
				{
					'|'
				});
				if (3 != array2.Length)
				{
					result = false;
				}
				else
				{
					int num2 = 0;
					if (!int.TryParse(array2[0], out num2))
					{
						result = false;
					}
					else
					{
						subForgeGoodsID = num2;
						if (!int.TryParse(array2[1], out num2))
						{
							result = false;
						}
						else
						{
							needNum = num2;
							if (!int.TryParse(array2[2], out num2))
							{
								result = false;
							}
							else
