		public static int GetAllowEnchanceLuckyNum(GameClient client, GoodsData goodsData, int luckyNum)
		{
			SystemXmlItem systemXmlItem = null;
			int result;
			if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem))
			{
				result = luckyNum;
			}
			else if (null == systemXmlItem)
			{
				result = luckyNum;
			}
			else if (goodsData.Quality >= 4)
			{
				result = luckyNum;
			}
			else
			{
				if (null == Global.EnchanceLevelRocksPercent)
				{
					Global.EnchanceLevelRocksPercent = GameManager.systemParamsList.GetParamValueIntArrayByName("EnchanceLevelRocksPercent", ',');
				}
				int num = Math.Abs(Global.EnchanceLevelRocksPercent[goodsData.Quality + 1]);
				if (num >= 100)
				{
					result = 0;
				}
				else
				{
					int num2 = (int)GameManager.systemParamsList.GetParamValueIntByName("EnchanceLuckyGoodsRate", -1);
					num2 = Global.GMax(num2, 1);
					int r = (100 - num - 1) / num2 + 1;
					result = Global.GMin(luckyNum, r);
				}
			}
			return result;
		}

		private static int GetEnchanceLuckyPercent(GameClient client, int luckyNum)
		{
			int num = (int)GameManager.systemParamsList.GetParamValueIntByName("EnchanceLuckyGoodsID", -1);
			int result;
			if (num < 0)
			{
				result = 0;
			}
			else if (luckyNum <= 0)
			{
				result = 0;
			}
			else
			{
				int num2 = (int)GameManager.systemParamsList.GetParamValueIntByName("EnchanceLuckyGoodsRate", -1);
				result = luckyNum * num2;
			}
			return result;
		}

