		public static void RestoreExchangeData(GameClient client, ExchangeData ed)
		{
			lock (ed)
			{
				List<GoodsData> list = null;
				if (ed.GoodsDict.TryGetValue(client.ClientData.RoleID, out list))
				{
					for (int i = 0; i < list.Count; i++)
					{
						if (!RebornEquip.IsRebornType(list[i].GoodsID))
						{
							Global.AddGoodsData(client, list[i]);
						}
						else
						{
							RebornEquip.AddGoodsData(client, list[i]);
						}
						GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, list[i], 1);
					}
					ed.GoodsDict.Remove(client.ClientData.RoleID);
				}
			}
		}

