		public static bool AddGoodsDataIntoExchangeData(GameClient client, int goodsDbID, ExchangeData ed)
		{
			bool result;
			if (Global.IsLockExchangeData(client.ClientData.RoleID, ed))
			{
				result = true;
			}
			else
			{
				lock (ed)
				{
					List<GoodsData> list = null;
					if (!ed.GoodsDict.TryGetValue(client.ClientData.RoleID, out list))
					{
						list = new List<GoodsData>();
						ed.GoodsDict[client.ClientData.RoleID] = list;
					}
					if (list.Count < 12)
					{
						bool flag2 = false;
						GoodsData goodsData = Global.GetGoodsByDbID(client, goodsDbID);
						if (null == goodsData)
						{
							goodsData = RebornEquip.GetRebornGoodsByDbID(client, goodsDbID);
							if (null == goodsData)
							{
								return false;
							}
							flag2 = true;
						}
						if (goodsData.Binding > 0)
						{
							return false;
						}
						if (Global.IsTimeLimitGoods(goodsData))
						{
							return false;
						}
						if (goodsData.Using > 0)
						{
							return false;
						}
						if (!Global.CanExchangeCategoriy(goodsData))
						{
							return false;
						}
						if (!flag2)
						{
							Global.RemoveGoodsData(client, goodsData);
						}
						else
						{
							RebornEquip.RemoveGoodsData(client, goodsData);
						}
						GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, goodsData, 0);
						if (-1 == list.IndexOf(goodsData))
						{
							list.Add(goodsData);
						}
					}
				}
				result = true;
			}
			return result;
		}

		public static bool RemoveGoodsDataFromExchangeData(GameClient client, int goodsDbID, ExchangeData ed)
		{
			bool result;
			if (Global.IsLockExchangeData(client.ClientData.RoleID, ed))
			{
				result = true;
			}
			else
			{
				GoodsData goodsData = null;
				lock (ed)
				{
					List<GoodsData> list = null;
					if (ed.GoodsDict.TryGetValue(client.ClientData.RoleID, out list))
					{
						for (int i = 0; i < list.Count; i++)
						{
							if (list[i].Id == goodsDbID)
							{
								goodsData = list[i];
								list.RemoveAt(i);
								break;
							}
						}
					}
				}
				if (null == goodsData)
				{
					result = false;
				}
				else
				{
					if (goodsData.Site == 15000)
					{
						goodsData.BagIndex = RebornEquip.GetIdleSlotOfRebornGoods(client);
						RebornEquip.AddGoodsData(client, goodsData);
					}
					else
					{
						goodsData.BagIndex = Global.GetIdleSlotOfBagGoods(client);
						Global.AddGoodsData(client, goodsData);
					}
					GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, goodsData, 1);
					result = true;
				}
			}
			return result;
		}

