		private static string BuildTradeAnalysisLog(GameClient from, GameClient to, List<GoodsData> outGoods, List<GoodsData> inGoods, int outMoney, int inMoney, int outJinbi, int inJinbi)
		{
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			Dictionary<int, int> dictionary2 = new Dictionary<int, int>();
			int num = 0;
			while (outGoods != null && num < outGoods.Count)
			{
				if (!dictionary.ContainsKey(outGoods[num].GoodsID))
				{
					dictionary.Add(outGoods[num].GoodsID, outGoods[num].GCount);
				}
				else
				{
					Dictionary<int, int> dictionary3;
					int goodsID;
					(dictionary3 = dictionary)[goodsID = outGoods[num].GoodsID] = dictionary3[goodsID] + outGoods[num].GCount;
				}
				num++;
			}
			num = 0;
			while (inGoods != null && num < inGoods.Count)
			{
				if (!dictionary2.ContainsKey(inGoods[num].GoodsID))
				{
					dictionary2.Add(inGoods[num].GoodsID, inGoods[num].GCount);
				}
				else
				{
					Dictionary<int, int> dictionary3;
					int goodsID;
					(dictionary3 = dictionary2)[goodsID = inGoods[num].GoodsID] = dictionary3[goodsID] + inGoods[num].GCount;
				}
				num++;
			}
			if (outJinbi > 0)
			{
				dictionary[-100] = outJinbi;
			}
			if (inJinbi > 0)
			{
				dictionary2[-100] = inJinbi;
			}
			if (outMoney > 0)
			{
				dictionary[-101] = outMoney;
			}
			if (inMoney > 0)
			{
				dictionary2[-101] = inMoney;
			}
			StringBuilder stringBuilder = new StringBuilder();
			StringBuilder stringBuilder2 = new StringBuilder();
			foreach (KeyValuePair<int, int> keyValuePair in dictionary2)
			{
				stringBuilder.Append(keyValuePair.Key).Append(':').Append(keyValuePair.Value).Append(',');
			}
			if (stringBuilder.Length > 0)
			{
				stringBuilder.Remove(stringBuilder.Length - 1, 1);
			}
			foreach (KeyValuePair<int, int> keyValuePair in dictionary)
			{
				stringBuilder2.Append(keyValuePair.Key).Append(':').Append(keyValuePair.Value).Append(',');
			}
			if (stringBuilder2.Length > 0)
			{
				stringBuilder2.Remove(stringBuilder2.Length - 1, 1);
			}
			FriendData friendData = Global.FindFriendData(from, to.ClientData.RoleID);
			int num2 = 0;
			if (friendData != null && friendData.FriendType == 0)
			{
				num2 = 100;
			}
			string ip = RobotTaskValidator.getInstance().GetIp(from);
			string ip2 = RobotTaskValidator.getInstance().GetIp(to);
			return string.Format("server={0} source={1} srcPlayer={2} target={3} dstPlayer={4} in={5} out={6} map={7} sviplevel={8} tviplevel={9} sexp={10} texp={11} friendDegree={12}", new object[]
			{
				GameManager.ServerId,
				from.strUserID,
				from.ClientData.RoleID,
				to.strUserID,
				to.ClientData.RoleID,
				stringBuilder.ToString(),
				stringBuilder2.ToString(),
				from.ClientData.MapCode,
				from.ClientData.VipLevel,
				to.ClientData.VipLevel,
				ip,
				ip2,
				num2
			});
		}

