		public static int GetTradeLevelLimit(GameClient client)
		{
			int result = 0;
			string paramName = (client.ClientSocket.session.IsGuest == 0) ? "trade_level_limit" : "GuestTradeLevelLimit";
			string[] array = GameManager.PlatConfigMgr.GetGameConfigItemStr(paramName, "0,0").Split(new char[]
			{
				','
			});
			if (array.Length == 2)
			{
				int zhuanSheng = Convert.ToInt32(array[0]);
				int level = Convert.ToInt32(array[1]);
				result = Global.GetUnionLevel(zhuanSheng, level, false);
			}
			return result;
		}

		public static bool TradeLevelLimit(GameClient client)
		{
			return Global.GetUnionLevel(client, false) < Global.GetTradeLevelLimit(client);
		}

		public static bool CanTrade(GameClient client)
		{
			DateTime t = TimeUtil.NowDateTime();
			int num = (int)client.ClientData.VipExp;
			int unionLevel = Global.GetUnionLevel(client, false);
			TradeLimitConfig tradeLimitConfig = GameManager.PlatConfigMgr.GetTradeLimitConfig();
			bool result;
			if (null == tradeLimitConfig)
			{
				result = true;
			}
			else if (tradeLimitConfig.ZuanShiOpen != 1)
			{
				GameManager.ClientMgr.NotifyHintMsg(client, GLang.GetLang(tradeLimitConfig.Message));
				result = false;
			}
			else if (t < tradeLimitConfig.StartTime || t > tradeLimitConfig.EndTime)
			{
				result = true;
			}
			else if (num >= tradeLimitConfig.ZuanShiLimit || unionLevel >= tradeLimitConfig.LevelLimit)
			{
				result = true;
			}
			else
			{
				GameManager.ClientMgr.NotifyHintMsg(client, GLang.GetLang(tradeLimitConfig.Message));
				result = false;
			}
			return result;
		}

		public static int CompleteExchangeData(GameClient client, GameClient otherClient, ExchangeData ed)
		{
