			{
				Monitor.Enter(ed, ref flag);
				List<GoodsData> list = null;
				if (ed.GoodsDict.TryGetValue(client.ClientData.RoleID, out list))
				{
					int num;
					if (!RebornEquip.MoreIsCanIntoRebornOrBaseBag(otherClient, list, out num))
					{
						if (num == 1)
						{
							return -1;
						}
						return -1;
					}
				}
				List<GoodsData> list2 = null;
				if (ed.GoodsDict.TryGetValue(otherClient.ClientData.RoleID, out list2))
				{
					int num;
					if (!RebornEquip.MoreIsCanIntoRebornOrBaseBag(client, list2, out num))
					{
						if (num == 1)
						{
							return -11;
						}
						return -11;
					}
