		public static bool AllowStartStall(GameClient client)
		{
			bool result;
			if (Data.MapStallList == null)
			{
				result = false;
			}
			else
			{
				for (int i = 0; i < Data.MapStallList.Count; i++)
				{
					if (Data.MapStallList[i].MapID == client.ClientData.MapCode)
					{
						Point target = new Point((double)client.ClientData.PosX, (double)client.ClientData.PosY);
						if (Global.InCircle(target, Data.MapStallList[i].ToPos, (double)Data.MapStallList[i].Radius))
						{
							return true;
						}
					}
				}
				result = false;
			}
			return result;
		}

		public static void RestoreStallData(GameClient client, StallData sd)
		{
			lock (sd)
			{
				for (int i = 0; i < sd.GoodsList.Count; i++)
				{
					Global.AddGoodsData(client, sd.GoodsList[i]);
					GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, sd.GoodsList[i], 1);
				}
				sd.GoodsList.Clear();
			}
		}

		public static bool AddGoodsDataIntoStallData(GameClient client, int goodsDbID, StallData sd, int price)
		{
			lock (sd)
			{
				if (sd.Start > 0)
				{
					return true;
				}
				if (sd.GoodsList.Count < 18)
				{
					GoodsData goodsByDbID = Global.GetGoodsByDbID(client, goodsDbID);
					if (null == goodsByDbID)
					{
						return false;
					}
					if (goodsByDbID.Binding > 0)
					{
						return false;
					}
					Global.RemoveGoodsData(client, goodsByDbID);
					GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, goodsByDbID, 0);
					if (-1 == sd.GoodsList.IndexOf(goodsByDbID))
					{
						sd.GoodsList.Add(goodsByDbID);
					}
					sd.GoodsPriceDict[goodsByDbID.Id] = price;
				}
			}
			return true;
		}

		public static bool RemoveGoodsDataFromStallData(GameClient client, int goodsDbID, StallData sd)
		{
			GoodsData goodsData = null;
			lock (sd)
			{
				if (sd.Start > 0)
				{
					return true;
				}
				for (int i = 0; i < sd.GoodsList.Count; i++)
				{
					if (sd.GoodsList[i].Id == goodsDbID)
					{
						goodsData = sd.GoodsList[i];
						sd.GoodsList.RemoveAt(i);
						sd.GoodsPriceDict.Remove(goodsData.Id);
						break;
					}
				}
			}
			bool result;
			if (null == goodsData)
			{
				result = false;
			}
			else
			{
				Global.AddGoodsData(client, goodsData);
				GameManager.ClientMgr.NotifyMoveGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, goodsData, 1);
				result = true;
			}
			return result;
		}

