		public static void QuitFromTeam(GameClient client)
		{
			if (client.ClientData.TeamID > 0)
			{
				ZhuanShengShiLian.ProcessClearRoleLog(client);
				TeamData teamData = GameManager.TeamMgr.FindData(client.ClientData.TeamID);
				if (null == teamData)
				{
					client.ClientData.TeamID = 0;
					GameManager.TeamMgr.RemoveRoleID2TeamID(client.ClientData.RoleID);
				}
				else
				{
					bool flag = false;
					lock (teamData)
					{
						if (teamData.TeamRoles.Count > 1)
						{
							for (int i = 0; i < teamData.TeamRoles.Count; i++)
							{
								if (teamData.TeamRoles[i].RoleID == client.ClientData.RoleID)
								{
									teamData.TeamRoles.RemoveAt(i);
									break;
								}
							}
							if (teamData.LeaderRoleID == client.ClientData.RoleID)
							{
								teamData.LeaderRoleID = teamData.TeamRoles[0].RoleID;
							}
						}
						else
						{
							flag = true;
							teamData.LeaderRoleID = -1;
						}
					}
					if (flag)
					{
						GameManager.TeamMgr.RemoveData(client.ClientData.TeamID);
						GameManager.ClientMgr.NotifyOthersTeamDestroy(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, teamData);
					}
					ZhuanShengShiLian.ProcessChangeTeamName(client, true);
					client.ClientData.TeamID = 0;
					GameManager.TeamMgr.RemoveRoleID2TeamID(client.ClientData.RoleID);
					GameManager.ClientMgr.NotifyTeamData(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, teamData);
					GameManager.ClientMgr.NotifyOthersTeamIDChanged(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client);
				}
			}
		}

