		public static bool JugeSendMessgeLevel(GameClient client, int index)
		{
			int num = 0;
			if (index == 1)
			{
				num = GameManager.PlatConfigMgr.GetGameConfigItemInt("chat_near_level", 0);
			}
			if (index == 2)
			{
				num = GameManager.PlatConfigMgr.GetGameConfigItemInt("chat_world_level", 0);
			}
			else if (index == 3)
			{
				num = GameManager.PlatConfigMgr.GetGameConfigItemInt("chat_family_level", 0);
			}
			else if (index == 4)
			{
				num = GameManager.PlatConfigMgr.GetGameConfigItemInt("chat_team_level", 0);
			}
			else if (index == 5)
			{
				num = GameManager.PlatConfigMgr.GetGameConfigItemInt("chat_private_level", 0);
			}
			int num2 = client.ClientData.ChangeLifeCount * 100 + client.ClientData.Level;
			bool result;
			if (num2 < num)
			{
				string textMsg = StringUtil.substitute(GLang.GetLang(154, new object[0]), new object[]
				{
					num / 100,
					num % 100
				});
				GameManager.ClientMgr.SendSystemChatMessageToClient(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, textMsg);
				result = false;
			}
			else
			{
				result = true;
			}
			return result;
		}

		public static int[] HorseExtStr2IntArray(string extStr)
		{
			int[] result;
			if (string.IsNullOrEmpty(extStr))
			{
				result = new int[10];
			}
			else
			{
				string[] array = extStr.Split(new char[]
				{
					','
				});
				int[] array2 = new int[10];
				int num = 0;
				while (num < array2.Length && num < array.Length)
				{
					try
					{
						array2[num] = Convert.ToInt32(array[num]);
					}
					catch (Exception)
					{
					}
					num++;
				}
				result = array2;
			}
			return result;
		}

		public static string HorseExtIntArray2Str(int[] intArray)
		{
			string text = "";
			for (int i = 0; i < intArray.Length; i++)
			{
				text += intArray[i].ToString();
				if (i < intArray.Length - 1)
				{
					text += ",";
				}
			}
			return text;
		}

