		public static bool UpdateHorseDataProps(GameClient client, bool toAdd = true)
		{
			bool result;
			if (client.ClientData.HorseDbID <= 0)
			{
				result = false;
			}
			else
			{
				HorseData horseDataByDbID = Global.GetHorseDataByDbID(client, client.ClientData.HorseDbID);
				if (null == horseDataByDbID)
				{
					result = false;
				}
				else
				{
					SystemXmlItem horseBasePropXmlNode = Global.GetHorseBasePropXmlNode(horseDataByDbID.HorseID);
					if (null == horseBasePropXmlNode)
					{
						result = false;
					}
					else
					{
						int[] horsePropIntArray = Global.HorseExtStr2IntArray(horseDataByDbID.PropsVal);
						bool flag = false;
						for (int i = 0; i < 10; i++)
						{
							int horseBasePropVal = Global.GetHorseBasePropVal(horseDataByDbID.HorseID, (HorseExtIndexes)i, horseBasePropXmlNode);
							double num = (double)Global.GetHorseExtFieldIntVal(horsePropIntArray, (HorseExtIndexes)i);
							num += (double)horseBasePropVal;
							flag = (num > 0.0 || flag);
							Global.UpdateHorseDataProp(client, (HorseExtIndexes)i, toAdd ? num : (0.0 - num));
						}
						result = flag;
					}
				}
			}
			return result;
		}

		public static void AddHorseData(GameClient client, HorseData horseData)
		{
			if (null == client.ClientData.HorsesDataList)
			{
				client.ClientData.HorsesDataList = new List<HorseData>();
			}
			lock (client.ClientData.HorsesDataList)
			{
				client.ClientData.HorsesDataList.Add(horseData);
			}
		}

		public static void RemoveHorseDataByDbID(GameClient client, int horseDbID)
		{
			if (null != client.ClientData.HorsesDataList)
			{
				lock (client.ClientData.HorsesDataList)
				{
					for (int i = 0; i < client.ClientData.HorsesDataList.Count; i++)
					{
						if (client.ClientData.HorsesDataList[i].DbID == horseDbID)
						{
							client.ClientData.HorsesDataList.RemoveAt(i);
							break;
						}
					}
				}
			}
		}

