		public static int CalcHorsePropJiFen(HorseExtIndexes extIndex, int extPropValue)
		{
			int num = 1;
			SystemXmlItem horseJiFenXmlNode = Global.GetHorseJiFenXmlNode();
			if (null != horseJiFenXmlNode)
			{
				string name = Global.HorsePropNames[(int)extIndex];
				num = horseJiFenXmlNode.GetIntValue(name, -1);
			}
			num = Global.GMax(1, num);
			return extPropValue / num;
		}

		public static int CalcHorsePropsJiFen(HorseData horseData)
		{
			int result;
			if (string.IsNullOrEmpty(horseData.PropsVal))
			{
				result = 0;
			}
			else
			{
				SystemXmlItem horseBasePropXmlNode = Global.GetHorseBasePropXmlNode(horseData.HorseID);
				if (null == horseBasePropXmlNode)
				{
					result = 0;
				}
				else
				{
					int num = 0;
					string[] array = horseData.PropsVal.Split(new char[]
					{
						','
					});
					int num2 = 0;
					while (num2 < array.Length && num2 < 10)
					{
						int horseBasePropVal = Global.GetHorseBasePropVal(horseData.HorseID, (HorseExtIndexes)num2, horseBasePropXmlNode);
						int num3 = Global.SafeConvertToInt32(array[num2]);
						num3 += horseBasePropVal;
						num += Global.CalcHorsePropJiFen((HorseExtIndexes)num2, num3);
						num2++;
					}
					result = num;
				}
			}
			return result;
		}

