					});
				}
			}
			string result;
			if (null == Global.HorseNamesList)
			{
				result = GLang.GetLang(155, new object[0]);
			}
			else if (horseID <= 0)
			{
				result = GLang.GetLang(155, new object[0]);
			}
			else if (horseID > Global.HorseNamesList.Length)
			{
				result = GLang.GetLang(155, new object[0]);
