		public static bool IsHorsePropsFull(HorseData horseData)
		{
			SystemXmlItem horseBasePropXmlNode = Global.GetHorseBasePropXmlNode(horseData.HorseID);
			bool result;
			if (null == horseBasePropXmlNode)
			{
				result = false;
			}
			else
			{
				int[] horsePropIntArray = Global.HorseExtStr2IntArray(horseData.PropsVal);
				for (int i = 0; i < 10; i++)
				{
					int horseBasePropVal = Global.GetHorseBasePropVal(horseData.HorseID, (HorseExtIndexes)i, horseBasePropXmlNode);
					double num = (double)Global.GetHorseExtFieldIntVal(horsePropIntArray, (HorseExtIndexes)i);
					num += (double)horseBasePropVal;
					int horsePropLimitVal = Global.GetHorsePropLimitVal(horseData.HorseID, (HorseExtIndexes)i);
					if (num < (double)horsePropLimitVal)
					{
						return false;
					}
				}
				result = true;
			}
			return result;
		}

		public static int GetTempHorseID(GameClient client)
		{
			int result;
			if (client.ClientData.HorseDbID <= 0)
			{
				result = 0;
			}
			else
			{
				HorseData horseDataByDbID = Global.GetHorseDataByDbID(client, client.ClientData.HorseDbID);
				if (null == horseDataByDbID)
				{
					result = 0;
				}
				else
				{
					int num = horseDataByDbID.HorseID;
					if (client.ClientData.StartTempHorseIDTicks <= 0L)
					{
						result = num;
					}
					else if (client.ClientData.TempHorseID <= 0)
					{
						result = num;
					}
					else
					{
						long num2 = TimeUtil.NOW();
						if (num2 - client.ClientData.StartTempHorseIDTicks >= 180000L)
						{
							result = num;
						}
						else
						{
							num = client.ClientData.TempHorseID;
							result = num;
						}
