			}
			else
			{
				lock (client.ClientData.PetsDataList)
				{
					for (int i = 0; i < client.ClientData.PetsDataList.Count; i++)
					{
						if (client.ClientData.PetsDataList[i].DbID == dbID)
						{
							return client.ClientData.PetsDataList[i];
