		public static int GetPetLevel(PetData petData)
		{
			int result;
			if (petData.FeedNum <= 0)
			{
				result = 1;
			}
			else if (petData.FeedNum >= 1 && petData.FeedNum < 3)
			{
				result = 2;
			}
			else if (petData.FeedNum >= 3 && petData.FeedNum < 6)
			{
				result = 3;
			}
			else if (petData.FeedNum >= 6 && petData.FeedNum < 10)
			{
				result = 4;
			}
			else if (petData.FeedNum >= 10 && petData.FeedNum < 15)
			{
				result = 5;
			}
			else if (petData.FeedNum >= 15 && petData.FeedNum < 20)
			{
				result = 6;
			}
			else if (petData.FeedNum >= 20 && petData.FeedNum < 25)
			{
				result = 7;
			}
			else if (petData.FeedNum >= 25 && petData.FeedNum < 30)
			{
				result = 8;
			}
			else if (petData.FeedNum >= 30 && petData.FeedNum < 35)
			{
				result = 9;
			}
			else
			{
				result = 10;
			}
			return result;
		}

		public static void InitBagParams()
		{
			int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("BagGridParams", ',');
			if (paramValueIntArrayByName != null && 6 == paramValueIntArrayByName.Length)
			{
				if (paramValueIntArrayByName[0] > 0)
				{
					Global.MaxPortableGridNum = paramValueIntArrayByName[0];
				}
				if (paramValueIntArrayByName[1] > 0)
				{
					Global.OnePortableGridYuanBao = paramValueIntArrayByName[1];
				}
				if (paramValueIntArrayByName[2] > 0)
				{
					Global.DefaultPortableGridNum = paramValueIntArrayByName[2];
				}
				if (paramValueIntArrayByName[3] > 0)
				{
					Global.MaxBagGridNum = paramValueIntArrayByName[3];
				}
				if (paramValueIntArrayByName[4] > 0)
				{
					Global.OneBagGridYuanBao = paramValueIntArrayByName[4];
				}
				if (paramValueIntArrayByName[5] > 0)
				{
					Global.DefaultBagGridNum = paramValueIntArrayByName[5];
				}
			}
			int[] paramValueIntArrayByName2 = GameManager.systemParamsList.GetParamValueIntArrayByName("ExtraStoragePrice", ',');
			if (paramValueIntArrayByName2 != null && 2 == paramValueIntArrayByName2.Length)
			{
				Global.ExtraBagGridPriceStartPos = Global.GMax(0, paramValueIntArrayByName2[0]);
				Global.ExtraBagGridPrice = Global.GMax(0, paramValueIntArrayByName2[1]);
			}
			Global.ManorPetMax = Global.SafeConvertToInt32(GameManager.systemParamsList.GetParamValueByName("ManorPetMax"));
		}

		public static int GetExtBagGridNeedYuanBao(GameClient client, int addNum, int hasTime)
		{
			int selfBagCapacity = Global.GetSelfBagCapacity(client);
			int num = selfBagCapacity + 1;
			int num2 = selfBagCapacity + addNum;
			int num3 = 0;
			for (int i = num; i <= num2; i++)
			{
				num3 += Global.GetOneBagGridExtendNeedYuanBao(i);
				if (i == num)
				{
					double num4 = (double)hasTime / (double)((selfBagCapacity + 1 - Global.DefaultBagGridNum) * 3000);
					num3 = (int)((double)num3 * Math.Max(0.0, 1.0 - num4));
				}
			}
			return num3;
		}

		public static int GetOneBagGridExtendNeedYuanBao(int extendPos)
		{
			int num = (extendPos - Global.DefaultBagGridNum) * Global.OneBagGridYuanBao;
			if (num > 10 * Global.OneBagGridYuanBao)
			{
				num = 10 * Global.OneBagGridYuanBao;
			}
			return num;
		}

		public static int ExtGridPortableBagDBCommand(TCPOutPacketPool pool, GameClient client, int addGridNum)
		{
			int portableBagCapacity = Global.GetPortableBagCapacity(client);
			int result;
			if (portableBagCapacity >= Global.MaxPortableGridNum)
			{
				GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, pool, client, StringUtil.substitute(GLang.GetLang(156, new object[0]), new object[]
				{
					Global.MaxPortableGridNum
				}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 1);
				result = -1;
			}
			else if (portableBagCapacity + addGridNum > Global.MaxPortableGridNum)
			{
				if (Global.MaxPortableGridNum - portableBagCapacity >= 5)
				{
					GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, pool, client, StringUtil.substitute(GLang.GetLang(157, new object[0]), new object[]
					{
						Global.MaxPortableGridNum
					}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
				}
				else
				{
					GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, pool, client, StringUtil.substitute(GLang.GetLang(158, new object[0]), new object[]
					{
						Global.MaxPortableGridNum
					}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
				}
				result = -2;
			}
			else
			{
				client.ClientData.MyPortableBagData.ExtGridNum += addGridNum;
				GameManager.DBCmdMgr.AddDBCmd(10044, string.Format("{0}:{1}", client.ClientData.RoleID, client.ClientData.MyPortableBagData.ExtGridNum), null, client.ServerId);
				GameManager.ClientMgr.NotifyPortableBagData(client);
				result = 0;
			}
			return result;
		}

