		private static void GetCurrent9Grid(MapGrid mapGrid, int centerCridX, int centerCridY, out int startGridX, out int startGridY, out int endGridX, out int endGridY)
		{
			startGridX = 0;
			startGridY = 0;
			endGridX = 0;
			endGridY = 0;
			startGridX = centerCridX - Global.MaxCache9XGridNum;
			endGridX = centerCridX + Global.MaxCache9XGridNum;
			startGridY = centerCridY - Global.MaxCache9YGridNum;
			endGridY = centerCridY + Global.MaxCache9YGridNum;
			startGridX = Global.GMax(startGridX, 0);
			startGridY = Global.GMax(startGridY, 0);
			endGridX = Global.GMin(endGridX, mapGrid.MapGridXNum - 1);
			endGridY = Global.GMin(endGridY, mapGrid.MapGridYNum - 1);
		}

		private static bool In9Grid(int myX, int myY, int centerCridX, int centerCridY, int maxGridX, int maxGridY)
		{
			int num = centerCridX - Global.MaxCache9XGridNum;
			int num2 = centerCridX + Global.MaxCache9XGridNum;
			int num3 = centerCridY - Global.MaxCache9YGridNum;
			int num4 = centerCridY + Global.MaxCache9YGridNum;
			num = Global.GMax(num, 0);
			num3 = Global.GMax(num3, 0);
			num2 = Global.GMin(num2, maxGridX - 1);
			num4 = Global.GMin(num4, maxGridY - 1);
			for (int i = num; i <= num2; i++)
			{
				for (int j = num3; j <= num4; j++)
				{
					if (myX == i && myY == j)
					{
						return true;
					}
				}
			}
			return false;
		}

		public static void Get9GridObjects(GameClient client, out List<object> toRemoveObjsList, out List<object> toAddObjsList)
		{
			toRemoveObjsList = null;
			toAddObjsList = null;
			MapGrid mapGrid = GameManager.MapGridMgr.DictGrids[client.ClientData.MapCode];
			bool onlyShowNPC = mapGrid._GameMap.OnlyShowNPC;
			int centerCridX = client.ClientData.PosX / mapGrid.MapGridWidth;
			int centerCridY = client.ClientData.PosY / mapGrid.MapGridHeight;
			lock (client.ClientData.VisibleGrid9Objects)
			{
				List<object> list = client.ClientData.VisibleGrid9Objects.Keys.ToList<object>();
				int count = list.Count;
				for (int i = 0; i < count; i++)
				{
					object obj = list[i];
					client.ClientData.VisibleGrid9Objects[obj] = 0;
				}
			}
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			int num4 = 0;
			Global.GetCurrent9Grid(mapGrid, centerCridX, centerCridY, out num, out num2, out num3, out num4);
			for (int j = num; j <= num3; j++)
			{
				for (int k = num2; k <= num4; k++)
				{
					List<object> list2 = mapGrid.FindObjects(j, k);
					if (list2 != null && list2.Count > 0)
					{
						lock (client.ClientData.VisibleGrid9Objects)
						{
							int i = 0;
							while (i < list2.Count)
							{
								IObject @object = list2[i] as IObject;
								if (@object.ObjectType == ObjectTypes.OT_NPC)
								{
									goto IL_1AB;
								}
								if (!onlyShowNPC || @object == client)
								{
									if (@object.CurrentCopyMapID == client.CurrentCopyMapID)
									{
										goto IL_1AB;
									}
								}
								IL_20A:
								i++;
								continue;
								IL_1AB:
								if (client.ClientData.VisibleGrid9Objects.ContainsKey(list2[i]))
								{
									client.ClientData.VisibleGrid9Objects[list2[i]] = 1;
								}
								else
								{
									client.ClientData.VisibleGrid9Objects[list2[i]] = 2;
								}
								goto IL_20A;
							}
						}
					}
				}
			}
			toRemoveObjsList = new List<object>();
			toAddObjsList = new List<object>();
