			{
				result = null;
			}
			else
			{
				HashSet<int> hashSet = new HashSet<int>();
				List<GameClient> list = new List<GameClient>();
				for (int i = 0; i < objsList.Count; i++)
				{
					GameClient gameClient = objsList[i];
					if (gameClient != null && !hashSet.Contains(gameClient.ClientData.RoleID))
					{
						hashSet.Add(gameClient.ClientData.RoleID);
						list.Add(gameClient);
					}
				}
				if (list.Count <= 0)
				{
					list = null;
				}
				result = list;
			}
			return result;
		}

