		public static int GetLeftMonsterByCopyMapID(int copyMapID)
		{
			CopyMap copyMap = GameManager.CopyMapMgr.FindCopyMap(copyMapID);
			int result;
			if (null == copyMap)
			{
				result = 0;
			}
			else
			{
				int num = 0;
				if (copyMap.KilledNormalNum <= 0 && copyMap.KilledBossNum <= 0)
				{
					num += copyMap.TotalNormalNum - copyMap.KilledNormalNum;
					num += copyMap.TotalBossNum - copyMap.KilledBossNum;
					result = num;
				}
				else
				{
					int copyMapIDMonstersCount = GameManager.MonsterMgr.GetCopyMapIDMonstersCount(copyMapID, 0);
					result = copyMapIDMonstersCount;
				}
			}
			return result;
		}

