		public static string GetFuBenName(int fuBenID)
		{
			SystemXmlItem systemXmlItem = null;
			string result;
			if (!GameManager.systemFuBenMgr.SystemXmlItemDict.TryGetValue(fuBenID, out systemXmlItem))
			{
				result = "";
			}
			else
			{
				string text = systemXmlItem.GetStringValue("CopyName");
				if (string.IsNullOrEmpty(text))
				{
					result = text;
				}
				else
				{
					text = text.Replace("【", "『");
					text = text.Replace("】", "』");
					string[] array = text.Split(new char[]
					{
						'|'
					});
					if (array.Length <= 1)
					{
						result = text;
					}
					else
					{
						result = array[0];
					}
				}
			}
			return result;
		}

		public static SystemXmlItem FindShiLianTaFuBenIDByLevel(GameClient client, out int myMinLevel)
		{
			myMinLevel = 1000000;
			int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("JingYanTaFuBenIDs", ',');
			SystemXmlItem result;
			if (paramValueIntArrayByName == null || paramValueIntArrayByName.Length <= 0)
			{
				result = null;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				for (int i = 0; i < paramValueIntArrayByName.Length; i++)
				{
					if (GameManager.systemFuBenMgr.SystemXmlItemDict.TryGetValue(paramValueIntArrayByName[i], out systemXmlItem))
					{
						int intValue = systemXmlItem.GetIntValue("MinLevel", -1);
						int num = systemXmlItem.GetIntValue("MaxLevel", -1);
						if (num <= 0)
						{
							num = 1000;
						}
						if (myMinLevel > intValue)
						{
							myMinLevel = intValue;
						}
						if (client.ClientData.Level >= intValue && client.ClientData.Level <= num)
						{
							return systemXmlItem;
						}
					}
				}
				result = null;
			}
			return result;
		}

