		public static bool CanReEnterCopyMap(int mapCode, int fuBenSeqID)
		{
			CopyMap copyMap = GameManager.CopyMapMgr.FindCopyMap(mapCode, fuBenSeqID);
			bool result;
			if (null == copyMap)
			{
				result = false;
			}
