		public static bool GotoMap(GameClient client, int toMapCode)
		{
			TCPManager instance = TCPManager.getInstance();
			TCPOutPacketPool instance2 = TCPOutPacketPool.getInstance();
			bool result;
			if (!GameManager.MapMgr.DictMaps.ContainsKey(toMapCode))
			{
				LogManager.WriteLog(2, string.Format("ProcessSpriteGoToMapCmd mapCode Error, mapCode={0}", toMapCode), null, true);
				result = false;
			}
			else
			{
				if (DBRoleBufferManager.ProcessMonthVIP(client) <= 0.0)
				{
					int mapTransNeedMoney = Global.GetMapTransNeedMoney(toMapCode);
					if (!Global.SubBindTongQianAndTongQian(client, mapTransNeedMoney, "地图传送"))
					{
						GameManager.ClientMgr.NotifyImportantMsg(instance.MySocketListener, instance2, client, StringUtil.substitute(GLang.GetLang(171, new object[0]), new object[]
						{
							mapTransNeedMoney,
							Global.GetMapName(toMapCode)
						}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 27);
						return false;
					}
					if (mapTransNeedMoney > 0)
					{
						GameManager.ClientMgr.NotifyImportantMsg(instance.MySocketListener, instance2, client, StringUtil.substitute(GLang.GetLang(172, new object[0]), new object[]
						{
							mapTransNeedMoney,
							Global.GetMapName(toMapCode)
						}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					}
				}
				if (client.ClientSocket.IsKuaFuLogin)
				{
					Global.ModifyMapRecordData(client, (ushort)toMapCode, 0, 0, 0);
					KuaFuManager.getInstance().GotoLastMap(client);
					result = true;
				}
				else if (KuaFuManager.getInstance().IsKuaFuMap(toMapCode))
				{
					LogManager.WriteLog(2, string.Format("GotoMap denied, mapCode={0},IsKuaFuLogin={1}", toMapCode, client.ClientSocket.IsKuaFuLogin), null, true);
					result = false;
				}
				else
				{
					GameMap gameMap = null;
					if (GameManager.MapMgr.DictMaps.TryGetValue(toMapCode, out gameMap))
					{
						int maxX = -1;
						int mapY = -1;
						int randomNumber = Global.GetRandomNumber(0, 8);
						GameManager.ClientMgr.NotifyChangeMap(instance.MySocketListener, instance2, client, toMapCode, maxX, mapY, randomNumber, 0);
					}
					result = true;
				}
			}
			return result;
		}

		public static bool GotoLastMap(GameClient client, int relife = 1)
		{
			bool result;
			if (null == client)
			{
				result = false;
			}
			else
			{
				int num = GameManager.MainMapCode;
				int maxX = -1;
				int mapY = -1;
				if (client.ClientData.LastMapCode != -1 && client.ClientData.LastPosX != -1 && client.ClientData.LastPosY != -1 && 0 == Global.GetMapSceneType(client.ClientData.LastMapCode))
				{
					if (MapTypes.Normal == Global.GetMapType(client.ClientData.LastMapCode))
					{
						if (GameManager.BattleMgr.BattleMapCode != client.ClientData.LastMapCode && GameManager.ArenaBattleMgr.BattleMapCode != client.ClientData.LastMapCode)
						{
							num = client.ClientData.LastMapCode;
							maxX = client.ClientData.LastPosX;
							mapY = client.ClientData.LastPosY;
						}
					}
				}
				GameMap gameMap = null;
				result = (GameManager.MapMgr.DictMaps.TryGetValue(num, out gameMap) && GameManager.ClientMgr.NotifyChangeMap(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, num, maxX, mapY, relife, 0));
			}
			return result;
		}

