		public static int ProcessUpJingmaiLevel(GameClient client, int jingMaiBodyLevel, int jingMaiID, ref int jingMaiLevel, int luckyPercent)
		{
			int result;
			if (jingMaiBodyLevel != client.ClientData.JingMaiBodyLevel)
			{
				result = -100000;
			}
			else if (jingMaiBodyLevel > Global.MaxJingMaiBodyLevel)
			{
				result = -10000;
			}
			else
			{
				int num = -1;
				int num2 = 1;
				JingMaiData jingMaiData = null;
				if (jingMaiLevel == -1)
				{
					jingMaiData = Global.GetJingMaiDataByJMID(client, jingMaiBodyLevel, jingMaiID);
					if (null != jingMaiData)
					{
						num = jingMaiData.DbID;
						num2 = jingMaiData.JingMaiLevel + 1;
						if (num2 > Global.MaxJingMaiLevel)
						{
							num2 = -1;
						}
					}
				}
				else
				{
					num2 = jingMaiLevel;
					jingMaiData = Global.GetJingMaiDataByJMID(client, jingMaiBodyLevel, jingMaiID);
					if (null != jingMaiData)
					{
						num = jingMaiData.DbID;
					}
					if (num2 > Global.MaxJingMaiLevel)
					{
						num2 = -1;
					}
				}
				if (num2 < 0)
				{
					result = -1000;
				}
				else
				{
					if (jingMaiLevel == -1)
					{
						if (!Global.TodayCanChongXue(client))
						{
							return -11000;
						}
					}
					int occupation = Global.CalcOriginalOccupationID(client);
					SystemXmlItem jingMaiXmlItem = Global.GetJingMaiXmlItem(jingMaiID, occupation, jingMaiBodyLevel - 1);
					if (null == jingMaiXmlItem)
					{
						result = -1;
					}
					else
					{
						int upJingMaiNeedLevel = Global.GetUpJingMaiNeedLevel(client, jingMaiXmlItem, jingMaiBodyLevel, jingMaiID);
						if (client.ClientData.Level < upJingMaiNeedLevel)
						{
							result = -200;
						}
						else
						{
							if (jingMaiLevel == -1)
							{
								int upJingMaiNeedLingLi = Global.GetUpJingMaiNeedLingLi(client, jingMaiXmlItem, jingMaiBodyLevel, jingMaiID);
								if (upJingMaiNeedLingLi < 0)
								{
									return -2;
								}
								if (client.ClientData.InterPower < upJingMaiNeedLingLi)
								{
									return -3;
								}
								if (!GameManager.ClientMgr.SubInterPower(client, upJingMaiNeedLingLi))
								{
									return -4;
								}
								int intValue = jingMaiXmlItem.GetIntValue("GoodsID", -1);
								if (Global.GetTotalGoodsCountByID(client, intValue) <= 0)
								{
									return -104;
								}
								bool flag = false;
								bool flag2 = false;
								if (!GameManager.ClientMgr.NotifyUseGoods(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, intValue, 1, false, out flag, out flag2, false))
								{
									return -104;
								}
								Global.UpdateDailyJingMaiData(client, 1);
							}
							client.ClientData.ChongXueFailedNum = 0;
							string[] array = null;
							string strcmd = string.Format("{0}:{1}:{2}:{3}:{4}", new object[]
							{
								client.ClientData.RoleID,
								num,
								jingMaiBodyLevel,
								jingMaiID,
								num2
							});
							TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10024, strcmd, out array, client.ServerId);
							if (tcpprocessCmdResults == TCPProcessCmdResults.RESULT_FAILED)
							{
								result = -20;
							}
							else if (array.Length <= 0 || Convert.ToInt32(array[0]) < 0)
							{
								result = -21;
							}
							else
							{
								num = Convert.ToInt32(array[0]);
								if (null == client.ClientData.JingMaiDataList)
								{
									client.ClientData.JingMaiDataList = new List<JingMaiData>();
								}
								int num3 = 0;
								int oldXueWeiNum = 0;
								int nowXueWeiNum = 0;
								lock (client.ClientData.JingMaiDataList)
								{
									if (null == jingMaiData)
									{
										jingMaiData = new JingMaiData
										{
											DbID = num,
											JingMaiID = jingMaiID,
											JingMaiLevel = num2,
											JingMaiBodyLevel = jingMaiBodyLevel
										};
										client.ClientData.JingMaiDataList.Add(jingMaiData);
										num3 = num2;
										nowXueWeiNum = jingMaiData.JingMaiLevel;
									}
									else
									{
										num3 = num2 - jingMaiData.JingMaiLevel;
										oldXueWeiNum = jingMaiData.JingMaiLevel;
										jingMaiData.JingMaiLevel = num2;
										nowXueWeiNum = jingMaiData.JingMaiLevel;
									}
								}
								Global.AddRoleJingMaiEvent(client, client.ClientData.JingMaiBodyLevel, jingMaiID, oldXueWeiNum, nowXueWeiNum);
								client.ClientData.RoleXueWeiNum += num3;
								Global.BroadcastJingMaiLevelOk(client, jingMaiData);
								int roleXueWeiNum = client.ClientData.RoleXueWeiNum;
								if (client.ClientData.JingMaiBodyLevel < Global.MaxJingMaiBodyLevel)
								{
									int jingMaiBodyLevel2 = client.ClientData.JingMaiBodyLevel;
									Global.CalcJingMaiBodyLevel(client, roleXueWeiNum);
									Global.BroadcastJingMaiBodyLevelOk(client, jingMaiBodyLevel2);
								}
								Global.AddRoleQueueCmd(client, QueueCmdIDs.NotifyEndJingMai, TimeUtil.NOW() * 10000L + 20000000L);
								jingMaiLevel = num2;
								result = num;
							}
						}
					}
				}
			}
			return result;
		}

