		private static void AddSelfJingMaiExp(GameClient client, int nMultiple = 1)
		{
			if (nMultiple < 1)
			{
				nMultiple = 1;
			}
			SystemXmlItem systemXmlItem = null;
			if (GameManager.systemJingMaiExpMgr.SystemXmlItemDict.TryGetValue(client.ClientData.JingMaiBodyLevel, out systemXmlItem))
			{
				int num = systemXmlItem.GetIntValue("SelfRoleExp", -1) * nMultiple;
				Global.AddRoleJingMaiExp(client, num);
				client.ClientData.TotalJingMaiExp += num;
				GameManager.DBCmdMgr.AddDBCmd(10038, string.Format("{0}:{1}:{2}", client.ClientData.RoleID, num, client.ClientData.JingMaiExpNum), null, client.ServerId);
				GameManager.ClientMgr.NotifyOtherJingMaiExp(client);
			}
		}

		private static void AddOthersJingMaiExp(GameClient client)
		{
			List<object> list = new List<object>();
			GameManager.ClientMgr.LookupRolesInCircle(client, client.ClientData.MapCode, client.ClientData.PosX, client.ClientData.PosY, 250, list);
			if (list.Count > 0)
			{
				SystemXmlItem systemXmlItem = null;
				for (int i = 0; i < list.Count; i++)
				{
					GameClient gameClient = list[i] as GameClient;
					systemXmlItem = null;
					if (GameManager.systemJingMaiExpMgr.SystemXmlItemDict.TryGetValue(gameClient.ClientData.JingMaiBodyLevel, out systemXmlItem))
					{
						int leftAddJingMaiExpNum = Global.GetLeftAddJingMaiExpNum(gameClient);
						if (leftAddJingMaiExpNum > 0)
						{
							gameClient.ClientData.JingMaiExpNum++;
							int intValue = systemXmlItem.GetIntValue("OthersRoleExp", -1);
							Global.AddRoleJingMaiExp(gameClient, intValue);
							gameClient.ClientData.TotalJingMaiExp += intValue;
							GameManager.DBCmdMgr.AddDBCmd(10038, string.Format("{0}:{1}:{2}", gameClient.ClientData.RoleID, intValue, gameClient.ClientData.JingMaiExpNum), null, gameClient.ServerId);
							GameManager.ClientMgr.NotifyOtherJingMaiExp(gameClient);
						}
					}
				}
			}
		}

		public static int GetLeftAddJingMaiExpNum(GameClient client)
		{
			long num = TimeUtil.NOW();
			long num2 = (num - client.ClientData.RegTime) / 86400000L * 20L;
			num2 += 20L;
			num2 -= (long)client.ClientData.JingMaiExpNum;
			return (int)num2;
		}

		public static void UpdateJingMaiListProps(GameClient client, bool toAdd = true)
		{
			Dictionary<string, int> dictionary = new Dictionary<string, int>();
			if (null != client.ClientData.JingMaiDataList)
			{
				lock (client.ClientData.JingMaiDataList)
				{
					for (int i = 0; i < client.ClientData.JingMaiDataList.Count; i++)
					{
						JingMaiData jingMaiData = client.ClientData.JingMaiDataList[i];
						Global.UpdateJingMaiProps(client, jingMaiData, dictionary, toAdd);
					}
				}
			}
			int leftAddJingMaiExpNum = Global.GetLeftAddJingMaiExpNum(client);
			dictionary["JiaChengCiShu"] = leftAddJingMaiExpNum;
			dictionary["LeiJiJingYan"] = client.ClientData.TotalJingMaiExp;
			client.ClientData.JingMaiPropsDict = dictionary;
		}

		private static int CalcJingMaiProp(SystemXmlItem systemJingMaiItem, JingMaiData jingMaiData)
		{
			return systemJingMaiItem.GetIntValue("Property", -1);
		}

		private static void CalcLevelsJingMaiProp(GameClient client, JingMaiData jingMaiData, ref Dictionary<string, int> propsDict)
		{
			int occupation = Global.CalcOriginalOccupationID(client);
			SystemXmlItem jingMaiXmlItem = Global.GetJingMaiXmlItem(jingMaiData.JingMaiID, occupation, jingMaiData.JingMaiBodyLevel - 1);
			if (null != jingMaiXmlItem)
			{
				int num = Global.CalcJingMaiProp(jingMaiXmlItem, jingMaiData);
				string stringValue = jingMaiXmlItem.GetStringValue("EnglishName");
				for (int i = 1; i <= jingMaiData.JingMaiLevel; i++)
				{
					if (!propsDict.ContainsKey(stringValue))
					{
						propsDict[stringValue] = 0;
					}
					Dictionary<string, int> dictionary;
					string key;
					(dictionary = propsDict)[key = stringValue] = dictionary[key] + num;
				}
			}
		}

		private static void UpdateJingMaiProps(GameClient client, JingMaiData jingMaiData, Dictionary<string, int> jingMaiPropsDict, bool toAdd)
		{
			Dictionary<string, int> dictionary = new Dictionary<string, int>();
			Global.CalcLevelsJingMaiProp(client, jingMaiData, ref dictionary);
			if (dictionary.Count > 0)
			{
				foreach (string key in dictionary.Keys)
				{
					int num = dictionary[key];
					if (!jingMaiPropsDict.ContainsKey(key))
					{
						jingMaiPropsDict[key] = 0;
					}
					if (toAdd)
					{
						jingMaiPropsDict[key] += num;
					}
					else
					{
						jingMaiPropsDict[key] -= num;
					}
				}
			}
		}

		public static int CalcJingMaiXueWeiNum(SafeClientData clientData)
		{
			int result;
			if (null == clientData.JingMaiDataList)
			{
				result = 0;
			}
			else
			{
				int num = 0;
				lock (clientData.JingMaiDataList)
				{
					for (int i = 0; i < clientData.JingMaiDataList.Count; i++)
					{
						num += clientData.JingMaiDataList[i].JingMaiLevel;
					}
				}
				result = num;
			}
			return result;
		}

