		public static void UpdateDailyJingMaiData(GameClient client, int num = 1)
		{
			bool flag = false;
			string text = TimeUtil.NowDateTime().ToString("yyyy-MM-dd");
			if (null == client.ClientData.MyDailyJingMaiData)
			{
				flag = true;
			}
			else if (client.ClientData.MyDailyJingMaiData.JmTime == text)
			{
				client.ClientData.MyDailyJingMaiData.JmNum += num;
			}
			else
			{
				flag = true;
			}
			if (flag)
			{
				client.ClientData.MyDailyJingMaiData = new DailyJingMaiData
				{
					JmTime = text,
					JmNum = num
				};
			}
			GameManager.DBCmdMgr.AddDBCmd(10042, string.Format("{0}:{1}:{2}", client.ClientData.RoleID, client.ClientData.MyDailyJingMaiData.JmTime, client.ClientData.MyDailyJingMaiData.JmNum), null, client.ServerId);
			GameManager.ClientMgr.NotifyDailyJingMaiData(client);
		}

		public static int GetFreeChuanSongNum(GameClient client)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(client, "FreeCSDayID");
			int num = Math.Max(0, Global.GetRoleParamsInt32FromDB(client, "FreeCSNum"));
			int num2 = (int)GameManager.systemParamsList.GetParamValueIntByName("FreeCSMaxTimes", -1);
			int result;
			if (roleParamsInt32FromDB == dayOfYear)
			{
				result = num2 - num;
			}
			else
			{
				result = num2;
			}
			return result;
		}

		public static void AddFreeChuanSongNum(GameClient client)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int num = Global.GetRoleParamsInt32FromDB(client, "FreeCSDayID");
			int num2 = Math.Max(0, Global.GetRoleParamsInt32FromDB(client, "FreeCSNum"));
			if (num == dayOfYear)
			{
				num2++;
			}
			else
			{
				num = dayOfYear;
				num2 = 1;
			}
			Global.SaveRoleParamsInt32ValueToDB(client, "FreeCSDayID", num, true);
			Global.SaveRoleParamsInt32ValueToDB(client, "FreeCSNum", num2, true);
		}

