		public static T1 SendToNameServer<T, T1>(TCPClient tcpClient, int cmdId, T cmdInfo)
		{
			T1 result = default(T1);
			byte[] array = DataHelper.ObjectToBytes<T>(cmdInfo);
			TCPOutPacket tcpoutPacket = TCPOutPacket.MakeTCPOutPacket(TCPOutPacketPool.getInstance(), array, 0, array.Length, cmdId);
			if (null != tcpoutPacket)
			{
				byte[] array2 = Global.SendAndRecvData(tcpClient, tcpoutPacket);
				if (null == array2)
				{
					LogManager.WriteLog(2, string.Format("与DBServer通讯失败, CMD={0}", (TCPGameServerCmds)cmdId), null, true);
					return result;
				}
				result = DataHelper.BytesToObject<T1>(array2, 6, array2.Length - 6);
				Global.PushBackTcpOutPacket(tcpoutPacket);
			}
			return result;
		}

		public static byte[] SendAndRecvData(TCPClient tcpClient, TCPOutPacket tcpOutPacket)
		{
			byte[] array = null;
			try
			{
				if (null != tcpClient)
				{
					array = tcpClient.SendData(tcpOutPacket);
				}
				if (array != null && array.Length >= 6)
				{
					ushort num = BitConverter.ToUInt16(array, 4);
					if (30767 == num)
					{
						array = null;
						LogManager.WriteLog(2, "与NameServer 通讯时返回错误 CMD_DB_ERR_RETURN", null, true);
					}
				}
			}
			catch (Exception arg)
			{
				LogManager.WriteLog(2, "与NameServer 通讯时发生异常" + arg, null, true);
			}
			return array;
		}

