		public static TCPProcessCmdResults RequestToDBServer(TCPClientPool tcpClientPool, TCPOutPacketPool pool, int nID, string strcmd, out string[] fields, int serverId)
		{
			fields = null;
			try
			{
				byte[] array = Global.SendAndRecvData<string>(nID, strcmd, serverId, 0);
				if (null == array)
				{
					LogManager.WriteLog(2, string.Format("与DBServer通讯失败, CMD={0}", (TCPGameServerCmds)nID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = BitConverter.ToInt32(array, 0);
				string @string = new UTF8Encoding().GetString(array, 6, num - 2);
				fields = @string.Split(new char[]
				{
					':'
				});
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception ex)
			{
				DataHelper.WriteExceptionLogEx(ex, "RequestToDBServer");
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		public static byte[] SendAndRecvData<T>(int cmdId, T data, int serverId, int PoolId = 0)
		{
			byte[] result = null;
			TCPOutPacket tcpoutPacket = null;
			TCPOutPacketPool instance = TCPOutPacketPool.getInstance();
			if (null != instance)
			{
				try
				{
					if (data is string)
					{
						tcpoutPacket = TCPOutPacket.MakeTCPOutPacket(instance, data as string, cmdId);
					}
					else if (data is byte[])
					{
						tcpoutPacket = TCPOutPacket.MakeTCPOutPacket(instance, data as byte[], cmdId);
					}
					else
					{
						byte[] array = DataHelper.ObjectToBytes<T>(data);
						if (null != array)
						{
							tcpoutPacket = TCPOutPacket.MakeTCPOutPacket(instance, array, cmdId);
						}
					}
					if (null != tcpoutPacket)
					{
						result = Global.SendAndRecvData(tcpoutPacket, serverId, PoolId);
					}
				}
				finally
				{
					if (null != tcpoutPacket)
					{
						instance.Push(tcpoutPacket);
					}
				}
			}
			return result;
		}

