		public static TCPProcessCmdResults RequestToDBServer2(TCPClientPool tcpClientPool, TCPOutPacketPool pool, int nID, string strcmd, out TCPOutPacket tcpOutPacket, int serverId)
		{
			tcpOutPacket = null;
			try
			{
				byte[] array = Global.SendAndRecvData<string>(nID, strcmd, serverId, 0);
				if (null == array)
				{
					LogManager.WriteLog(2, string.Format("与DBServer通讯失败, CMD={0}", (TCPGameServerCmds)nID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = BitConverter.ToInt32(array, 0);
				ushort packetCmdID = BitConverter.ToUInt16(array, 4);
				tcpOutPacket = pool.Pop();
				tcpOutPacket.PacketCmdID = packetCmdID;
				tcpOutPacket.FinalWriteData(array, 6, num - 2);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, "RequestToDBServer2", false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

