		public static string QueryUserMoneyFromDB(int roleID, string otherRoleName, out int userMoney, out int realMoney, int serverId)
		{
			userMoney = 0;
			realMoney = 0;
			string result;
			if (string.IsNullOrEmpty(otherRoleName))
			{
				result = null;
			}
			else
			{
				string[] array = Global.ExecuteDBCmd(10069, string.Format("{0}:{1}", roleID, otherRoleName), serverId);
				if (array == null || array.Length < 4)
				{
					if (null == array)
					{
						return null;
					}
				}
				else
				{
					userMoney = Global.SafeConvertToInt32(array[2]);
