		public static int GetSwitchServerWaitSecs(TMSKSocket socket)
		{
			TimeSpan timeOfDay = TimeUtil.NowDateTime().TimeOfDay;
			int result;
			if (timeOfDay.TotalMinutes >= (double)GameManager.ConstCheckServerTimeDiffMinutes && timeOfDay.TotalMinutes < TimeSpan.FromDays(1.0).TotalMinutes - (double)GameManager.ConstCheckServerTimeDiffMinutes)
			{
				result = 0;
			}
			else
			{
				long num = (socket.session.LastLogoutServerTicks - TimeUtil.NOW()) / 1000L;
				if (num < 0L || num > (long)(GameManager.ConstCheckServerTimeDiffMinutes * 60))
				{
					if (num > 30L && num < 3600L)
					{
						LogManager.WriteLog(2, string.Format("账号登陆时检测，服务器时间误差可能超过60秒，本次登录比上次下线时间早{0}秒", num), null, true);
					}
					num = 0L;
				}
				result = (int)num;
			}
			return result;
		}

		public static int RegisterUserIDToDBServer(string userID, int state, int serverId, ref long logoutServerTicks)
		{
			logoutServerTicks = 0L;
			string[] array = null;
			long num = TimeUtil.NOW();
			int num2 = 0;
			while (TCPProcessCmdResults.RESULT_FAILED == Global.RequestToDBServer(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10025, string.Format("{0}:{1}:{2}", userID, GameManager.ServerLineID, state), out array, serverId))
			{
				if (state == 0)
				{
					if (num2++ < 5 || Math.Abs(TimeUtil.NOW() - num) < 60000L)
					{
						Thread.Sleep(100);
						continue;
					}
				}
				return -1;
			}
			if (array == null || array.Length <= 0)
			{
				return -2;
			}
			if (array.Length >= 2)
			{
				logoutServerTicks = Convert.ToInt64(array[1]);
			}
			return Convert.ToInt32(array[0]);
		}

