		public static int GetAntiAddictionTimeType(GameClient client)
		{
			int num = GameManager.OnlineUserSession.FindUserAdult(client.ClientSocket);
			int result;
			if (num > 0)
			{
				result = 0;
			}
			else
			{
				int num2 = GameManager.GameConfigMgr.GetGameConfigItemInt("anti-addiction-hint", 10800);
				num2 = Global.GMax(0, num2);
				if (client.ClientData.AntiAddictionSecs < num2)
				{
					result = 0;
				}
				else
				{
					int num3 = GameManager.GameConfigMgr.GetGameConfigItemInt("anti-addiction-warning", 18000);
					num3 = Global.GMax(0, num3);
					if (client.ClientData.AntiAddictionSecs >= num2 && client.ClientData.AntiAddictionSecs < num3)
					{
						result = 1;
					}
					else
					{
						result = 2;
					}
				}
			}
			return result;
		}

