				}
			}
		}

		private static bool InstantDBUpdateRoleStat(DateTime dateTime)
		{
			int dayOfYear = dateTime.DayOfYear;
			int hour = dateTime.Hour;
			int minute = dateTime.Minute;
			bool result;
			if (dayOfYear != Global.LastDBUpdateRoleStatDay)
			{
				Global.LastDBUpdateRoleStatDay = dayOfYear;
				Global.LastDBUpdateRoleStatHour = hour;
				Global.LastDBUpdateRoleStatMinute = minute;
				result = false;
			}
			else if (hour == Global.LastDBUpdateRoleStatHour && minute == Global.LastDBUpdateRoleStatMinute)
			{
				result = false;
			}
			else
			{
				int num = Global.LastDBUpdateRoleStatHour * 60 + Global.LastDBUpdateRoleStatMinute;
				int num2 = hour * 60 + minute;
				bool flag = false;
				int num3 = 405;
				if (num3 > num)
				{
					if (num2 >= num3)
					{
						flag = true;
					}
				}
				Global.LastDBUpdateRoleStatDay = dayOfYear;
				Global.LastDBUpdateRoleStatHour = hour;
				Global.LastDBUpdateRoleStatMinute = minute;
				result = flag;
			}
			return result;
		}

