		public static void ProcessDBRoleParamCmdByTicks(GameClient client, bool force = false)
		{
			if (null != client.ClientData.RoleParamsDict)
			{
				long num = TimeUtil.NOW();
				List<string> list = new List<string>();
				lock (client.ClientData.LastDBRoleParamCmdTicksDict)
				{
					List<string> list2 = client.ClientData.LastDBRoleParamCmdTicksDict.Keys.ToList<string>();
					int count = list2.Count;
					for (int i = 0; i < count; i++)
					{
						string text = list2[i];
						long num2 = client.ClientData.LastDBRoleParamCmdTicksDict[text];
						if (num2 > 0L)
						{
							if (num - num2 >= 7200000L || force)
							{
								list.Add(text);
								Global.SetLastDBRoleParamCmdTicks(client, text, 0L);
							}
						}
					}
				}
				foreach (string text in list)
				{
					string text;
					string roleParamByName = Global.GetRoleParamByName(client, text);
					GameManager.DBCmdMgr.AddDBCmd(10100, string.Format("{0}:{1}:{2}", client.ClientData.RoleID, text, roleParamByName), null, client.ServerId);
				}
			}
		}

