		public static bool UpdateWeekLoginNum(GameClient client)
		{
			int dayOfWeek = (int)TimeUtil.NowDateTime().DayOfWeek;
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int num = Global.SafeConvertToInt32(client.ClientData.MyHuodongData.LastDayID);
			bool result;
			if (num >= dayOfYear && Math.Abs(num - dayOfYear) < 2)
			{
				result = false;
			}
			else
			{
				bool flag = false;
				if (1 != dayOfWeek)
				{
					if (client.ClientData.MyHuodongData.LastDayID != dayOfYear.ToString())
					{
						if (client.ClientData.MyHuodongData.LastDayID == TimeUtil.NowDateTime().AddDays(-1.0).DayOfYear.ToString())
						{
							client.ClientData.MyHuodongData.LastDayID = dayOfYear.ToString();
							client.ClientData.MyHuodongData.LoginNum++;
							return true;
						}
						flag = true;
					}
				}
				else
				{
					flag = true;
				}
				if (flag)
				{
					client.ClientData.MyHuodongData.LoginGiftState = 0;
					client.ClientData.MyHuodongData.LastWeekID = dayOfWeek.ToString();
					client.ClientData.MyHuodongData.LastDayID = dayOfYear.ToString();
					client.ClientData.MyHuodongData.LoginNum = 1;
					result = true;
				}
				else
				{
					result = false;
				}
			}
			return result;
		}

		public static void InitNewStep(GameClient client)
		{
			if (client.ClientData.MyHuodongData.NewStep <= 0)
