		public static bool UpdateLimitTimeLoginNum(GameClient client)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int limitTimeLoginHuoDongID = HuodongCachingMgr.GetLimitTimeLoginHuoDongID();
			if (limitTimeLoginHuoDongID > 0)
			{
				if (limitTimeLoginHuoDongID != client.ClientData.MyHuodongData.LastLimitTimeHuoDongID)
				{
					client.ClientData.MyHuodongData.LastLimitTimeHuoDongID = limitTimeLoginHuoDongID;
					client.ClientData.MyHuodongData.LastLimitTimeDayID = dayOfYear;
					client.ClientData.MyHuodongData.LimitTimeLoginNum = 1;
					client.ClientData.MyHuodongData.LimitTimeGiftState = 0;
					return true;
				}
				if (dayOfYear != client.ClientData.MyHuodongData.LastLimitTimeDayID)
				{
					client.ClientData.MyHuodongData.LastLimitTimeDayID = dayOfYear;
					client.ClientData.MyHuodongData.LimitTimeLoginNum++;
					return true;
				}
			}
			return false;
		}

		public static object TryLockObject(object obj, int millisecondsTimeout = 5000)
		{
			bool flag = false;
			Monitor.TryEnter(obj, millisecondsTimeout, ref flag);
			object result;
			if (flag)
			{
				result = obj;
			}
			else
			{
				try
				{
					StackTrace stackTrace = new StackTrace(1, true);
					DataHelper.WriteFormatStackLog(stackTrace, "");
				}
				catch (Exception)
				{
				}
				result = null;
			}
			return result;
		}

		public static void FinalUnLockObject(object obj)
		{
			if (null != obj)
			{
				Monitor.Exit(obj);
			}
		}

