						stringValue
					});
					if (bNeedSend)
					{
						Global.BroadcastRoleActionMsg(client, RoleActionsMsgTypes.HintMsg, msgText, true, GameInfoTypeIndexes.Hot, ShowGameInfoTypes.SysHintAndChatBox, 0, 0, 100, 100);
					}
				}
			}
		}

