		public static void EnterCaiShenMiao(GameClient client, int fuBenID, int goodsBinding)
		{
			SystemXmlItem systemXmlItem = null;
			if (!GameManager.systemFuBenMgr.SystemXmlItemDict.TryGetValue(fuBenID, out systemXmlItem))
			{
				GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(319, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
			}
			else
			{
				int intValue = systemXmlItem.GetIntValue("MapCode", -1);
				string[] array = Global.ExecuteDBCmd(10049, string.Format("{0}", client.ClientData.RoleID), client.ServerId);
				if (array == null || array.Length < 2)
				{
					GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(320, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
				}
				else
				{
					int fuBenSeqID = Global.SafeConvertToInt32(array[1]);
					Global.UpdateFuBenData(client, fuBenID, 1, 0);
					GameMap gameMap = null;
					if (!GameManager.MapMgr.DictMaps.TryGetValue(intValue, out gameMap))
					{
						GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(321, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					}
					else
					{
						client.ClientData.FuBenSeqID = fuBenSeqID;
						FuBenManager.AddFuBenSeqID(client.ClientData.RoleID, client.ClientData.FuBenSeqID, goodsBinding, fuBenID);
						GameManager.ClientMgr.NotifyChangeMap(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, intValue, -1, -1, -1, 0);
					}
				}
			}
		}

		public static DateTimeRange[] ParseDateTimeRangeStr(string str)
		{
			DateTimeRange[] result;
			if (null == str)
			{
				result = null;
			}
			else
			{
				str = str.Trim();
				if (string.IsNullOrEmpty(str))
				{
					result = null;
				}
				else
				{
					string[] array = str.Split(new char[]
					{
						'|'
					});
					if (array == null || array.Length <= 0)
					{
						result = null;
					}
					else
					{
						DateTimeRange[] array2 = new DateTimeRange[array.Length];
						for (int i = 0; i < array.Length; i++)
						{
							string text = array[i].Trim();
							if (string.IsNullOrEmpty(text))
							{
								array2[i] = null;
							}
							else
							{
								string[] array3 = text.Split(new char[]
								{
									'-'
								});
								if (array3 == null || array3.Length != 2)
								{
									array2[i] = null;
								}
								else
								{
									string text2 = array3[0].Trim();
									if (string.IsNullOrEmpty(text2))
									{
										array2[i] = null;
									}
									else
									{
										string[] array4 = text2.Split(new char[]
										{
											':'
										});
										if (array4 == null || array4.Length != 2)
										{
											array2[i] = null;
										}
										else
										{
											string text3 = array3[1].Trim();
											if (string.IsNullOrEmpty(text3))
											{
												array2[i] = null;
											}
											else
											{
												string[] array5 = text3.Split(new char[]
												{
													':'
												});
												if (array5 == null || array5.Length != 2)
												{
													array2[i] = null;
												}
												else
												{
													array2[i] = new DateTimeRange
													{
														FromHour = Global.SafeConvertToInt32(array4[0]),
														FromMinute = Global.SafeConvertToInt32(array4[1]),
														EndHour = Global.SafeConvertToInt32(array5[0]),
														EndMinute = Global.SafeConvertToInt32(array5[1])
													};
												}
											}
										}
									}
								}
							}
						}
						result = array2;
					}
				}
			}
			return result;
		}

		public static bool JugeDateTimeInTimeRange(DateTime dateTime, DateTimeRange[] dateTimeRangeArray, out int endMinute, bool equalEndTime = true)
		{
			endMinute = 0;
			bool result;
			if (null == dateTimeRangeArray)
			{
				result = true;
			}
			else
			{
				int hour = dateTime.Hour;
				int minute = dateTime.Minute;
				for (int i = 0; i < dateTimeRangeArray.Length; i++)
				{
					if (null != dateTimeRangeArray[i])
					{
						int num = dateTimeRangeArray[i].FromHour * 60 + dateTimeRangeArray[i].FromMinute;
						int num2 = dateTimeRangeArray[i].EndHour * 60 + dateTimeRangeArray[i].EndMinute;
						int num3 = hour * 60 + minute;
						if (!equalEndTime)
						{
							num2--;
						}
						if (num3 >= num && num3 <= num2)
						{
							endMinute = num2;
							return true;
						}
					}
				}
				result = false;
			}
			return result;
		}

