		public static bool CanTakeNormalYaBiao(GameClient client)
		{
			bool result;
			if (null == client.ClientData.MyYaBiaoData)
			{
				result = true;
			}
			else
			{
				int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
				if (client.ClientData.MyYaBiaoData.YaBiaoDayID != dayOfYear)
				{
					result = true;
				}
				else
				{
					int num = Global.MaxDayYaBiaoNum;
					num += (int)DBRoleBufferManager.ProcessMonthVIP(client);
					result = (client.ClientData.MyYaBiaoData.YaBiaoNum < num);
				}
			}
			return result;
		}

