		public static bool CanGetDayChongZhiDaLi(GameClient client, int nBtnIndex)
		{
			int num = 0;
			string roleParamByName = Global.GetRoleParamByName(client, "DailyChargeGiftFlags");
			if (!string.IsNullOrEmpty(roleParamByName))
			{
				string[] array = roleParamByName.Split(new char[]
				{
					','
				});
				num = Global.SafeConvertToInt32(array[nBtnIndex - 1]);
			}
			return num != TimeUtil.NowDateTime().DayOfYear;
		}

		public static void CompleteDayChongZhiDaLi(GameClient client, int nBtnIndex)
		{
			string roleParamByName = Global.GetRoleParamByName(client, "DailyChargeGiftFlags");
			string text = "";
			string[] array;
			if (string.IsNullOrEmpty(roleParamByName))
			{
				int count = ((MeiRiChongZhiActivity)Global.GetActivity(ActivityTypes.MeiRiChongZhiHaoLi)).AwardDict.Count;
				array = new string[count];
				for (int i = 0; i < count; i++)
				{
					array[i] = "-1";
				}
			}
			else
			{
				array = roleParamByName.Split(new char[]
				{
					','
				});
			}
			array[nBtnIndex - 1] = TimeUtil.NowDateTime().DayOfYear.ToString();
			for (int i = 0; i < array.Length; i++)
			{
				if (0 == i)
				{
					text = array[0];
				}
				else
				{
					text = text + "," + array[i];
				}
			}
			Global.SaveRoleParamsStringToDB(client, "DailyChargeGiftFlags", text, true);
		}

		public static bool CanGetChongJiLingQuShenZhuang(GameClient client, int nBtnIndex)
		{
			string text = Global.GetRoleParamByName(client, "ChongJiGiftList");
			bool result;
			if (string.IsNullOrEmpty(text))
			{
				KingActivity kingActivity = (KingActivity)Global.GetActivity(ActivityTypes.NewZoneUpLevelMadman);
				int count = kingActivity.RoleLimit.Count;
				for (int i = 0; i < count; i++)
				{
					if (i == 0)
					{
						text = "0";
					}
					else
					{
						text += ",0";
					}
				}
				Global.SaveRoleParamsStringToDB(client, "ChongJiGiftList", text, true);
				result = true;
			}
			else
			{
				string[] array = text.Split(new char[]
				{
					','
				});
				result = (array[nBtnIndex - 1] == "0");
			}
			return result;
		}

		public static bool CanGetChongJiLingQuShenZhuangUserID(GameClient client, int nBtnIndex, ActivityTypes ActType)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			string[] array = Global.ExecuteDBCmd(10121, string.Format("{0}:{1}:{2}:{3}", new object[]
			{
				client.ClientData.RoleID,
				dayOfYear,
				nBtnIndex,
				ActType
			}), client.ServerId);
			return array == null || array.Length != 1 || int.Parse(array[0]) <= 0;
		}

		public static int GetChongJiLingQuShenZhuangQuota(GameClient client, int nBtnIndex)
		{
			string text = GameManager.GameConfigMgr.GetGameConfigItemStr("ChongJiGiftList", "");
			int result;
			if (string.IsNullOrEmpty(text))
			{
				KingActivity kingActivity = (KingActivity)Global.GetActivity(ActivityTypes.NewZoneUpLevelMadman);
				text = "";
				int count = kingActivity.RoleLimit.Count;
				for (int i = 1; i < count + 1; i++)
				{
					if (i == 1)
					{
						text = "0";
					}
					else
					{
						text += ",0";
					}
				}
				GameManager.GameConfigMgr.SetGameConfigItem("ChongJiGiftList", text);
				Global.UpdateDBGameConfigg("ChongJiGiftList", text);
				result = 0;
			}
			else
			{
				int num = Global.SafeConvertToInt32(text.Split(new char[]
				{
					','
				})[nBtnIndex - 1]);
				result = num;
			}
			return result;
		}

		public static void CompleteChongJiLingQuShenZhuang(GameClient client, int nBtnIndex, int nQuota)
		{
			string roleParamByName = Global.GetRoleParamByName(client, "ChongJiGiftList");
			string[] array = roleParamByName.Split(new char[]
			{
				','
			});
			if (nBtnIndex <= array.Length)
			{
				array[nBtnIndex - 1] = "1";
				string text = "";
				for (int i = 0; i < array.Length; i++)
				{
					if (i == 0)
					{
						text = array[i];
					}
					else
					{
						text = text + "," + array[i];
					}
				}
				Global.SaveRoleParamsStringToDB(client, "ChongJiGiftList", text, true);
				string gameConfigItemStr = GameManager.GameConfigMgr.GetGameConfigItemStr("ChongJiGiftList", "");
				string[] array2 = gameConfigItemStr.Split(new char[]
				{
					','
				});
				array2[nBtnIndex - 1] = nQuota.ToString();
				string text2 = "";
				for (int i = 0; i < array2.Length; i++)
				{
					if (i == 0)
					{
						text2 = array2[0];
					}
					else
					{
						text2 = text2 + "," + array2[i];
					}
				}
				Global.UpdateDBGameConfigg("ChongJiGiftList", text2);
			}
		}

