		public static BangHuiMiniData GetBangHuiMiniData(int bangHuiID, int serverId = 0)
		{
			BangHuiMiniData bangHuiMiniData = null;
			BangHuiMiniData result;
			if (Global.DictBangHui.TryGetValue(bangHuiID, out bangHuiMiniData))
			{
				result = bangHuiMiniData;
			}
			else
			{
				byte[] array = null;
				if (TCPProcessCmdResults.RESULT_FAILED == Global.RequestToDBServer3(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10106, string.Format("{0}", bangHuiID), out array, serverId))
				{
					result = null;
				}
				else if (array == null || array.Length <= 6)
				{
					result = null;
				}
				else
				{
					int num = BitConverter.ToInt32(array, 0);
					bangHuiMiniData = DataHelper.BytesToObject<BangHuiMiniData>(array, 6, num - 2);
					if (null == bangHuiMiniData)
					{
						result = null;
					}
					else
					{
						lock (Global.DictBangHui)
						{
							if (!Global.DictBangHui.ContainsKey(bangHuiID))
							{
								Global.DictBangHui.Add(bangHuiID, bangHuiMiniData);
							}
						}
						result = bangHuiMiniData;
					}
				}
			}
			return result;
		}

