		public static double ProcessLingDiMonsterExperience(GameClient client, Monster monster)
		{
			double num = 0.0;
			double result;
			if (client.ClientData.Faction <= 0)
			{
				result = 0.0;
			}
			else
			{
				int lingDiID = 3;
				if (client.ClientData.Faction != JunQiManager.GetBHIDByLingDiID(lingDiID))
				{
					result = num;
				}
				else
				{
					int junQiLevelByBHID = JunQiManager.GetJunQiLevelByBHID(client.ClientData.Faction);
					if (junQiLevelByBHID <= 0)
					{
						result = num;
					}
					else
					{
						if (1 == junQiLevelByBHID)
						{
							num = 0.05;
						}
						else if (2 == junQiLevelByBHID)
						{
							num = 0.15;
						}
						else if (3 == junQiLevelByBHID)
						{
							num = 0.3;
						}
						else if (4 == junQiLevelByBHID)
						{
							num = 0.5;
						}
						result = num;
					}
				}
			}
			return result;
		}

