		public static bool CanHuangChengAlive(GameClient client)
		{
			bool result;
			if (client.ClientData.Faction <= 0)
			{
				result = false;
			}
			else
			{
				BangHuiLingDiItemData firstLingDiItemDataByBHID = JunQiManager.GetFirstLingDiItemDataByBHID(client.ClientData.Faction);
				if (null == firstLingDiItemDataByBHID)
				{
					result = false;
				}
				else
				{
					SystemXmlItem systemXmlItem = null;
					if (!GameManager.systemHuangChengFuHuoMgr.SystemXmlItemDict.TryGetValue(firstLingDiItemDataByBHID.LingDiID, out systemXmlItem))
					{
						result = false;
					}
					else
					{
						int intValue = systemXmlItem.GetIntValue("PosX", -1);
						int intValue2 = systemXmlItem.GetIntValue("PosY", -1);
						result = !Global.InCircle(new Point((double)client.ClientData.PosX, (double)client.ClientData.PosY), new Point((double)intValue, (double)intValue2), (double)Global.MaxRadiusMustGoToYangZhou);
					}
				}
			}
			return result;
		}

