		public static bool CanOpenFallBaoXiang(GameClient client, SystemXmlItem systemGoodsItem, int goodsID)
		{
			List<MagicActionItem> list = null;
			bool result;
			if (!GameManager.SystemMagicActionMgr.GoodsActionsDict.TryGetValue(goodsID, out list) || null == list)
			{
				result = true;
			}
			else if (list.Count <= 0)
			{
				result = true;
			}
			else
			{
				MagicActionItem magicActionItem = list[0];
				if (MagicActionIDs.FALL_BAOXIANG != magicActionItem.MagicActionID && MagicActionIDs.FALL_BAOXIANG_2 != magicActionItem.MagicActionID)
				{
					result = true;
				}
				else
				{
					int num = (int)magicActionItem.MagicActionParams[1];
					if (MagicActionIDs.FALL_BAOXIANG == magicActionItem.MagicActionID)
					{
						if (RebornEquip.IsRebornType(goodsID))
						{
							result = RebornEquip.CanAddGoodsNum(client, num);
						}
						else
						{
							result = Global.CanAddGoodsNum(client, num);
						}
					}
					else
					{
						int num2 = (int)magicActionItem.MagicActionParams[2];
						if (num2 <= 7000)
						{
							if (num2 == 0)
							{
								return Global.CanAddGoodsNum(client, num);
							}
							if (num2 == 3000)
							{
								return ElementhrtsManager.CanAddGoodsNum(client, num);
							}
							if (num2 == 7000)
							{
								return GameManager.FluorescentGemMgr.CanAddGoodsNum(client, num);
							}
						}
						else if (num2 <= 11000)
						{
							if (num2 == 8000)
							{
								return SingletonTemplate<SoulStoneManager>.Instance().CanAddGoodsNum(client, num);
							}
							if (num2 == 11000)
							{
								return ShenShiManager.CanAddGoodsNum(client, num);
							}
						}
						else
						{
							if (num2 == 15000)
							{
								return RebornEquip.CanAddGoodsNum(client, num);
							}
							if (num2 == 16000)
							{
								return MountHolyStampManager.CanAddGoodsNum(client, num);
							}
						}
						result = false;
					}
				}
			}
			return result;
		}

		public static bool CanUnPackSimpleGoods(GameClient client, SystemXmlItem systemGoodsItem, int goodsID)
		{
			List<MagicActionItem> list = null;
			bool result;
			if (!GameManager.SystemMagicActionMgr.GoodsActionsDict.TryGetValue(goodsID, out list) || null == list)
			{
				result = true;
			}
			else if (list.Count <= 0)
			{
				LogManager.WriteLog(2, string.Format("CanUnPackSimpleGoods magicActionItemList.Count goodsID={0}", goodsID), null, true);
				result = false;
			}
			else
			{
				MagicActionItem magicActionItem = list[0];
				if (MagicActionIDs.UN_PACK != magicActionItem.MagicActionID)
				{
					result = true;
				}
				else
				{
					int num = (int)magicActionItem.MagicActionParams[1];
					int num2 = Global.GetGoodsGridNumByID((int)magicActionItem.MagicActionParams[0]);
					num2 = Math.Max(num2, 1);
					int newGoodsCount = num / num2 + ((num % num2 == 0) ? 0 : 1);
					result = Global.CanAddGoodsNum(client, newGoodsCount);
				}
			}
			return result;
		}

