		public static Dictionary<int, int> GetYaoShiDiaoLuoForXiangZhi(int idXiangZi)
		{
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			Dictionary<int, SystemXmlItem> systemXmlItemDict = GameManager.SystemGoods.SystemXmlItemDict;
			Dictionary<int, int> result;
			if (!systemXmlItemDict.Keys.Contains(idXiangZi))
			{
				result = dictionary;
			}
			else
			{
				SystemXmlItem systemXmlItem = systemXmlItemDict[idXiangZi];
				if (null == systemXmlItem)
				{
					result = dictionary;
				}
				else
				{
					string stringValue = systemXmlItem.GetStringValue("ExecMagic");
					int num = stringValue.IndexOf('(');
					int num2 = stringValue.IndexOf(')');
					if (num < 0 || num2 <= 0 || num2 - num < 1 || num + 1 >= stringValue.Length)
					{
						result = dictionary;
					}
					else
					{
						string[] array = stringValue.Substring(num + 1, num2 - num - 1).Split(new char[]
						{
							'|'
						});
						for (int i = 0; i < array.Length; i++)
						{
							if (!string.IsNullOrWhiteSpace(array[i]))
							{
								string[] array2 = array[i].Split(new char[]
								{
									','
								});
								if (2 == array2.Length)
								{
									dictionary.Add(Convert.ToInt32(array2[1]), Convert.ToInt32(array2[0]));
								}
							}
						}
						result = dictionary;
					}
				}
			}
			return result;
		}

		public static int SubUserMoneyForGoods(GameClient client, Dictionary<int, int> needGoods, string sReason)
		{
			int num = 0;
			foreach (KeyValuePair<int, int> keyValuePair in needGoods)
			{
				int priceByGoodsID = MallPriceMgr.GetPriceByGoodsID(keyValuePair.Key);
				if (priceByGoodsID <= 0)
				{
					return -2000;
				}
				int value = keyValuePair.Value;
				if (value <= 0 || value >= 10000)
				{
					return -2100;
				}
				num += priceByGoodsID * value;
			}
			int result;
			if (num <= 0)
			{
				result = -2200;
			}
			else if (client.ClientData.UserMoney + client.ClientData.Gold < num)
			{
				result = -2300;
			}
			else
			{
				foreach (KeyValuePair<int, int> keyValuePair in needGoods)
				{
					int num2 = Global.SubUserMoneyForGoods(client, keyValuePair.Key, keyValuePair.Value, sReason);
					if (num2 <= 0)
					{
						return num2;
					}
				}
				result = num;
			}
			return result;
		}

		public static int SubUserMoneyForGoods(GameClient client, int needGoodsID, int needGoodsNum, string sReason)
		{
			int priceTypeByGoodsIDFromCfg = MallPriceMgr.GetPriceTypeByGoodsIDFromCfg(needGoodsID);
			int result;
			if (0 == priceTypeByGoodsIDFromCfg)
			{
				result = Global.SubUserYuanBaoForGoods(client, needGoodsID, needGoodsNum, sReason);
			}
			else if (1 == priceTypeByGoodsIDFromCfg)
			{
				result = Global.SubUserGoldForGoods(client, needGoodsID, needGoodsNum, sReason);
			}
			else
			{
				result = 0;
			}
			return result;
		}

		public static int SubUserYuanBaoForGoods(GameClient client, int needGoodsID, int needGoodsNum, string sReason)
		{
			int priceByGoodsID = MallPriceMgr.GetPriceByGoodsID(needGoodsID);
			int result;
			if (priceByGoodsID <= 0)
			{
				result = -2000;
			}
			else if (needGoodsNum <= 0 || needGoodsNum >= 10000)
			{
				result = -2100;
			}
			else
			{
				int num = priceByGoodsID * needGoodsNum;
				if (num <= 0)
				{
					result = -2200;
				}
				else if (client.ClientData.UserMoney < num)
				{
					result = -2300;
				}
				else
				{
					int userMoney = client.ClientData.UserMoney;
					string msg = string.Format("物品[{0}]x[{1}]{2}", needGoodsID, needGoodsNum, sReason);
					if (!GameManager.ClientMgr.SubUserMoney(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, num, msg, true, true, false, DaiBiSySType.None))
					{
						result = -2400;
					}
					else
					{
						int subYuanBao = num;
						Global.AddAutoSubYuanBaoEvent(client, needGoodsID, needGoodsNum, priceByGoodsID, subYuanBao, sReason, userMoney, client.ClientData.UserMoney);
						result = num;
					}
				}
			}
			return result;
		}

		public static int SubUserGoldForGoods(GameClient client, int needGoodsID, int needGoodsNum, string sReason)
		{
			int priceByGoodsID = MallPriceMgr.GetPriceByGoodsID(needGoodsID);
			int result;
			if (priceByGoodsID <= 0)
			{
				result = -2000;
			}
			else if (needGoodsNum <= 0 || needGoodsNum >= 10000)
			{
				result = -2100;
			}
			else
			{
				int num = priceByGoodsID * needGoodsNum;
				if (num <= 0)
				{
					result = -2200;
				}
				else if (client.ClientData.Gold < num)
				{
					result = -2300;
				}
				else
				{
					int gold = client.ClientData.Gold;
					if (!GameManager.ClientMgr.SubUserGold(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, num, "无", false))
					{
						result = -2400;
					}
					else
					{
						int subGold = num;
						Global.AddAutoSubGoldEvent(client, needGoodsID, needGoodsNum, priceByGoodsID, subGold, sReason, gold, client.ClientData.Gold);
						result = num;
					}
				}
			}
			return result;
		}

		public static void AddCoolDownItem(Dictionary<int, CoolDownItem> coolDownDict, int id, long startTicks, long cdTicks)
		{
			CoolDownItem coolDownItem = null;
			coolDownDict.TryGetValue(id, out coolDownItem);
			if (null == coolDownItem)
			{
				coolDownItem = new CoolDownItem
				{
					ID = id,
					StartTicks = startTicks,
					CDTicks = cdTicks
				};
				coolDownDict[id] = coolDownItem;
			}
			else if (startTicks + cdTicks > coolDownItem.StartTicks + coolDownItem.CDTicks)
			{
				coolDownItem.StartTicks = startTicks;
				coolDownItem.CDTicks = cdTicks;
			}
		}

