		public static string GetActivityRequestCmdString(ActivityTypes type, GameClient client, int extTag = 0)
		{
			int roleID = client.ClientData.RoleID;
			string result = "";
			string format = "{0}:{1}:{2}:{3}:{4}";
			KingActivity kingActivity = null;
			switch (type)
			{
			case ActivityTypes.InputFanLi:
			{
				InputFanLiActivity inputFanLiActivity = HuodongCachingMgr.GetInputFanLiActivity();
				if (null != inputFanLiActivity)
				{
					result = string.Format(format, new object[]
					{
						roleID,
						inputFanLiActivity.FromDate.Replace(':', '$'),
						inputFanLiActivity.ToDate.Replace(':', '$'),
						inputFanLiActivity.FanLiPersent,
						extTag
					});
				}
				break;
			}
			case ActivityTypes.InputJiaSong:
			{
				InputSongActivity inputSongActivity = HuodongCachingMgr.GetInputSongActivity();
				if (null != inputSongActivity)
				{
					result = string.Format(format, new object[]
					{
						roleID,
						inputSongActivity.FromDate.Replace(':', '$'),
						inputSongActivity.ToDate.Replace(':', '$'),
						inputSongActivity.MyAwardItem.MinAwardCondionValue,
						extTag
					});
				}
				break;
			}
			case ActivityTypes.InputKing:
			case ActivityTypes.NewZoneRechargeKing:
				kingActivity = HuodongCachingMgr.GetInputKingActivity();
				extTag = 4;
				break;
			case ActivityTypes.LevelKing:
				kingActivity = HuodongCachingMgr.GetLevelKingActivity();
				break;
			case ActivityTypes.EquipKing:
			case ActivityTypes.NewZoneBosskillKing:
				kingActivity = HuodongCachingMgr.GetEquipKingActivity();
				extTag = 6;
				break;
			case ActivityTypes.HorseKing:
				kingActivity = HuodongCachingMgr.GetHorseKingActivity();
				break;
			case ActivityTypes.JingMaiKing:
				kingActivity = HuodongCachingMgr.GetJingMaiKingActivity();
				break;
			case ActivityTypes.JieriDaLiBao:
			{
				JieriDaLiBaoActivity jieriDaLiBaoActivity = HuodongCachingMgr.GetJieriDaLiBaoActivity();
				if (null != jieriDaLiBaoActivity)
				{
					result = string.Format(format, new object[]
					{
						roleID,
						jieriDaLiBaoActivity.FromDate.Replace(':', '$'),
						jieriDaLiBaoActivity.ToDate.Replace(':', '$'),
						jieriDaLiBaoActivity.MyAwardItem.MinAwardCondionValue,
						extTag
					});
				}
				break;
			}
			case ActivityTypes.JieriDengLuHaoLi:
			{
				JieRiDengLuActivity jieRiDengLuActivity = HuodongCachingMgr.GetJieRiDengLuActivity();
				if (null != jieRiDengLuActivity)
				{
					result = string.Format(format, new object[]
					{
						roleID,
						jieRiDengLuActivity.FromDate.Replace(':', '$'),
						jieRiDengLuActivity.ToDate.Replace(':', '$'),
						Global.GetRoleParamsInt32FromDB(client, "JieriLoginNum"),
						extTag
					});
				}
				break;
			}
			case ActivityTypes.JieriVIP:
			{
				JieriVIPActivity jieriVIPActivity = HuodongCachingMgr.GetJieriVIPActivity();
				if (null != jieriVIPActivity)
				{
					result = string.Format(format, new object[]
					{
						roleID,
						jieriVIPActivity.FromDate.Replace(':', '$'),
						jieriVIPActivity.ToDate.Replace(':', '$'),
						Global.IsVip(client) ? 1 : 0,
						extTag
					});
				}
				break;
			}
			case ActivityTypes.JieriCZSong:
			{
				JieriCZSongActivity jieriCZSongActivity = HuodongCachingMgr.GetJieriCZSongActivity();
				if (null != jieriCZSongActivity)
				{
					string text = new DateTime(TimeUtil.NowDateTime().Year, TimeUtil.NowDateTime().Month, TimeUtil.NowDateTime().Day, 0, 0, 0).ToString();
					string text2 = new DateTime(TimeUtil.NowDateTime().Year, TimeUtil.NowDateTime().Month, TimeUtil.NowDateTime().Day, 23, 59, 59).ToString();
					AwardItem award = jieriCZSongActivity.GetAward(extTag);
					if (null != award)
					{
						result = string.Format(format, new object[]
						{
							roleID,
							text.Replace(':', '$'),
							text2.Replace(':', '$'),
							award.MinAwardCondionValue,
							extTag
						});
					}
					else
					{
						result = string.Format(format, new object[]
						{
							roleID,
							text.Replace(':', '$'),
							text2.Replace(':', '$'),
							0,
							extTag
						});
					}
				}
				break;
			}
