		public static bool AddZaJinDanJiFen(GameClient client, int addJiFen, string strFrom, bool isGM = false)
		{
			int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(client, "ZJDJiFen");
			long num = (long)roleParamsInt32FromDB;
			long num2 = num + (long)addJiFen;
			bool result;
			if (isGM && (num2 > 2147483647L || num2 < -2147483648L))
			{
				result = false;
			}
			else
			{
				int nSurplus = (int)Global.Clamp(num2, -2147483648L, 2147483647L);
				if (addJiFen > 0)
				{
					GameManager.logDBCmdMgr.AddDBLogInfo(-1, "祈福积分", strFrom, "系统", client.ClientData.RoleName, "增加", addJiFen, client.ClientData.ZoneID, client.strUserID, nSurplus, client.ServerId, null);
				}
				else
				{
					GameManager.logDBCmdMgr.AddDBLogInfo(-1, "祈福积分", strFrom, client.ClientData.RoleName, "系统", "减少", addJiFen, client.ClientData.ZoneID, client.strUserID, nSurplus, client.ServerId, null);
				}
				Global.SaveRoleParamsInt32ValueToDB(client, "ZJDJiFen", roleParamsInt32FromDB + addJiFen, true);
				GameManager.ClientMgr.NotifyZaJinDanKAwardDailyData(client);
				result = true;
			}
			return result;
		}

