				}
			}
		}

		public static ShiLianTaAwardsInfoData GetShiLianTaFuBenAwardsInfoData(GameClient client)
		{
			int num = FuBenManager.FindFuBenIDByMapCode(client.ClientData.MapCode);
			ShiLianTaAwardsInfoData result;
			if (num <= 0)
			{
				result = null;
			}
			else if (client.ClientData.FuBenSeqID <= 0)
			{
				result = null;
			}
			else
			{
				FuBenInfoItem fuBenInfoItem = FuBenManager.FindFuBenInfoBySeqID(client.ClientData.FuBenSeqID);
				if (null == fuBenInfoItem)
				{
					result = null;
				}
				else if (num != fuBenInfoItem.FuBenID)
				{
					result = null;
				}
				else
				{
					FuBenMapItem fuBenMapItem = FuBenManager.FindMapCodeByFuBenID(num, client.ClientData.MapCode);
					if (null == fuBenMapItem)
					{
						result = null;
					}
					else
					{
						SystemXmlItem systemXmlItem = Global.FindShiLianTaFuBenItemByMapCode(client);
						if (null == systemXmlItem)
						{
							result = null;
						}
						else
						{
							int num2 = FuBenManager.FindMapCodeIndexByFuBenID(client.ClientData.MapCode);
							if (num2 <= 0)
							{
								result = null;
							}
							else
							{
								int nextFloorExperienceAward = 0;
								int num3 = FuBenManager.FindNextMapCodeByFuBenID(client.ClientData.MapCode);
								if (-1 != num3)
								{
									FuBenMapItem fuBenMapItem2 = FuBenManager.FindMapCodeByFuBenID(num, num3);
									if (null != fuBenMapItem2)
									{
										nextFloorExperienceAward = Global.GMax(0, fuBenMapItem2.Experience);
									}
								}
								ShiLianTaAwardsInfoData shiLianTaAwardsInfoData = new ShiLianTaAwardsInfoData
								{
									CurrentFloorTotalMonsterNum = 5,
									CurrentFloorExperienceAward = Global.GMax(0, fuBenMapItem.Experience),
									NextFloorNeedGoodsID = systemXmlItem.GetIntValue("EnterGoods", -1),
									NextFloorNeedGoodsNum = Global.GetShiLianTaNeedGoodsNum(systemXmlItem.GetIntValue("GoodsNumber", -1), num2 + 1),
									NextFloorExperienceAward = nextFloorExperienceAward
								};
								result = shiLianTaAwardsInfoData;
							}
						}
					}
				}
			}
			return result;
		}

