		public static void RecalcDSMonsterProps(GameClient client, Monster monster, int magicLevel, int SurvivalTime)
		{
			double[] paramValueDoubleArrayByName;
			if ((long)monster.MonsterInfo.ExtensionID == GameManager.systemParamsList.GetParamValueIntByName("DSMonsterKuLouID", -1))
			{
				paramValueDoubleArrayByName = GameManager.systemParamsList.GetParamValueDoubleArrayByName("DSMonsterKuLouProps", ',');
			}
			else
			{
				if ((long)monster.MonsterInfo.ExtensionID != GameManager.systemParamsList.GetParamValueIntByName("DSMonsterShenShouID", -1))
				{
					return;
				}
				paramValueDoubleArrayByName = GameManager.systemParamsList.GetParamValueDoubleArrayByName("DSMonsterShenShouProps", ',');
			}
			double[] paramValueDoubleArrayByName2 = GameManager.systemParamsList.GetParamValueDoubleArrayByName("DSMonsterKuLouPropsTwo", ',');
			if (paramValueDoubleArrayByName2 != null && paramValueDoubleArrayByName != null && paramValueDoubleArrayByName2.Length == 18 && paramValueDoubleArrayByName.Length == 18)
			{
				int num = (int)Math.Pow((double)(client.ClientData.ChangeLifeCount * 100 + client.ClientData.Level), 1.8);
				monster.MonsterInfo.Defense = (int)(paramValueDoubleArrayByName[0] * (double)num) + (int)(paramValueDoubleArrayByName2[0] * RoleAlgorithm.GetMaxADefenseV(client));
				monster.MonsterInfo.MDefense = (int)(paramValueDoubleArrayByName[1] * (double)num) + (int)(paramValueDoubleArrayByName2[1] * RoleAlgorithm.GetMaxMDefenseV(client));
				monster.MonsterInfo.MinAttack = (int)(paramValueDoubleArrayByName[2] * (double)num) + (int)(paramValueDoubleArrayByName2[2] * Math.Max(RoleAlgorithm.GetMaxAttackV(client), RoleAlgorithm.GetMaxMagicAttackV(client)));
				monster.MonsterInfo.MaxAttack = (int)(paramValueDoubleArrayByName[3] * (double)num) + (int)(paramValueDoubleArrayByName2[3] * Math.Max(RoleAlgorithm.GetMaxAttackV(client), RoleAlgorithm.GetMaxMagicAttackV(client)));
				monster.MonsterInfo.VLifeMax = (double)((int)(paramValueDoubleArrayByName[4] * (double)num) + (int)(paramValueDoubleArrayByName2[4] * RoleAlgorithm.GetMaxLifeV(client)));
				monster.MonsterInfo.HitV = (double)((int)(paramValueDoubleArrayByName[5] * (double)num) + (int)(paramValueDoubleArrayByName2[5] * RoleAlgorithm.GetHitV(client)));
				monster.MonsterInfo.Dodge = (double)((int)(paramValueDoubleArrayByName[6] * (double)num) + (int)(paramValueDoubleArrayByName2[6] * RoleAlgorithm.GetDodgeV(client)));
				monster.MonsterInfo.MonsterSubAttackInjurePercent = paramValueDoubleArrayByName[7] * (double)num + paramValueDoubleArrayByName2[7] * RoleAlgorithm.GetExtProp(client, 24);
				monster.MonsterInfo.ExtProps[122] = paramValueDoubleArrayByName[8] * (double)num + paramValueDoubleArrayByName2[8] * RoleAlgorithm.GetExtProp(client, 122);
				monster.MonsterInfo.ExtProps[123] = paramValueDoubleArrayByName[9] * (double)num + paramValueDoubleArrayByName2[9] * RoleAlgorithm.GetExtProp(client, 123);
				monster.MonsterInfo.ExtProps[129] = paramValueDoubleArrayByName[10] * (double)num + paramValueDoubleArrayByName2[10] * RoleAlgorithm.GetExtProp(client, 129);
				monster.MonsterInfo.ExtProps[130] = paramValueDoubleArrayByName[11] * (double)num + paramValueDoubleArrayByName2[11] * RoleAlgorithm.GetExtProp(client, 130);
				monster.MonsterInfo.ExtProps[136] = paramValueDoubleArrayByName[12] * (double)num + paramValueDoubleArrayByName2[12] * RoleAlgorithm.GetExtProp(client, 136);
				monster.MonsterInfo.ExtProps[137] = paramValueDoubleArrayByName[13] * (double)num + paramValueDoubleArrayByName2[13] * RoleAlgorithm.GetExtProp(client, 137);
				monster.MonsterInfo.ExtProps[143] = paramValueDoubleArrayByName[14] * (double)num + paramValueDoubleArrayByName2[14] * RoleAlgorithm.GetExtProp(client, 143);
				monster.MonsterInfo.ExtProps[144] = paramValueDoubleArrayByName[15] * (double)num + paramValueDoubleArrayByName2[15] * RoleAlgorithm.GetExtProp(client, 144);
				monster.MonsterInfo.ExtProps[150] = paramValueDoubleArrayByName[16] * (double)num + paramValueDoubleArrayByName2[16] * RoleAlgorithm.GetExtProp(client, 150);
				monster.MonsterInfo.ExtProps[151] = paramValueDoubleArrayByName[17] * (double)num + paramValueDoubleArrayByName2[17] * RoleAlgorithm.GetExtProp(client, 151);
				if (monster.MonsterInfo != null && monster.MonsterInfo.ExtProps != null)
				{
					Array.Copy(monster.MonsterInfo.ExtProps, monster.DynamicData.ExtProps, 177);
				}
				monster.VLife = monster.MonsterInfo.VLifeMax;
				monster.CurrentMagicLevel = magicLevel;
				monster.SurvivalTime = SurvivalTime * 1000;
				monster.SurvivalTick = TimeUtil.NOW() + (long)monster.SurvivalTime;
			}
		}

