		public static string GetRoleParamsStringWithNullFromDBOffline(int rid, string roleParamsKey, int serverid)
		{
			string text = Global.GetRoleParamsFromDBByRoleID(rid, roleParamsKey, serverid);
			string result;
			if (string.IsNullOrEmpty(text))
			{
				result = text;
			}
			else
			{
				byte[] bytes = Convert.FromBase64String(text);
				text = Encoding.GetEncoding("latin1").GetString(bytes);
				result = text;
			}
