		public static bool GetMapRecordDataByField(GameClient client, int indexRecord, out int mapCode, out int x, out int y)
		{
			mapCode = 0;
			x = 0;
			y = 0;
			List<ushort> roleParamsUshortListFromDB = Global.GetRoleParamsUshortListFromDB(client, "MapPosRecord");
			int num = indexRecord * 3;
			bool result;
			if (num + 2 >= roleParamsUshortListFromDB.Count)
			{
				result = false;
			}
			else
			{
				mapCode = (int)roleParamsUshortListFromDB[num++];
				x = (int)roleParamsUshortListFromDB[num++];
				y = (int)roleParamsUshortListFromDB[num];
				result = (mapCode != 0 || x != 0 || 0 != y);
			}
			return result;
		}

		public static void ModifyMapRecordData(GameClient client, ushort mapCode, ushort x, ushort y, int indexRecord)
		{
			List<ushort> roleParamsUshortListFromDB = Global.GetRoleParamsUshortListFromDB(client, "MapPosRecord");
			int num = indexRecord * 3;
			while (roleParamsUshortListFromDB.Count < num + 3)
			{
				roleParamsUshortListFromDB.Add(0);
				roleParamsUshortListFromDB.Add(0);
				roleParamsUshortListFromDB.Add(0);
			}
			roleParamsUshortListFromDB[num++] = mapCode;
			roleParamsUshortListFromDB[num++] = x;
			roleParamsUshortListFromDB[num] = y;
			Global.SaveRoleParamsUshortListToDB(client, roleParamsUshortListFromDB, "MapPosRecord", true);
		}

