		public static void ParseDayLimitSecsByMapCode(GameClient client, int mapCode, out int oldDayID, out int oldStayingSecs, out int oldRoleAddedSecs)
		{
			oldDayID = -1;
			oldStayingSecs = 0;
			oldRoleAddedSecs = 0;
			string name = string.Format("{0}{1}", "MapLimitSecs_", mapCode);
			string roleParamByName = Global.GetRoleParamByName(client, name);
			if (!string.IsNullOrEmpty(roleParamByName))
			{
				string[] array = roleParamByName.Split(new char[]
				{
					','
				});
				if (array.Length == 3)
				{
					oldDayID = Global.SafeConvertToInt32(array[0]);
					oldStayingSecs = Global.SafeConvertToInt32(array[1]);
					oldRoleAddedSecs = Global.SafeConvertToInt32(array[2]);
				}
			}
		}

		public static void UpdateDayLimitSecsByMapCode(GameClient client, int mapCode, int oldDayID, int oldStayingSecs, int oldRoleAddedSecs)
		{
			string name = string.Format("{0}{1}", "MapLimitSecs_", mapCode);
			string value = string.Format("{0},{1},{2}", oldDayID, oldStayingSecs, oldRoleAddedSecs);
			Global.UpdateRoleParamByName(client, name, value, false);
		}

		public static bool AddStayingSecsByMapCode(GameClient client, int mapCode, int elapsedSecs)
		{
			int num = Global.GetDayLimitSecsByMapCode(mapCode);
			bool result;
			if (num <= 0)
			{
				result = false;
			}
			else
			{
				int num2 = -1;
				int num3 = 0;
				int num4 = 0;
				Global.ParseDayLimitSecsByMapCode(client, mapCode, out num2, out num3, out num4);
				int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
				if (dayOfYear != num2)
				{
					num2 = dayOfYear;
					num3 = 0;
					num4 = 0;
				}
				num3 += elapsedSecs;
				Global.UpdateDayLimitSecsByMapCode(client, mapCode, num2, num3, num4);
				GameMap gameMap = GameManager.MapMgr.DictMaps[mapCode];
				num = gameMap.DayLimitSecs + num4;
				result = (num3 >= num);
			}
			return result;
		}

		public static int AddExtLimitSecsByMapCode(GameClient client, int mapCode, int limitSecs)
		{
			int dayLimitSecsByMapCode = Global.GetDayLimitSecsByMapCode(mapCode);
			int result;
			if (dayLimitSecsByMapCode <= 0)
			{
				result = 0;
			}
			else
			{
				int num = -1;
				int oldStayingSecs = 0;
				int num2 = 0;
				Global.ParseDayLimitSecsByMapCode(client, mapCode, out num, out oldStayingSecs, out num2);
				int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
				if (dayOfYear != num)
				{
					num = dayOfYear;
					oldStayingSecs = 0;
					num2 = 0;
				}
				num2 += limitSecs;
				Global.UpdateDayLimitSecsByMapCode(client, mapCode, num, oldStayingSecs, num2);
				result = num2;
			}
			return result;
		}

		public static void ProcessDayLimitSecsByClient(GameClient client, int elapsedSecs)
		{
			if (Global.AddStayingSecsByMapCode(client, client.ClientData.MapCode, elapsedSecs))
			{
				GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(90, new object[0]), new object[]
				{
					Global.GetMapName(client.ClientData.MapCode)
				}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
				GameManager.ClientMgr.NotifyChangeMap(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, GameManager.DefaultMapCode, -1, -1, -1, 0);
			}
		}

		public static bool CanUseTongLing(GameClient client, SystemXmlItem systemGoodsItem, int goodsID)
		{
			string stringValue = systemGoodsItem.GetStringValue("ExecMagic");
			bool result;
			if (-1 == stringValue.IndexOf("FALL_XINGYUN") && -1 == stringValue.IndexOf("ADD_XINGYUN"))
			{
				result = true;
			}
			else
			{
				List<GoodsData> usingWeaponGoods = Global.GetUsingWeaponGoods(client);
				if (usingWeaponGoods == null || usingWeaponGoods.Count<GoodsData>() == 0)
				{
					GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(357, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					result = false;
				}
				else
				{
					for (int i = 0; i < usingWeaponGoods.Count<GoodsData>(); i++)
					{
						if (usingWeaponGoods[i].Lucky >= 9)
						{
							GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(358, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
						}
					}
					result = true;
				}
			}
			return result;
		}

