		public static void TryToActivateSpecialZuanHuangLevel(GameClient client, bool notifyPropsChanged = true)
		{
			int zuanHuangLevelValue = GameManager.ClientMgr.GetZuanHuangLevelValue(client);
			for (int i = 0; i < 10; i++)
			{
				int zuanHuangLevelValue2 = GameManager.ClientMgr.GetZuanHuangLevelValue(client);
				int num = zuanHuangLevelValue2 + 1;
				if (num > GameManager.SystemZuanHuangLevel.SystemXmlItemDict.Count)
				{
					break;
				}
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemZuanHuangLevel.SystemXmlItemDict.TryGetValue(num, out systemXmlItem) || null == systemXmlItem)
				{
					break;
				}
				int intValue = systemXmlItem.GetIntValue("MinYuanBao", -1);
				if ((long)intValue > Global.GetUserInputAllYuanBao(client))
				{
					break;
				}
				GameManager.ClientMgr.ModifyZuanHuangLevelValue(client, 1, true, true);
			}
			int zuanHuangLevelValue3 = GameManager.ClientMgr.GetZuanHuangLevelValue(client);
			Global.BroadcastZuanHuangLevelOk(client, zuanHuangLevelValue, zuanHuangLevelValue3);
			Global.ActiveZuanHuangBuffer(client, notifyPropsChanged);
		}

		public static bool ActiveZuanHuangBuffer(GameClient client, bool notifyPropsChanged)
		{
			int num = GameManager.ClientMgr.GetZuanHuangLevelValue(client) - 1;
			int num2 = -1;
			BufferData bufferDataByID = Global.GetBufferDataByID(client, 49);
			if (bufferDataByID != null && !Global.IsBufferDataOver(bufferDataByID, 0L))
			{
				num2 = (int)bufferDataByID.BufferVal;
			}
			bool result;
			if (num2 == num)
			{
				result = false;
			}
			else
			{
				Global.UpdateBufferData(client, BufferItemTypes.ZuanHuang, new double[]
				{
					(double)num
				}, 1, notifyPropsChanged);
				if (notifyPropsChanged)
				{
					GameManager.ClientMgr.NotifyUpdateEquipProps(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client);
					GameManager.ClientMgr.NotifyOthersLifeChanged(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, true, false, 7);
				}
				result = true;
			}
			return result;
		}

