			int result;
			if (zuanHuangLevelValue <= 0)
			{
				result = -100;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemZuanHuangLevel.SystemXmlItemDict.TryGetValue(zuanHuangLevelValue, out systemXmlItem) || null == systemXmlItem)
				{
					result = -1;
				}
				else
				{
					string roleParamByName = Global.GetRoleParamByName(client, "ZHAwardTime");
					if (roleParamByName != null && roleParamByName.Length > 0)
					{
						long num = -1L;
						try
						{
							long.TryParse(roleParamByName, out num);
						}
						finally
						{
						}
						if (num <= 0L)
						{
							return -2;
						}
						DateTime dtmS = new DateTime(num * 10000L);
						if (Global.IsInSameWeek(dtmS, TimeUtil.NowDateTime()))
						{
							return -3;
						}
					}
					if (isJustCheck)
					{
						result = 1680;
					}
					else
					{
						string stringValue = systemXmlItem.GetStringValue("WeekGoods");
						int intValue = systemXmlItem.GetIntValue("WeekBindYuanBao", -1);
						List<GoodsData> list = Global.ParseGoodsDataListFromGoodsStr(stringValue, "钻皇配置文件");
						if (!Global.CanAddGoodsNum(client, list.Count))
						{
							result = -31;
						}
						else
						{
							Global.UpdateRoleParamByName(client, "ZHAwardTime", string.Format("{0}", TimeUtil.NOW()), true);
							if (intValue > 0)
							{
								GameManager.ClientMgr.AddUserGold(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, intValue, "钻皇周奖励");
								GameManager.SystemServerEvents.AddEvent(string.Format("使用钻皇等级领取绑定元宝, roleID={0}({1}), Money={2}, newMoney={3}, zuanhuanglevel={4}", new object[]
								{
									client.ClientData.RoleID,
									client.ClientData.RoleName,
									client.ClientData.UserMoney,
									intValue,
									zuanHuangLevelValue
								}), EventLevels.Record);
								Global.BroadcastVipFetchBindYuanBaoAwardMsg(client, intValue);
							}
							string goodsFromWhere = string.Format("使用钻皇等级{0}获取", zuanHuangLevelValue);
							for (int i = 0; i < list.Count; i++)
							{
								GoodsData goodsData = list[i];
								if (null != goodsData)
								{
									goodsData.Id = Global.AddGoodsDBCommand(Global._TCPManager.TcpOutPacketPool, client, goodsData.GoodsID, goodsData.GCount, goodsData.Quality, goodsData.Props, goodsData.Forge_level, goodsData.Binding, 0, goodsData.Jewellist, true, 1, goodsFromWhere, goodsData.Endtime, goodsData.AddPropIndex, goodsData.BornIndex, goodsData.Lucky, goodsData.Strong, 0, 0, 0, null, null, 0, true);
								}
							}
							result = 1;
						}
					}
				}
			}
			return result;
		}

		public static bool IsInSameWeek(DateTime dtmS, DateTime dtmE)
		{
			double totalDays = (dtmE - dtmS).TotalDays;
			int num = Convert.ToInt32(dtmE.DayOfWeek);
			if (0 == num)
			{
				num = 7;
			}
			return totalDays < 7.0 && totalDays < (double)num;
		}

