		public static bool isDoubleXinFu(int activityID)
		{
			bool result;
			try
			{
				string[] array = GameManager.systemParamsList.GetParamValueByName("DoubleXinFu").Split(new char[]
				{
					'|'
				});
				DateTime t = DateTime.Parse(array[0]);
				DateTime t2 = DateTime.Parse(array[1]);
				DateTime kaiFuTime = Global.GetKaiFuTime();
				if (kaiFuTime < t || kaiFuTime > t2)
				{
					result = false;
				}
				else
				{
					string[] array2 = GameManager.systemParamsList.GetParamValueByName("DoubleXinFuID").Split(new char[]
					{
						','
					});
					foreach (string value in array2)
					{
						if (activityID == Convert.ToInt32(value))
						{
							return true;
						}
					}
					result = false;
				}
			}
			catch
			{
				result = false;
			}
			return result;
		}

