		public static int BeginOfWeek(DateTime date)
		{
			int num = (int)date.DayOfWeek;
			if (num == 0)
			{
				num = 7;
			}
			num--;
			int offsetDay = Global.GetOffsetDay(date);
			return offsetDay - num;
		}

