		public static bool QueryQiangGouItemInfo(int roleID, int qiangGouID, int goodsID, int random, int actStartDay, int serverId, out int singleHasPurchase, out int fullHasPurchase)
		{
			singleHasPurchase = 0;
			fullHasPurchase = 0;
			string[] array = Global.ExecuteDBCmd(10109, string.Format("{0}:{1}:{2}:{3}:{4}", new object[]
			{
				roleID,
				goodsID,
				qiangGouID,
				random,
				actStartDay
			}), serverId);
			bool result;
			if (array == null || array.Length < 3)
			{
				result = false;
			}
			else
			{
				singleHasPurchase = Global.SafeConvertToInt32(array[1]);
				fullHasPurchase = Global.SafeConvertToInt32(array[2]);
				result = true;
			}
			return result;
		}

		public static string GetQiangGouXmlString(GameClient client)
		{
			List<QiangGouItemData> qiangGouItemList = Global.GetQiangGouItemList();
			string result;
			if (qiangGouItemList == null || qiangGouItemList.Count <= 0)
			{
				result = "";
			}
			else
			{
				client.ClientData.QiangGouItemList = qiangGouItemList;
				StringBuilder stringBuilder = new StringBuilder();
				stringBuilder.AppendLine("<?xml version=\"1.0\" encoding=\"utf-8\"?>");
				stringBuilder.AppendLine("<Config>");
				stringBuilder.AppendLine("<Mall>");
				if (null != qiangGouItemList)
				{
					SystemXmlItem systemXmlItem = new SystemXmlItem();
					systemXmlItem.XMLNode = new XElement("Item");
					int num = 0;
					int num2 = 0;
					for (int i = 0; i < qiangGouItemList.Count; i++)
					{
						QiangGouItemData qiangGouItemData = qiangGouItemList[i];
						int actStartDay;
						switch (qiangGouItemData.Type)
						{
						case 1:
							actStartDay = Global.GetOffsetDay(Global.GetHefuStartDay());
							break;
						case 2:
							actStartDay = Global.GetOffsetDay(Global.GetJieriStartDay());
							break;
						default:
							actStartDay = 0;
							break;
						}
						if (Global.QueryQiangGouItemInfo(client.ClientData.RoleID, qiangGouItemData.QiangGouID, qiangGouItemData.GoodsID, qiangGouItemData.Random, actStartDay, client.ServerId, out num, out num2))
						{
							systemXmlItem.XMLNode.SetAttributeValue("CurrentRoleID", client.ClientData.RoleID);
							systemXmlItem.XMLNode.SetAttributeValue("SingleHasPurchase", num);
							if (Global.IsGmStopQiangGou())
							{
								systemXmlItem.XMLNode.SetAttributeValue("FullHasPurchase", qiangGouItemData.FullPurchase);
							}
							else
							{
								systemXmlItem.XMLNode.SetAttributeValue("FullHasPurchase", num2);
							}
							systemXmlItem.XMLNode.SetAttributeValue("QiangGouID", qiangGouItemData.QiangGouID);
							systemXmlItem.XMLNode.SetAttributeValue("GoodsID", qiangGouItemData.GoodsID);
							systemXmlItem.XMLNode.SetAttributeValue("OrigPrice", qiangGouItemData.OrigPrice);
							systemXmlItem.XMLNode.SetAttributeValue("Price", qiangGouItemData.Price);
							systemXmlItem.XMLNode.SetAttributeValue("SinglePurchase", qiangGouItemData.SinglePurchase);
							systemXmlItem.XMLNode.SetAttributeValue("FullPurchase", qiangGouItemData.FullPurchase);
							systemXmlItem.XMLNode.SetAttributeValue("DaysTime", qiangGouItemData.DaysTime);
							systemXmlItem.XMLNode.SetAttributeValue("StartTime", qiangGouItemData.StartTime);
							systemXmlItem.XMLNode.SetAttributeValue("Type", qiangGouItemData.Type);
							stringBuilder.AppendLine(systemXmlItem.XMLNode.ToString());
						}
					}
				}
				stringBuilder.AppendLine("</Mall>");
				stringBuilder.AppendLine("</Config>");
				result = stringBuilder.ToString();
			}
			return result;
		}

		public static List<QiangGouItemData> GetQiangGouItemList()
		{
			int daysSpanNum = Global.GetDaysSpanNum(TimeUtil.NowDateTime(), Global.GetKaiFuTime(), true);
			int num = 0;
			Dictionary<int, bool> dictionary = new Dictionary<int, bool>();
			List<QiangGouItemData> list = null;
			Dictionary<int, SystemXmlItem> systemXmlItemDict = GameManager.SystemQiangGou.SystemXmlItemDict;
			for (int i = 0; i < systemXmlItemDict.Count; i++)
			{
				SystemXmlItem value = systemXmlItemDict.ElementAt(i).Value;
				int intValue = value.GetIntValue("Group", -1);
				int intValue2 = value.GetIntValue("DaysTime", -1);
				int intValue3 = value.GetIntValue("Random", -1);
				if (!dictionary.ContainsKey(intValue))
				{
					dictionary.Add(intValue, true);
					if (0 == intValue3)
					{
						int addDays = num;
						num += intValue2;
						if (daysSpanNum < num)
						{
							string startTime = Global.GetAddDaysDataTime(Global.GetKaiFuTime(), addDays, true).ToString("yyyy-MM-dd HH:mm:ss");
							list = Global.CreateQiangGouItems(intValue, intValue3, startTime);
							if (null != list)
							{
								break;
							}
						}
					}
				}
			}
			if (null == list)
			{
				lock (Global.CachingQiangGouItemDataListMutex)
				{
					if (Global.CachingQiangGouItemDataList != null && TimeUtil.NowDateTime().DayOfYear == Global.CachingQiangGouItemDataListDayID)
					{
						list = Global.CachingQiangGouItemDataList;
					}
					else
					{
						string startTime = Global.GetAddDaysDataTime(TimeUtil.NowDateTime(), 0, true).ToString("yyyy-MM-dd HH:mm:ss");
						list = Global.CreateQiangGouItems(100, 1, startTime);
						Global.CachingQiangGouItemDataList = list;
						Global.CachingQiangGouItemDataListDayID = TimeUtil.NowDateTime().DayOfYear;
					}
				}
			}
			List<QiangGouItemData> heFuQiangGouItemList = Global.GetHeFuQiangGouItemList();
			if (null == list)
			{
				list = heFuQiangGouItemList;
			}
			else if (null != heFuQiangGouItemList)
			{
				list.AddRange(heFuQiangGouItemList);
			}
			List<QiangGouItemData> jieRiQiangGouItemList = Global.GetJieRiQiangGouItemList();
			if (null == list)
			{
				list = jieRiQiangGouItemList;
			}
			else if (null != jieRiQiangGouItemList)
			{
				list.AddRange(jieRiQiangGouItemList);
			}
			return list;
		}

