		public static QiangGouItemData GetQiangGouItemData(GameClient client, int qiangGouID, int goodsID)
		{
			List<QiangGouItemData> qiangGouItemList = client.ClientData.QiangGouItemList;
			if (null == qiangGouItemList)
			{
				qiangGouItemList = Global.GetQiangGouItemList();
				if (qiangGouItemList == null || qiangGouItemList.Count <= 0)
				{
					return null;
				}
				client.ClientData.QiangGouItemList = qiangGouItemList;
			}
			QiangGouItemData result = null;
			for (int i = 0; i < qiangGouItemList.Count; i++)
			{
				if (qiangGouItemList[i].QiangGouID == qiangGouID && qiangGouItemList[i].GoodsID == goodsID)
				{
					result = qiangGouItemList[i];
					break;
				}
			}
			return result;
		}

		public static int CheckQiangGou(GameClient client, int singleHasPurchase, int fullHasPurchase, int qiangGouID, int buyNum, int goodsID, out int price)
		{
			price = 100000;
			int result;
			if (buyNum <= 0 || buyNum > 10000)
			{
				result = -20001;
			}
			else
			{
				List<QiangGouItemData> qiangGouItemList = client.ClientData.QiangGouItemList;
				QiangGouItemData qiangGouItemData = null;
				for (int i = 0; i < qiangGouItemList.Count; i++)
				{
					if (qiangGouItemList[i].QiangGouID == qiangGouID && qiangGouItemList[i].GoodsID == goodsID)
					{
						qiangGouItemData = qiangGouItemList[i];
						break;
					}
				}
				if (null == qiangGouItemData)
				{
					result = -20002;
				}
				else
				{
					SystemXmlItem systemXmlItem = null;
					bool flag = GameManager.SystemQiangGou.SystemXmlItemDict.TryGetValue(qiangGouItemData.QiangGouID, out systemXmlItem);
					if (!flag)
					{
						flag = GameManager.SystemHeFuQiangGou.SystemXmlItemDict.TryGetValue(qiangGouItemData.QiangGouID, out systemXmlItem);
					}
					if (!flag)
					{
						flag = GameManager.SystemJieRiQiangGou.SystemXmlItemDict.TryGetValue(qiangGouItemData.QiangGouID, out systemXmlItem);
					}
					if (!flag || systemXmlItem.GetIntValue("GoodsID", -1) != goodsID)
					{
						result = -20002;
					}
					else if (fullHasPurchase >= qiangGouItemData.FullPurchase)
					{
						result = -20003;
					}
					else if (fullHasPurchase + buyNum > qiangGouItemData.FullPurchase)
					{
						result = -20004;
					}
					else if (singleHasPurchase >= qiangGouItemData.SinglePurchase)
					{
						result = -20005;
					}
					else if (singleHasPurchase + buyNum > qiangGouItemData.SinglePurchase)
					{
						result = -20006;
					}
					else
					{
						int daysSpanNum = Global.GetDaysSpanNum(TimeUtil.NowDateTime(), DateTime.Parse(qiangGouItemData.StartTime), true);
						if (daysSpanNum >= qiangGouItemData.DaysTime)
						{
							result = -20007;
						}
						else
						{
							price = qiangGouItemData.Price;
							if (price <= 0)
							{
								result = -20008;
							}
							else
							{
								result = 1;
							}
						}
					}
				}
			}
			return result;
		}

