		public static int IsRoleHasEnoughMoney(GameClient client, int totalNeedMoney, int moneyType)
		{
			int result;
			if (totalNeedMoney <= 0)
			{
				result = -20000;
			}
			else
			{
				int num = 0;
				if (moneyType <= 30)
				{
					if (moneyType <= 8)
					{
						if (moneyType != 1)
						{
							if (moneyType == 8)
							{
								num = client.ClientData.YinLiang;
							}
						}
						else
						{
							num = client.ClientData.Money1;
						}
					}
					else
					{
						switch (moneyType)
						{
						case 13:
							num = GameManager.ClientMgr.GetTianDiJingYuanValue(client);
							break;
						case 14:
							num = GameManager.ClientMgr.GetJunGongValue(client);
							break;
						default:
							if (moneyType != 20)
							{
								if (moneyType == 30)
								{
									num = GameManager.ClientMgr.GetZhuangBeiJiFenValue(client);
								}
							}
							else
							{
								num = GameManager.ClientMgr.GetLieShaValue(client);
							}
							break;
						}
					}
				}
				else if (moneyType <= 90)
				{
					if (moneyType != 40)
					{
						if (moneyType == 90)
						{
							num = GameManager.ClientMgr.GetZhanHunValue(client);
						}
					}
					else
					{
						num = client.ClientData.UserMoney;
					}
				}
				else if (moneyType != 101)
				{
					switch (moneyType)
					{
					case 110:
						num = GameManager.ClientMgr.GetTreasureJiFen(client);
						break;
					case 111:
						num = GameManager.ClientMgr.GetTreasureXueZuan(client);
						break;
					default:
						switch (moneyType)
						{
						case 160:
							num = client.ClientData.TeamRongYao;
							break;
						case 162:
							num = client.ClientData.TeamPoint;
							break;
						case 163:
							num = client.ClientData.LuckStar;
							break;
						}
						break;
					}
				}
				else
				{
					num = GameManager.ClientMgr.GetZaiZaoValue(client);
				}
				if (num < totalNeedMoney)
				{
					result = -moneyType;
				}
				else
				{
					result = 1;
				}
			}
			return result;
		}

		public static int SubRoleMoneyForGoods(GameClient client, int totalNeedMoney, int moneyType, string strFrom)
		{
			int result;
			if (totalNeedMoney <= 0)
			{
				result = -20000;
			}
			else
			{
				bool flag = true;
				if (moneyType <= 20)
				{
					if (moneyType <= 8)
					{
						if (moneyType == 1)
						{
							flag = GameManager.ClientMgr.SubMoney1(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, totalNeedMoney, strFrom);
							goto IL_1E4;
						}
						if (moneyType == 8)
						{
							flag = GameManager.ClientMgr.SubUserYinLiang(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, totalNeedMoney, strFrom, false);
							goto IL_1E4;
						}
					}
					else
					{
						switch (moneyType)
						{
						case 13:
							GameManager.ClientMgr.ModifyTianDiJingYuanValue(client, -totalNeedMoney, strFrom, true, true, false);
							goto IL_1E4;
						case 14:
							GameManager.ClientMgr.ModifyJunGongValue(client, -totalNeedMoney, true, true);
							goto IL_1E4;
						default:
							if (moneyType == 20)
							{
								GameManager.ClientMgr.ModifyLieShaValue(client, -totalNeedMoney, true, true);
								goto IL_1E4;
							}
							break;
						}
					}
				}
				else if (moneyType <= 40)
				{
					if (moneyType == 30)
					{
						GameManager.ClientMgr.ModifyZhuangBeiJiFenValue(client, -totalNeedMoney, true, true);
						goto IL_1E4;
					}
					if (moneyType == 40)
					{
						GameManager.ClientMgr.SubUserMoney(client, -totalNeedMoney, strFrom, true, true, true, true, DaiBiSySType.None);
						goto IL_1E4;
					}
				}
				else
				{
					if (moneyType == 90)
					{
						GameManager.ClientMgr.ModifyZhanHunValue(client, -totalNeedMoney, true, true);
						goto IL_1E4;
					}
					switch (moneyType)
					{
					case 110:
						GameManager.ClientMgr.ModifyTreasureJiFenValue(client, -totalNeedMoney, strFrom, true);
						goto IL_1E4;
					case 111:
