		public static void GiveGuMuTimeLimitAward(GameClient client)
		{
			int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
			int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(client, "GuMuAwardDayID");
			if (dayOfYear != roleParamsInt32FromDB)
			{
				int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("GuMuTimeLimitAward", ',');
				if (null != paramValueIntArrayByName)
				{
					if (3 == paramValueIntArrayByName.Length)
					{
						int num = paramValueIntArrayByName[1];
						if (Global.IsVip(client))
						{
							num = paramValueIntArrayByName[2];
						}
						double num2 = 0.0;
						JieRiMultAwardActivity jieRiMultAwardActivity = HuodongCachingMgr.GetJieRiMultAwardActivity();
						if (null != jieRiMultAwardActivity)
						{
							JieRiMultConfig config = jieRiMultAwardActivity.GetConfig(4);
							if (null != config)
							{
								num2 += config.GetMult();
							}
						}
						num2 = Math.Max(1.0, num2);
						Global.AddGuMuMapTime(client, (int)((double)(num * 60) * num2), 0);
						Global.SaveRoleParamsInt32ValueToDB(client, "GuMuAwardDayID", dayOfYear, true);
						SpecPriorityActivity specPriorityActivity = HuodongCachingMgr.GetSpecPriorityActivity();
						if (null != specPriorityActivity)
						{
							specPriorityActivity.AutoGiveSpecialAward(client, false);
						}
					}
				}
			}
		}

