		public static int EnterBossFuBen(GameClient client)
		{
			int num = Global.FindBossFuBenIDByRoleLevel(client.ClientData.Level);
			int result;
			if (num <= 0)
			{
				result = -1;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.systemFuBenMgr.SystemXmlItemDict.TryGetValue(num, out systemXmlItem))
				{
					result = -2;
				}
				else
				{
					int intValue = systemXmlItem.GetIntValue("MinLevel", -1);
					int num2 = systemXmlItem.GetIntValue("MaxLevel", -1);
					if (num2 <= 0)
					{
						num2 = 1000;
					}
					int intValue2 = systemXmlItem.GetIntValue("CopyType", -1);
					int intValue3 = systemXmlItem.GetIntValue("EnterNumber", -1);
					int intValue4 = systemXmlItem.GetIntValue("FinishNumber", -1);
					int intValue5 = systemXmlItem.GetIntValue("MapCode", -1);
					if (client.ClientData.Level < intValue || client.ClientData.Level > num2)
					{
						result = -3;
					}
					else
					{
						FuBenData fuBenData = Global.GetFuBenData(client, num);
						int num3 = 0;
						int fuBenEnterNum = Global.GetFuBenEnterNum(fuBenData, out num3);
						int bossFuBenCanFreeEnterNum = Global.GetBossFuBenCanFreeEnterNum(client);
						int bossFuBenCanExtEnterNum = Global.GetBossFuBenCanExtEnterNum(client);
						if (fuBenEnterNum >= bossFuBenCanFreeEnterNum)
						{
							if (bossFuBenCanExtEnterNum <= 0)
							{
								return -4;
							}
						}
						if (fuBenEnterNum >= bossFuBenCanFreeEnterNum)
						{
							Global.UpdateBossFuBenExtraEnterNum(client, -1);
						}
						string[] array = Global.ExecuteDBCmd(10049, string.Format("{0}", client.ClientData.RoleID), client.ServerId);
						if (array == null || array.Length < 2)
						{
							result = -5;
						}
						else
						{
							int fuBenSeqID = Global.SafeConvertToInt32(array[1]);
							if (0 == intValue2)
							{
								Global.UpdateFuBenData(client, num, 1, 0);
								GameMap gameMap = null;
								if (!GameManager.MapMgr.DictMaps.TryGetValue(intValue5, out gameMap))
								{
									result = -6;
								}
								else
								{
									client.ClientData.FuBenSeqID = fuBenSeqID;
									FuBenManager.AddFuBenSeqID(client.ClientData.RoleID, client.ClientData.FuBenSeqID, 0, num);
									GameManager.ClientMgr.NotifyChangeMap(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, intValue5, -1, -1, -1, 0);
									result = 1;
								}
							}
							else
							{
								result = -7;
							}
						}
					}
				}
			}
			return result;
		}

