		private static bool LearnCareerSkill(GameClient client, int skillID, int skillLevel = 1)
		{
			skillLevel = Global.GMax(1, skillLevel);
			skillLevel = Global.GMin(3, skillLevel);
			if (null == Global.GetSkillDataByID(client, skillID))
