		public static JieriXmlData LoadJieriXmlData()
		{
			JieriXmlData result;
			if (null != Global.CachingJieriXmlData)
			{
				result = Global.CachingJieriXmlData;
			}
			else
			{
				JieriXmlData jieriXmlData = new JieriXmlData();
				jieriXmlData.Version = Global.CachingJieriXmlVersion++;
				jieriXmlData.XmlList = new List<string>();
				string text = Global.GameResPath("Config/JieRiGifts/MuJieRiType.xml");
				string item = File.ReadAllText(text);
				jieriXmlData.XmlList.Add(item);
				JieriActivityConfig jieriActivityConfig = HuodongCachingMgr.GetJieriActivityConfig();
				if (null == jieriActivityConfig)
				{
					result = null;
				}
				else
				{
					foreach (int num in jieriActivityConfig.openList)
					{
						if (num == 67)
						{
							JieRiCZQGActivity jieRiCZQGActivity = HuodongCachingMgr.GetJieRiCZQGActivity();
							if (jieRiCZQGActivity == null || UserMoneyMgr.getInstance().PlatformOpenStateVavle == 0)
							{
								jieriXmlData.XmlList.Add("");
								continue;
							}
						}
						else if (num == 71)
						{
							JieriSuperInputActivity jieRiSuperInputActivity = HuodongCachingMgr.GetJieRiSuperInputActivity();
							if (jieRiSuperInputActivity == null || jieRiSuperInputActivity.PlatformOpenStateVavle == 0)
							{
								jieriXmlData.XmlList.Add("");
								continue;
							}
						}
						text = Global.GameResPath("Config/JieRiGifts/" + jieriActivityConfig.GetFileName(num));
						text = WorldLevelManager.getInstance().GetJieRiConfigFileName(text);
						jieriXmlData.XmlList.Add(File.ReadAllText(text));
					}
					Global.CachingJieriXmlData = jieriXmlData;
					result = jieriXmlData;
				}
			}
			return result;
		}

