		public static string GetGiftExchangeFileName(out string sectionKey)
		{
			sectionKey = "dl_app";
			string text = GameManager.GameConfigMgr.GetGameConfigItemStr("platformtype", "app");
			text = text.ToLower();
			if (text == "app")
			{
				sectionKey = "dl_app";
			}
			else if (text == "yueyu")
			{
				sectionKey = "dl_yueyu";
			}
			else if (text == "andrid" || text == "android" || text == "yyb")
			{
				sectionKey = "dl_android";
			}
			return "Config/Gifts/MU_Activities.xml";
		}

		public static ActivitiesData LoadActivitiesFileData()
		{
			string sectionKey = string.Empty;
			string giftExchangeFileName = Global.GetGiftExchangeFileName(out sectionKey);
			XElement xelement = new XElement("config");
			XDocument xdocument = new XDocument(new XDeclaration("1.0", "UTF-8", null), new object[]
			{
				xelement
			});
			XElement xelement2 = XElement.Load(Global.IsolateResPath(giftExchangeFileName));
			IEnumerable<XElement> content = xelement2.Elements().First((XElement _xml) => _xml.Attribute("TypeID").Value.ToString().ToLower() == sectionKey).Elements();
			xelement.Add(content);
			return new ActivitiesData
			{
				ActivitiesXmlString = xdocument.Declaration.ToString() + xdocument.ToString()
			};
		}

		public static int GetTotalBindTongQianAndTongQianVal(GameClient client)
		{
			return Math.Max(0, client.ClientData.Money1 + client.ClientData.YinLiang);
		}

		public static bool SubBindTongQianAndTongQian(GameClient client, int money, string strFrom)
		{
			bool result;
			if (client.ClientData.Money1 + client.ClientData.YinLiang < money)
			{
				result = false;
			}
			else
			{
				int num = Math.Min(client.ClientData.Money1, money);
				if (num > 0)
				{
					if (!GameManager.ClientMgr.SubMoney1(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, num, strFrom))
					{
						return false;
					}
				}
				if (num >= money)
				{
					result = true;
				}
				else
				{
					num = Math.Max(0, money - num);
					if (num > 0)
					{
						if (client.ClientData.YinLiang < num)
						{
							return false;
						}
						if (!GameManager.ClientMgr.SubUserYinLiang(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, num, strFrom, false))
						{
							return false;
						}
					}
					result = true;
				}
			}
			return result;
		}

		public static int CalcFixAllEquipsStrongMoney(GameClient client)
		{
			int result;
			if (null == client.ClientData.GoodsDataList)
			{
				result = 0;
			}
			else if (client.ClientData.GoodsDataList.Count <= 0)
			{
				result = 0;
			}
			else
			{
				List<GoodsData> list = null;
				lock (client.ClientData.GoodsDataList)
				{
					list = client.ClientData.GoodsDataList.GetRange(0, client.ClientData.GoodsDataList.Count);
				}
				int num = 0;
				for (int i = 0; i < list.Count; i++)
				{
					GoodsData goodsData = list[i];
					if (goodsData.Using > 0)
					{
						int goodsCatetoriy = Global.GetGoodsCatetoriy(goodsData.GoodsID);
						if (goodsCatetoriy >= 0 && goodsCatetoriy <= 49)
						{
							SystemXmlItem systemXmlItem = null;
							if (GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem) && null != systemXmlItem)
							{
								int intValue = systemXmlItem.GetIntValue("PriceTwo", -1);
								int[] intArrayValue = systemXmlItem.GetIntArrayValue("EquipProps", ',');
								if (intArrayValue != null && intArrayValue.Length >= 2 && intValue > 0)
								{
									double num2 = (double)intArrayValue[0];
									if (num2 > 0.0 && (double)goodsData.Strong > 0.0)
									{
										int num3 = (int)((double)intValue / 3.0 * (double)goodsData.Strong / num2);
										num3 = Global.RecalcNeedYinLiang(num3);
										num += num3;
									}
								}
							}
						}
					}
				}
				result = num;
			}
			return result;
		}

		public static int OneKeyFixAllEquips(GameClient client)
		{
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			int num4 = Global.CalcFixAllEquipsStrongMoney(client);
			if (num4 <= 0)
			{
				num3 = -50;
			}
			else if (!Global.SubBindTongQianAndTongQian(client, num4, "一键修理普通装备"))
			{
				GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(365, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 27);
				num3 = -51;
			}
			else if (null == client.ClientData.GoodsDataList)
			{
				num3 = -50;
			}
			else if (client.ClientData.GoodsDataList.Count <= 0)
			{
				num3 = -50;
			}
			else
			{
				List<GoodsData> list = null;
				lock (client.ClientData.GoodsDataList)
				{
					list = client.ClientData.GoodsDataList.GetRange(0, client.ClientData.GoodsDataList.Count);
				}
				int num5 = 0;
				for (int i = 0; i < list.Count; i++)
				{
					GoodsData goodsData = list[i];
					if (goodsData.Using > 0)
					{
						int goodsCatetoriy = Global.GetGoodsCatetoriy(goodsData.GoodsID);
						if (goodsCatetoriy >= 0 && goodsCatetoriy <= 49)
						{
							if (goodsData.Strong > 0)
							{
								GameManager.ClientMgr.SubEquipStrong(client, goodsData, goodsData.Strong);
								num5++;
							}
						}
					}
				}
				num += num4;
				num2 += num5;
			}
			int num6 = 0;
			int num7 = RebornEquip.CalcFixAllEquipsStrongMoney(client);
			if (num7 <= 0)
			{
				num6 = -50;
			}
			else if (!Global.SubBindTongQianAndTongQian(client, num7, "一键修理重生装备"))
			{
				GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(365, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 27);
				num6 = -51;
			}
			else if (null == client.ClientData.RebornGoodsDataList)
			{
				num6 = -50;
			}
			else if (client.ClientData.RebornGoodsDataList.Count <= 0)
			{
				num6 = -50;
			}
			else
			{
				List<GoodsData> list2 = null;
				lock (client.ClientData.RebornGoodsDataList)
				{
					list2 = client.ClientData.RebornGoodsDataList.GetRange(0, client.ClientData.RebornGoodsDataList.Count);
				}
				int num8 = 0;
				for (int i = 0; i < list2.Count; i++)
				{
					GoodsData goodsData = list2[i];
					if (goodsData.Using > 0)
					{
						int goodsCatetoriy = Global.GetGoodsCatetoriy(goodsData.GoodsID);
						if (goodsCatetoriy >= 30 && goodsCatetoriy <= 38)
						{
							if (goodsData.Strong > 0)
							{
								GameManager.ClientMgr.SubEquipStrong(client, goodsData, goodsData.Strong);
								num8++;
							}
						}
					}
				}
				num += num7;
				num2 += num8;
			}
			bool flag3 = false;
			bool flag4 = false;
			if (num6 < 0)
			{
				flag4 = true;
			}
			if (num3 < 0)
			{
				flag3 = true;
			}
			if (flag4 && flag3)
			{
				if (flag3)
				{
					return num3;
				}
				if (flag4)
				{
					return num6;
				}
			}
			Global.RefreshEquipPropAndNotify(client);
			GameManager.ClientMgr.NotifyImportantMsg(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, StringUtil.substitute(GLang.GetLang(366, new object[0]), new object[]
			{
				num2,
				num
			}), GameInfoTypeIndexes.Hot, ShowGameInfoTypes.ErrAndBox, 0);
			return 1;
		}

		public static SystemXmlItem GetQualityUpXmlNode(int categoriy, int suitID, int qualityID)
		{
			string uri = string.Format("Config/QualityUp.xml", new object[0]);
			XElement xelement = GeneralCachingXmlMgr.GetXElement(Global.GameResPath(uri));
			SystemXmlItem result;
			if (null == xelement)
			{
				result = null;
			}
			else
			{
				XElement xelement2 = Global.GetXElement(xelement, "Equip", "Categoriy", categoriy.ToString());
				if (null == xelement2)
				{
					result = null;
				}
				else
				{
					IEnumerable<XElement> enumerable = xelement2.Elements("Item");
					foreach (XElement xelement3 in enumerable)
					{
						if (Convert.ToInt32((string)xelement3.Attribute("ShouShiSuitID")) == suitID && Convert.ToInt32((string)xelement3.Attribute("QualityID")) == qualityID)
						{
							return new SystemXmlItem
							{
								XMLNode = xelement3
							};
						}
					}
					result = null;
				}
			}
			return result;
		}

		public static SystemXmlItem GetGoodsXmlNodeByQualityUp(int categoriy, int suitID, int qualityID, int occ)
		{
			foreach (SystemXmlItem systemXmlItem in GameManager.SystemGoods.SystemXmlItemDict.Values)
			{
