		public static int GetRoleTotalPointFromLevelUp(GameClient client)
		{
			int num = 0;
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			for (int i = 0; i <= changeLifeCount; i++)
			{
				ChangeLifeAddPointInfo changeLifeAddPointInfo = null;
				if (Data.ChangeLifeAddPointInfoList.TryGetValue(i, out changeLifeAddPointInfo) && changeLifeAddPointInfo != null)
				{
					if (i < changeLifeCount)
					{
						num += 99 * changeLifeAddPointInfo.AddPoint;
					}
					else
					{
						num += (client.ClientData.Level - 1) * changeLifeAddPointInfo.AddPoint;
					}
				}
			}
			return num;
		}

