		public static void AutoAddRolePoint(GameClient client)
		{
			int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(client, "TotalPropPoint");
			int roleParamsInt32FromDB2 = Global.GetRoleParamsInt32FromDB(client, "PropStrength");
			int roleParamsInt32FromDB3 = Global.GetRoleParamsInt32FromDB(client, "PropIntelligence");
			int roleParamsInt32FromDB4 = Global.GetRoleParamsInt32FromDB(client, "PropDexterity");
			int roleParamsInt32FromDB5 = Global.GetRoleParamsInt32FromDB(client, "PropConstitution");
			int num = roleParamsInt32FromDB2 + roleParamsInt32FromDB3 + roleParamsInt32FromDB4 + roleParamsInt32FromDB5;
			int num2 = roleParamsInt32FromDB - num;
			int num3 = 0;
			int num4 = 0;
			int num5 = 0;
			int num6 = 0;
			float num7 = 0f;
			float num8 = 0f;
			float num9 = 2f;
			float num10 = 1f;
			switch (Global.CalcOriginalOccupationID(client))
			{
			case 0:
				num7 = 2f;
				break;
			case 1:
				num8 = 2f;
				break;
			case 2:
				num7 = 2f;
				break;
			}
			int num11;
			for (;;)
			{
				num11 = num2;
				if (num7 > 0f)
				{
					num11 += roleParamsInt32FromDB2;
				}
				if (num8 > 0f)
				{
					num11 += roleParamsInt32FromDB3;
				}
				if (num9 > 0f)
				{
					num11 += roleParamsInt32FromDB4;
				}
				if (num10 > 0f)
				{
					num11 += roleParamsInt32FromDB5;
				}
				if (num10 > 0f && (float)num11 * num10 / (num10 + num7 + num8 + num9) <= (float)roleParamsInt32FromDB5)
				{
					num10 = 0f;
				}
				else if (num7 > 0f && (float)num11 * num7 / (num10 + num7 + num8 + num9) <= (float)roleParamsInt32FromDB2)
				{
					num7 = 0f;
				}
				else if (num8 > 0f && (float)num11 * num8 / (num10 + num7 + num8 + num9) <= (float)roleParamsInt32FromDB3)
				{
					num8 = 0f;
				}
				else
				{
					if (num9 <= 0f || (float)num11 * num9 / (num10 + num7 + num8 + num9) > (float)roleParamsInt32FromDB4)
					{
						break;
					}
					num9 = 0f;
				}
			}
			if (num7 > 0f)
			{
				num3 = (int)((float)num11 * num7 / (num10 + num7 + num8 + num9) - (float)roleParamsInt32FromDB2);
			}
			if (num8 > 0f)
			{
				num4 = (int)((float)num11 * num8 / (num10 + num7 + num8 + num9) - (float)roleParamsInt32FromDB3);
			}
			if (num9 > 0f)
			{
				num5 = (int)((float)num11 * num9 / (num10 + num7 + num8 + num9) - (float)roleParamsInt32FromDB4);
			}
			if (num10 > 0f)
			{
				num6 = (int)((float)num11 * num10 / (num10 + num7 + num8 + num9) - (float)roleParamsInt32FromDB5);
			}
			int num12 = num2 - (num3 + num4 + num5 + num6);
			if (num10 > 0f)
			{
				num6 += num12;
			}
			else if (num7 > 0f)
			{
				num3 += num12;
			}
			else if (num8 > 0f)
			{
				num4 += num12;
			}
			else if (num9 > 0f)
			{
				num5 += num12;
			}
		}

