		public static int GetSprOffLineMin(int nRid)
		{
			GameClient gameClient = GameManager.ClientMgr.FindClient(nRid);
			int result;
			if (null != gameClient)
			{
				result = 0;
			}
			else
			{
				RoleBaseInfo roleBaseInfo = GameManager.ClientMgr.QueryRoleBaseInfoFromDB(nRid, -1);
				if (null == roleBaseInfo)
				{
					result = 1800;
				}
				else if (roleBaseInfo.LoginTime >= roleBaseInfo.LogoutTime)
				{
					result = 0;
				}
				else
				{
					result = (int)Math.Floor((double)(Global.GMax(0L, TimeUtil.NOW() - roleBaseInfo.LogoutTime) / 60000L) * 1.0);
				}
			}
			return result;
		}

