		public static int GetBloodCastleCopySceneIDForRole(GameClient client)
		{
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			int level = client.ClientData.Level;
			foreach (BloodCastleDataInfo bloodCastleDataInfo in Data.BloodCastleDataInfoList.Values)
			{
				int minChangeLifeNum = bloodCastleDataInfo.MinChangeLifeNum;
				int maxChangeLifeNum = bloodCastleDataInfo.MaxChangeLifeNum;
				int minLevel = bloodCastleDataInfo.MinLevel;
				int maxLevel = bloodCastleDataInfo.MaxLevel;
				if (changeLifeCount > minChangeLifeNum && changeLifeCount < maxChangeLifeNum)
				{
					return bloodCastleDataInfo.MapCode;
				}
				if (changeLifeCount == minChangeLifeNum || changeLifeCount == maxChangeLifeNum)
				{
					if (level >= minLevel && level <= maxLevel)
					{
						return bloodCastleDataInfo.MapCode;
					}
				}
			}
			return -1;
		}

		public static bool CanEnterBloodCastleOnTime(List<string> BeginTime, int nPrepareTime)
		{
			DateTime t = TimeUtil.NowDateTime();
			string b = TimeUtil.NowDateTime().ToString("HH:mm");
			bool result;
			if (null == BeginTime)
			{
				result = false;
			}
			else
			{
				for (int i = 0; i < BeginTime.Count; i++)
				{
					DateTime t2 = DateTime.Parse(BeginTime[i]);
					DateTime t3 = t2.AddMinutes((double)(nPrepareTime / 60));
					if (BeginTime[i] == b || (t > t2 && t <= t3))
					{
						return true;
					}
				}
				result = false;
			}
			return result;
		}

		public static bool CanEnterBloodCastleCopySceneOnTime(List<string> BeginTime, int nPrepareTime, out int nTimer, out string strTimer)
		{
			strTimer = null;
			nTimer = 0;
			DateTime dateTime = TimeUtil.NowDateTime();
			string b = TimeUtil.NowDateTime().ToString("HH:mm");
			bool result;
			if (null == BeginTime)
			{
				result = false;
			}
			else
			{
				for (int i = 0; i < BeginTime.Count; i++)
				{
					DateTime t = DateTime.Parse(BeginTime[i]);
					DateTime t2 = t.AddMinutes((double)(nPrepareTime / 60));
					if (BeginTime[i] == b || (dateTime > t && dateTime <= t2))
					{
						TimeSpan timeSpan = dateTime - DateTime.Parse(BeginTime[i]);
						strTimer = BeginTime[i];
						nTimer = timeSpan.Minutes * 60 + timeSpan.Seconds;
						return true;
					}
				}
				result = false;
			}
			return result;
		}

