		public static void QueryDayActivityTotalPointInfoToDB(SpecialActivityTypes nType)
		{
			string[] array = null;
			string strcmd = string.Format("{0}", (int)nType);
			TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10134, strcmd, out array, 0);
			if (tcpprocessCmdResults != TCPProcessCmdResults.RESULT_FAILED)
			{
				if (array.Length == 2)
				{
					int num = Global.SafeConvertToInt32(array[0]);
					string sName = array[1];
					if (nType == SpecialActivityTypes.BloodCastle)
					{
						GameManager.BloodCastleCopySceneMgr.SetBloodCastleCopySceneTotalPoint(sName, num);
					}
					if (nType == SpecialActivityTypes.DemoSque)
					{
						GameManager.DaimonSquareCopySceneMgr.SetDaimonSquareCopySceneTotalPoint(sName, num);
					}
					else if (nType == SpecialActivityTypes.CampBattle)
					{
						BattleManager.SetTotalPointInfo(sName, num);
					}
					else if (nType == SpecialActivityTypes.TheKingOfPK)
					{
						GameManager.ArenaBattleMgr.SetTotalPointInfo(sName, num);
					}
					else if (nType == SpecialActivityTypes.AngelTemple)
					{
						GameManager.AngelTempleMgr.SetTotalPointInfo(sName, (long)num);
					}
				}
			}
		}

