		public static int GetDailyCircleTaskAddAward(GameClient client)
		{
			int result = -1;
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			int level = client.ClientData.Level;
			for (int i = 0; i < Data.DailyCircleTaskAward.Count; i++)
			{
				if (changeLifeCount >= Data.DailyCircleTaskAward[i].MinChangeLifeLev && changeLifeCount <= Data.DailyCircleTaskAward[i].MaxChangeLifeLev)
				{
					if (changeLifeCount != Data.DailyCircleTaskAward[i].MinChangeLifeLev || level >= Data.DailyCircleTaskAward[i].MinLev)
					{
						if (changeLifeCount != Data.DailyCircleTaskAward[i].MaxChangeLifeLev || level <= Data.DailyCircleTaskAward[i].MaxLev)
						{
							return i;
						}
					}
				}
			}
			return result;
		}

		public static int GetDailyCircleTaskIDBaseChangeLifeLev(GameClient client)
		{
			int num = -1;
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			int level = client.ClientData.Level;
			string paramValueByName = GameManager.systemParamsList.GetParamValueByName("DailyCircleTaskInfo");
			string[] array = paramValueByName.Split(new char[]
			{
				'|'
			});
			int result;
			if (array.Length < 0)
			{
				result = num;
			}
			else
			{
				for (int i = 0; i < array.Length; i++)
				{
					string[] array2 = array[i].Split(new char[]
					{
						','
					});
					if (array2.Length != 6)
					{
						return num;
					}
					int num2 = -1;
					if (!int.TryParse(array2[0], out num2))
					{
						return num;
					}
					int num3 = -1;
					if (!int.TryParse(array2[1], out num3))
					{
						return num;
					}
					int num4 = -1;
					if (!int.TryParse(array2[2], out num4))
					{
						return num;
					}
					int num5 = -1;
					if (!int.TryParse(array2[3], out num5))
					{
						return num;
					}
					if (changeLifeCount >= num2 && changeLifeCount <= num4)
					{
						if (changeLifeCount != num2 || level >= num3)
						{
							if (changeLifeCount != num4 || level <= num5)
							{
								int minV = -1;
								if (!int.TryParse(array2[4], out minV))
								{
									return num;
								}
								int num6 = -1;
								if (!int.TryParse(array2[5], out num6))
								{
									return num;
								}
								return Global.GetRandomNumber(minV, num6 + 1);
							}
						}
					}
				}
				result = num;
			}
			return result;
		}

		public static TaskData TakeNewTaskForDailyCircleTask(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPOutPacketPool pool, GameClient client, int taskID, int nNPCID, int nID)
		{
			TaskData taskData = new TaskData
			{
				DbID = -1,
				DoingTaskID = taskID
			};
			SystemXmlItem systemXmlItem = null;
			TaskData result;
			if (!GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
			{
				LogManager.WriteLog(2, string.Format("外挂接受新任务, 任务不存在, 一键完成日常跑环任务失败 CMD={0}, Client={1}, RoleID={2}, TaskID={3}", new object[]
				{
					(TCPGameServerCmds)nID,
					Global.GetSocketRemoteEndPoint(socket, false),
					client.ClientData.RoleID,
					taskID
				}), null, true);
				result = taskData;
			}
			else if (!Global.CanTakeNewTask(client, taskID, systemXmlItem))
			{
				LogManager.WriteLog(2, string.Format("外挂接受新任务, 任务不能再接, 一键完成日常跑环任务失败 CMD={0}, Client={1}, RoleID={2}, TaskID={3}", new object[]
				{
					(TCPGameServerCmds)nID,
					Global.GetSocketRemoteEndPoint(socket, false),
					client.ClientData.RoleID,
					taskID
				}), null, true);
				result = taskData;
			}
			else
			{
				int num = 1;
				if (Global.GetFocusTaskCount(client) >= Data.TaskMaxFocusCount)
				{
					num = 0;
				}
				int num2 = 5;
				string strcmd = string.Format("{0}:{1}:{2}:{3}:{4}", new object[]
				{
					client.ClientData.RoleID,
					nNPCID,
					taskID,
					num,
					num2
				});
				string[] array = null;
				if (TCPProcessCmdResults.RESULT_FAILED == Global.RequestToDBServer(tcpClientPool, pool, nID, strcmd, out array, client.ServerId))
				{
					LogManager.WriteLog(2, string.Format("与DBServer通讯失败, CMD={0}", (TCPGameServerCmds)nID), null, true);
					result = taskData;
				}
				else if (Convert.ToInt32(array[3]) < 0)
				{
					LogManager.WriteLog(2, string.Format("与DBServer报错！！！, CMD={0}", (TCPGameServerCmds)nID), null, true);
					result = taskData;
				}
				else
				{
					if (null == client.ClientData.TaskDataList)
					{
						client.ClientData.TaskDataList = new List<TaskData>();
					}
					taskData.DbID = Convert.ToInt32(array[3]);
					taskData.DoingTaskVal1 = 0;
					taskData.DoingTaskVal2 = 0;
					taskData.DoingTaskFocus = num;
					taskData.AddDateTime = Convert.ToInt64(array[2]);
					taskData.DoneCount = 0;
					taskData.StarLevel = num2;
					OldTaskData oldTaskData = Global.FindOldTaskByTaskID(client, taskID);
					if (null != oldTaskData)
					{
						taskData.DoneCount = oldTaskData.DoCount;
					}
					Global.ProcessTaskData(client, taskData);
					lock (client.ClientData.TaskDataList)
					{
						client.ClientData.TaskDataList.Add(taskData);
					}
					TCPOutPacket tcpOutPacket = DataHelper.ObjectToTCPOutPacket<TaskData>(taskData, pool, nID);
					tcpMgr.MySocketListener.SendData(client.ClientSocket, tcpOutPacket, true);
					int intValue = systemXmlItem.GetIntValue("SourceNPC", -1);
					if (intValue >= 0)
					{
						int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue, 0);
						GameManager.ClientMgr.NotifyUpdateNPCTaskSate(tcpMgr.MySocketListener, pool, client, intValue + 2130706432, state);
					}
					ProcessTask.Process(tcpMgr.MySocketListener, pool, client, nNPCID, nNPCID - 2130706432, -1, TaskTypes.GetSomething, null, 0, -1L, null);
					systemXmlItem = null;
					if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
					{
						int intValue2 = systemXmlItem.GetIntValue("DestNPC", -1);
						if (-1 != intValue2 && intValue2 != nNPCID - 2130706432)
						{
							int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue2, 0);
							GameManager.ClientMgr.NotifyUpdateNPCTaskSate(tcpMgr.MySocketListener, pool, client, intValue2 + 2130706432, state);
						}
						string stringValue = systemXmlItem.GetStringValue("PropsName1");
						string stringValue2 = systemXmlItem.GetStringValue("PropsName2");
						int num3 = ("" != stringValue) ? Global.GetGoodsByName(stringValue) : -1;
						int num4 = ("" != stringValue2) ? Global.GetGoodsByName(stringValue2) : -1;
						if (num3 >= 0)
						{
							ProcessTask.Process(tcpMgr.MySocketListener, pool, client, -1, -1, num3, TaskTypes.BuySomething, null, 0, -1L, null);
						}
						if (num4 >= 0)
						{
							ProcessTask.Process(tcpMgr.MySocketListener, pool, client, -1, -1, num4, TaskTypes.BuySomething, null, 0, -1L, null);
						}
					}
					result = taskData;
				}
			}
			return result;
		}

		public static int GetTaofaTaskIDBaseChangeLifeLev(GameClient client)
		{
			int num = -1;
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			int level = client.ClientData.Level;
			string paramValueByName = GameManager.systemParamsList.GetParamValueByName("PriceTaskInfo");
			string[] array = paramValueByName.Split(new char[]
			{
				'|'
			});
			int result;
			if (array.Length < 0)
			{
				result = num;
			}
			else
			{
				for (int i = 0; i < array.Length; i++)
				{
					string[] array2 = array[i].Split(new char[]
					{
						','
					});
					if (array2.Length != 6)
					{
						return num;
					}
					int num2 = -1;
					if (!int.TryParse(array2[0], out num2))
					{
						return num;
					}
					int num3 = -1;
					if (!int.TryParse(array2[1], out num3))
					{
						return num;
					}
					int num4 = -1;
					if (!int.TryParse(array2[2], out num4))
					{
						return num;
					}
					int num5 = -1;
					if (!int.TryParse(array2[3], out num5))
					{
						return num;
					}
					if (changeLifeCount >= num2 && changeLifeCount <= num4)
					{
						if (changeLifeCount != num2 || level >= num3)
						{
							if (changeLifeCount != num4 || level <= num5)
							{
								int minV = -1;
								if (!int.TryParse(array2[4], out minV))
								{
									return num;
								}
								int num6 = -1;
								if (!int.TryParse(array2[5], out num6))
								{
									return num;
								}
								return Global.GetRandomNumber(minV, num6 + 1);
							}
						}
					}
				}
				result = num;
			}
			return result;
		}

