		public static void QueryRoleDayActivityPoint(GameClient client, int nTpye)
		{
			string[] array = null;
			string strcmd = string.Format("{0}:{1}", client.ClientData.RoleID, nTpye);
			TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10135, strcmd, out array, client.ServerId);
			if (tcpprocessCmdResults != TCPProcessCmdResults.RESULT_FAILED)
			{
				if (array.Length == 5)
				{
					if (nTpye == 0)
					{
						client.ClientData.BloodCastleAwardTotalPoint = Global.SafeConvertToInt32(array[0]);
						client.ClientData.DaimonSquarePointTotalPoint = Global.SafeConvertToInt32(array[1]);
						client.ClientData.CampBattleTotalPoint = Global.SafeConvertToInt32(array[2]);
						client.ClientData.KingOfPkTopPoint = Global.SafeConvertToInt32(array[3]);
						client.ClientData.AngelTempleTopPoint = Global.SafeConvertToInt64(array[4]);
					}
					else if (nTpye == 1)
					{
						client.ClientData.BloodCastleAwardTotalPoint = Global.SafeConvertToInt32(array[0]);
					}
					else if (nTpye == 2)
					{
						client.ClientData.DaimonSquarePointTotalPoint = Global.SafeConvertToInt32(array[1]);
					}
					else if (nTpye == 3)
					{
						client.ClientData.CampBattleTotalPoint = Global.SafeConvertToInt32(array[2]);
					}
					else if (nTpye == 4)
					{
						client.ClientData.KingOfPkTopPoint = Global.SafeConvertToInt32(array[3]);
					}
					else if (nTpye == 5)
					{
						client.ClientData.AngelTempleTopPoint = (long)Global.SafeConvertToInt32(array[4]);
					}
				}
			}
		}

