		public static int GetDaimonSquareCopySceneIDForRole(GameClient client)
		{
			int level = client.ClientData.Level;
			int changeLifeCount = client.ClientData.ChangeLifeCount;
			foreach (DaimonSquareDataInfo daimonSquareDataInfo in Data.DaimonSquareDataInfoList.Values)
			{
				int minChangeLifeNum = daimonSquareDataInfo.MinChangeLifeNum;
				int maxChangeLifeNum = daimonSquareDataInfo.MaxChangeLifeNum;
				int minLevel = daimonSquareDataInfo.MinLevel;
				int maxLevel = daimonSquareDataInfo.MaxLevel;
				if (changeLifeCount > minChangeLifeNum && changeLifeCount < maxChangeLifeNum)
				{
					return daimonSquareDataInfo.MapCode;
				}
				if (changeLifeCount == minChangeLifeNum || changeLifeCount == maxChangeLifeNum)
				{
					if (level >= minLevel && level <= maxLevel)
					{
						return daimonSquareDataInfo.MapCode;
					}
				}
			}
			return -1;
		}

		public static bool CanEnterDaimonSquareOnTime(List<string> BeginTime, int nPrepareTime)
		{
			DateTime t = TimeUtil.NowDateTime();
			string b = TimeUtil.NowDateTime().ToString("HH:mm");
			bool result;
			if (null == BeginTime)
			{
				result = false;
			}
			else
			{
				for (int i = 0; i < BeginTime.Count; i++)
				{
					DateTime t2 = DateTime.Parse(BeginTime[i]);
					DateTime t3 = t2.AddMinutes((double)(nPrepareTime / 60));
					if (BeginTime[i] == b || (t > t2 && t <= t3))
					{
						return true;
					}
				}
				result = false;
			}
			return result;
		}

		public static bool CanEnterDaimonSquareCopySceneOnTime(List<string> BeginTime, int nPrepareTime, out int nSecond, out string strTimer)
		{
			nSecond = 0;
			strTimer = null;
			DateTime dateTime = TimeUtil.NowDateTime();
			string b = TimeUtil.NowDateTime().ToString("HH:mm");
			bool result;
			if (null == BeginTime)
			{
				result = false;
			}
			else
			{
				for (int i = 0; i < BeginTime.Count; i++)
				{
					DateTime t = DateTime.Parse(BeginTime[i]);
					DateTime t2 = t.AddMinutes((double)(nPrepareTime / 60));
					if (BeginTime[i] == b || (dateTime > t && dateTime <= t2))
					{
						TimeSpan timeSpan = dateTime - DateTime.Parse(BeginTime[i]);
						nSecond = timeSpan.Minutes * 60 + timeSpan.Seconds;
						strTimer = BeginTime[i];
						return true;
					}
				}
				result = false;
			}
			return result;
		}

