				{
					int[] mediateRewardTuple = enumerable.First<MeditateData>().MediateRewardTuple;
					if (mediateRewardTuple != null && mediateRewardTuple.Length > client.ClientData.Occupation)
					{
						return mediateRewardTuple[client.ClientData.Occupation];
					}
				}
				result = 0;
			}
			return result;
		}

