			if (bindZuanShi > 0)
			{
				GameManager.ClientMgr.AddUserGold(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, bindZuanShi, "领取VIP日奖励");
				GameManager.SystemServerEvents.AddEvent(string.Format("角色根据{0}特权领取绑定钻石, roleID={1}({2}), Money={3}, newMoney={4}, priority={5}", new object[]
				{
					Global.GetVipTypeNameString(client),
					client.ClientData.RoleID,
					client.ClientData.RoleName,
					client.ClientData.UserMoney,
					bindZuanShi,
					nIndex
				}), EventLevels.Record);
				Global.BroadcastVipFetchBindYuanBaoAwardMsg(client, bindZuanShi);
			}
			if (jinBi > 0)
			{
				GameManager.ClientMgr.AddUserYinLiang(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, jinBi, "领取VIP日奖励", false);
				GameManager.SystemServerEvents.AddEvent(string.Format("角色根据{0}特权领取金币, roleID={1}({2}), Money={3}, newMoney={4}, priority={5}", new object[]
				{
					Global.GetVipTypeNameString(client),
					client.ClientData.RoleID,
					client.ClientData.RoleName,
					client.ClientData.YinLiang,
					jinBi,
					nIndex
				}), EventLevels.Record);
			}
			if (bindJinBi > 0)
			{
				GameManager.ClientMgr.AddMoney1(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, bindJinBi, "领取VIP日奖励", false);
				GameManager.SystemServerEvents.AddEvent(string.Format("角色根据{0}特权领取绑定金币, roleID={1}({2}), Money={3}, newMoney={4}, priority={5}", new object[]
				{
					Global.GetVipTypeNameString(client),
					client.ClientData.RoleID,
					client.ClientData.RoleName,
					client.ClientData.Money1,
					bindJinBi,
					nIndex
				}), EventLevels.Record);
			}
			string goodsFromWhere = string.Format("VIP使用特权{0}获取", nIndex);
			if (awardGoods != null)
			{
				for (int i = 0; i < awardGoods.Count; i++)
				{
					GoodsData goodsData = awardGoods[i];
					if (null != goodsData)
					{
						goodsData.Id = Global.AddGoodsDBCommand(Global._TCPManager.TcpOutPacketPool, client, goodsData.GoodsID, goodsData.GCount, goodsData.Quality, goodsData.Props, goodsData.Forge_level, goodsData.Binding, 0, goodsData.Jewellist, true, 1, goodsFromWhere, goodsData.Endtime, goodsData.AddPropIndex, goodsData.BornIndex, goodsData.Lucky, goodsData.Strong, 0, 0, 0, null, null, 0, true);
					}
				}
			}
			if (bufferGoods != null && bufferGoods.Length > 0)
			{
				for (int i = 0; i < bufferGoods.Length; i++)
				{
					Global.AddBufferByGoodsID(client, bufferGoods[i]);
				}
			}
			if (1 == xiHongMing)
			{
				GameManager.ClientMgr.SetRolePKValuePoint(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, 0, 0, true);
			}
