		}

		public static bool ProcessVipLevelUp(GameClient client)
		{
			long num = Global.GetUserInputAllYuanBao(client);
			if (num > 0L && Data.DiamondToVipExpValue > 0)
			{
				num /= (long)Data.DiamondToVipExpValue;
			}
			num += (long)Global.GetRoleParamsInt32FromDB(client, "VIPExp");
			int num2 = Global.CalcVipLevelByZuanShi(num);
			int vipLevel = client.ClientData.VipLevel;
			bool result;
			if (vipLevel == num2)
			{
				result = true;
			}
			else
			{
				client.ClientData.VipLevel = num2;
				if (client._IconStateMgr.CheckVIPLevelAwardState(client) || client._IconStateMgr.CheckSpecialActivity(client) || client._IconStateMgr.CheckEverydayActivity(client))
				{
					client._IconStateMgr.SendIconStateToClient(client);
				}
				if (client._IconStateMgr.CheckJieRiFanLi(client, ActivityTypes.JieriVIPFanli))
				{
					client._IconStateMgr.AddFlushIconState(14000, client._IconStateMgr.IsAnyJieRiTipActived());
					client._IconStateMgr.SendIconStateToClient(client);
				}
				Global.ProcessVipSpecialBuffer(client);
				string strCmd = string.Format("{0}:{1}", client.ClientData.RoleID, client.ClientData.VipLevel);
				GameManager.ClientMgr.SendToClient(client, strCmd, 595);
				SpreadManager.getInstance().SpreadIsVip(client);
				FundManager.FundVip(client);
				UserReturnManager.getInstance().VipChange(client);
				SingletonTemplate<TradeBlackManager>.Instance().UpdateObjectExtData(client);
				VideoLogic.getInstance().GetOrSendPlayerVideoStatus(client, client.ClientData.RoleCommonUseIntPamams);
				try
				{
					string text = string.Format("vipchange server={0} account={1} player={2} viplevel={3}", new object[]
					{
						GameManager.ServerId,
						client.strUserID,
						client.ClientData.LocalRoleID,
						client.ClientData.VipLevel
					});
					LogManager.WriteLog(5, text, null, true);
				}
				catch
				{
				}
				result = true;
			}
			return result;
		}

		public static int CalcVipLevelByZuanShi(long zuanshi)
		{
			int result = 0;
			for (int i = 1; i <= VIPEumValue.VIPENUMVALUE_MAXLEVEL; i++)
			{
				if (Data.VIPLevAwardAndExpInfoList[i].NeedExp <= 0 || zuanshi < (long)Data.VIPLevAwardAndExpInfoList[i].NeedExp)
				{
					break;
				}
				result = Data.VIPLevAwardAndExpInfoList[i].VipLev;
			}
			return result;
		}

		public static bool GMSetVipLevel(GameClient client, int vipLevel)
		{
			vipLevel = Math.Min(vipLevel, VIPEumValue.VIPENUMVALUE_MAXLEVEL);
			long num = Global.GetUserInputAllYuanBao(client);
			if (num > 0L && Data.DiamondToVipExpValue > 0)
			{
				num /= (long)Data.DiamondToVipExpValue;
			}
			int nValue = (int)(-(int)num);
			if (Data.VIPLevAwardAndExpInfoList.ContainsKey(vipLevel))
			{
				nValue = Data.VIPLevAwardAndExpInfoList[vipLevel].NeedExp - (int)num;
			}
			Global.SaveRoleParamsInt32ValueToDB(client, "VIPExp", nValue, true);
			return Global.ProcessVipLevelUp(client);
		}

		public static bool ProcessVipSpecialBuffer(GameClient client)
		{
			bool result;
			if (client.ClientData.VipLevel <= 0)
			{
				result = false;
			}
			else
			{
				if (client.ClientData.VipLevel > VIPEumValue.VIPENUMVALUE_MAXLEVEL)
				{
					client.ClientData.VipLevel = VIPEumValue.VIPENUMVALUE_MAXLEVEL;
				}
				int vipLevel = client.ClientData.VipLevel;
				VIPLevAwardAndExpInfo viplevAwardAndExpInfo = null;
				if (!Data.VIPLevAwardAndExpInfoList.TryGetValue(vipLevel, out viplevAwardAndExpInfo) || viplevAwardAndExpInfo == null)
				{
					result = false;
				}
				else
				{
					int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("ZhuanhuangBufferGoodsIDs", ',');
					if (paramValueIntArrayByName == null || paramValueIntArrayByName.Count<int>() != VIPEumValue.VIPENUMVALUE_MAXLEVEL + 1 || paramValueIntArrayByName[vipLevel] < 0)
					{
						result = false;
					}
					else
					{
						int num = -1;
						BufferData bufferDataByID = Global.GetBufferDataByID(client, 49);
						if (bufferDataByID != null && !Global.IsBufferDataOver(bufferDataByID, 0L))
						{
							num = (int)bufferDataByID.BufferVal;
						}
						if (num == paramValueIntArrayByName[vipLevel])
						{
							result = false;
						}
						else
						{
							Global.UpdateBufferData(client, BufferItemTypes.ZuanHuang, new double[]
							{
								(double)paramValueIntArrayByName[vipLevel]
							}, 1, true);
							GameManager.ClientMgr.NotifyOthersLifeChanged(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, true, false, 7);
							result = true;
						}
					}
				}
			}
			return result;
		}

		public static void QueryVipAwardFlagToDB(GameClient client)
		{
			TCPOutPacket tcpoutPacket = null;
			string strcmd = string.Format("{0}", client.ClientData.RoleID);
			TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer2(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 10168, strcmd, out tcpoutPacket, client.ServerId);
			if (TCPProcessCmdResults.RESULT_FAILED != tcpprocessCmdResults)
			{
				string @string = new UTF8Encoding().GetString(tcpoutPacket.GetPacketBytes(), 6, tcpoutPacket.PacketDataSize - 6);
				string[] array = @string.Split(new char[]
				{
					':'
				});
				if (array.Length == 1)
				{
					client.ClientData.VipAwardFlag = Convert.ToInt32(array[0]);
				}
			}
			Global.PushBackTcpOutPacket(tcpoutPacket);
		}

