		public static void ProcessRedNamePunishForDebuff(GameClient client)
		{
			if (client.ClientData.PKPoint != client.ClientData.LastPKPoint)
			{
				client.ClientData.LastPKPoint = client.ClientData.PKPoint;
				BufferData bufferDataByID = Global.GetBufferDataByID(client, 92);
				double num = Math.Ceiling((double)client.ClientData.PKPoint / 100.0 - 1.0);
				if (num >= 0.0)
				{
					num = num * (num + 1.0) / 2.0;
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.AddAttackPercent,
						-Data.RedNameDebuffInfo[0] * num
					});
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.AddDefensePercent,
						-Data.RedNameDebuffInfo[1] * num
					});
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.MaxLifePercent,
						-Data.RedNameDebuffInfo[2] * num
					});
				}
				else
				{
					num = 0.0;
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.AddAttackPercent,
						0
					});
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.AddDefensePercent,
						0
					});
					client.ClientData.PropsCacheManager.SetExtPropsSingle(new object[]
					{
						PropsSystemTypes.RedNameDebuff,
						ExtPropIndexes.MaxLifePercent,
						0
					});
				}
				double[] array = new double[]
				{
					Data.RedNameDebuffInfo[3],
					(double)(client.ClientData.PKPoint - 200) / 10.0,
					num
				};
				if (null != bufferDataByID)
				{
					long num2 = (long)bufferDataByID.BufferSecs - (TimeUtil.NOW() - bufferDataByID.StartTime) / 60000L;
					long num3 = (long)array[1];
					if (num2 == num3)
					{
						return;
					}
				}
				Global.UpdateBufferData(client, BufferItemTypes.MU_REDNAME_DEBUFF, array, 1, true);
				GameManager.ClientMgr.NotifyUpdateEquipProps(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client);
				GameManager.ClientMgr.NotifyOthersLifeChanged(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, true, false, 7);
			}
		}

