		public static void EquipExchangeToMoJing(GameClient client, List<GoodsData> GoodsList)
		{
			int num = 0;
			for (int i = GoodsList.Count - 1; i >= 0; i--)
			{
				GoodsData goodsData = GoodsList[i];
				SystemXmlItem systemXmlItem = null;
				if (GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsData.GoodsID, out systemXmlItem) && null != systemXmlItem)
				{
					int goodsCatetoriy = Global.GetGoodsCatetoriy(goodsData.GoodsID);
					bool flag = false;
					if (goodsCatetoriy >= 0 && goodsCatetoriy <= 49)
					{
						flag = true;
					}
					else if (systemXmlItem.GetIntValue("ChangeJinYuan", -1) > 0)
					{
						flag = true;
					}
					if (flag)
					{
						double num2 = 1.0;
						if (goodsData.ExcellenceInfo != 0)
						{
							int equipExcellencePropNum = Global.GetEquipExcellencePropNum(goodsData);
							if (equipExcellencePropNum != 0)
							{
								double[] paramValueDoubleArrayByName = GameManager.systemParamsList.GetParamValueDoubleArrayByName("ZhuoYueHuiShouXiShu", ',');
								if (paramValueDoubleArrayByName != null && paramValueDoubleArrayByName.Length >= equipExcellencePropNum)
								{
									num2 = paramValueDoubleArrayByName[equipExcellencePropNum - 1];
								}
							}
						}
						int num3 = (int)((double)systemXmlItem.GetIntValue("ChangeJinYuan", -1) * num2);
						if (num3 > 0)
						{
							num += num3;
							GoodsList.RemoveAt(i);
						}
					}
				}
			}
			if (num > 0)
			{
				GameManager.ClientMgr.ModifyTianDiJingYuanValue(client, num, "副本扫荡装备回收", true, true, false);
				SevenDayGoalEventObject sevenDayGoalEventObject = SevenDayGoalEvPool.Alloc(client, ESevenDayGoalFuncType.RecoverMoJing);
				sevenDayGoalEventObject.Arg1 = num;
				GlobalEventSource.getInstance().fireEvent(sevenDayGoalEventObject);
			}
		}

		public static int GetBossAnimationCheckCode(int monsterID, int mapCode, int toX, int toY, int effectX, int effectY, long ticks)
		{
			CRC32 crc = new CRC32();
			crc.update(BitConverter.GetBytes(monsterID));
			crc.update(BitConverter.GetBytes(mapCode));
			crc.update(BitConverter.GetBytes(toX));
			crc.update(BitConverter.GetBytes(toY));
			crc.update(BitConverter.GetBytes(effectX));
			crc.update(BitConverter.GetBytes(effectY));
			crc.update(BitConverter.GetBytes(ticks));
			return (int)(crc.getValue() % 255U);
		}

