		public static int GetImpetrateTypeIDByLevel(GameClient Client)
		{
			int result = -1;
			int changeLifeCount = Client.ClientData.ChangeLifeCount;
			int level = Client.ClientData.Level;
			Dictionary<int, SystemXmlItem> systemXmlItemDict = GameManager.systemImpetrateByLevelMgr.SystemXmlItemDict;
			foreach (SystemXmlItem systemXmlItem in systemXmlItemDict.Values)
			{
				if (changeLifeCount >= systemXmlItem.GetIntValue("MinZhuanSheng", -1) && changeLifeCount <= systemXmlItem.GetIntValue("MaxZhuanSheng", -1))
				{
					if (level >= systemXmlItem.GetIntValue("MinLevel", -1) && level <= systemXmlItem.GetIntValue("MaxLevel", -1))
					{
						result = systemXmlItem.GetIntValue("ID", -1);
						break;
					}
				}
			}
			return result;
		}

		public static TCPProcessCmdResults ProcessScoreBoxCMD(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				int num = Convert.ToInt32(array[0]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (GameManager.PlatConfigMgr.GetGameConfigItemStr("PingFenGift", "0") != "1")
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int scoreBoxState = GameManager.ClientMgr.GetScoreBoxState(gameClient);
				if (2 == scoreBoxState)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (1 == Convert.ToInt32(array[1]))
				{
					if (gameClient.ClientData.Level < 31 && gameClient.ClientData.ChangeLifeCount == 0)
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
					int nOpen = scoreBoxState;
					GameManager.ClientMgr.ModifyScoreBoxState(gameClient, 2);
					if (!GameManager.ClientMgr.AddUserGold(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, gameClient, 150, "评分领取绑钻"))
					{
						GameManager.ClientMgr.ModifyScoreBoxState(gameClient, nOpen);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "0", nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "1", nID);
				}
				else if (0 == Convert.ToInt32(array[1]))
				{
					if (1 == scoreBoxState)
					{
						GameManager.ClientMgr.ModifyScoreBoxState(gameClient, 2);
					}
					else
					{
						GameManager.ClientMgr.ModifyScoreBoxState(gameClient, 1);
					}
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "1", nID);
				}
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, "ProcessGetFirstChargeInfoCMD", false, false);
			}
			return TCPProcessCmdResults.RESULT_DATA;
		}

