		public static int UseGoodsBindOrNot(GameClient client, int needID, int needCount, bool useBindFirst, out bool useBind, out bool useTimeLimit)
		{
			useBind = false;
			useTimeLimit = false;
			int num = 0;
			int num2 = 0;
			GoodsData bindGoodsByID = Global.GetBindGoodsByID(client, needID);
			GoodsData notBindGoodsByID = Global.GetNotBindGoodsByID(client, needID);
			int result;
			if (bindGoodsByID == null && notBindGoodsByID == null)
			{
				result = -1;
			}
			else
			{
				int num3 = 0;
				if (bindGoodsByID != null)
				{
					num = Global.GetTotalBindGoodsCountByID(client, bindGoodsByID.GoodsID);
					num3 += num;
				}
				if (notBindGoodsByID != null)
				{
					num2 = Global.GetTotalNotBindGoodsCountByID(client, notBindGoodsByID.GoodsID);
					num3 += num2;
				}
				if (num3 < needCount)
				{
					result = -1;
				}
				else
				{
					int num4 = 0;
					if (useBindFirst && num > 0)
					{
						int num5;
						if (num < needCount)
						{
							num5 = needCount - num;
							num4 = num;
						}
						else
						{
							num5 = 0;
							num4 = needCount;
						}
						if (bindGoodsByID != null && !GameManager.ClientMgr.NotifyUseBindGoods(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, bindGoodsByID.GoodsID, num4, false, out useBind, out useTimeLimit, false))
						{
							return -2;
						}
						if (num5 > 0 && notBindGoodsByID != null && !GameManager.ClientMgr.NotifyUseNotBindGoods(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, notBindGoodsByID.GoodsID, num5, false, out useBind, out useTimeLimit, false))
						{
							return -2;
						}
						useBind = true;
					}
					else
					{
						int num5;
						if (num2 > 0)
						{
							if (num2 < needCount)
							{
								num5 = needCount - num2;
								num4 = num2;
							}
							else
							{
								num5 = 0;
								num4 = needCount;
							}
						}
						else if (num > needCount)
						{
							num5 = needCount;
						}
						else
						{
							num5 = num;
						}
						if (num4 > 0 && notBindGoodsByID != null && !GameManager.ClientMgr.NotifyUseNotBindGoods(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, client, notBindGoodsByID.GoodsID, num4, false, out useBind, out useTimeLimit, false))
						{
							return -2;
						}
						if (num5 > 0)
						{
