		public static string GetJson(Dictionary<string, string> jsonDict)
		{
			string result;
			if (jsonDict == null || jsonDict.Count <= 0)
			{
				result = "";
			}
			else
			{
				string text = "{";
				bool flag = true;
				foreach (KeyValuePair<string, string> keyValuePair in jsonDict)
				{
					if (!flag)
					{
						text += ",";
					}
					text += string.Format("\"{0}\":\"{1}\"", keyValuePair.Key, keyValuePair.Value);
					flag = false;
				}
				text += "}";
				result = text;
			}
			return result;
		}

		public static string doPost(string url, string body, int timeout = 0)
		{
			string name = "utf-8";
			string text = "";
			string result;
			if (url == null || url == "")
			{
				result = null;
			}
			else
			{
				WebRequest webRequest = WebRequest.Create(url);
				webRequest.Method = "POST";
				webRequest.ContentType = "application/x-www-form-urlencoded";
				if (timeout > 0)
				{
					webRequest.Timeout = timeout;
				}
				if (body == null)
				{
					webRequest.ContentLength = 0L;
				}
				else
				{
					try
					{
						byte[] bytes = Encoding.Default.GetBytes(body);
						webRequest.ContentLength = (long)bytes.Length;
						Stream requestStream = webRequest.GetRequestStream();
						requestStream.Write(bytes, 0, bytes.Length);
						requestStream.Close();
					}
					catch (Exception e)
					{
						DataHelper.WriteFormatExceptionLog(e, "doPost", false, false);
						return null;
					}
				}
				try
				{
					Stream responseStream = webRequest.GetResponse().GetResponseStream();
					byte[] array = new byte[512];
					for (int i = responseStream.Read(array, 0, 512); i > 0; i = responseStream.Read(array, 0, 512))
					{
						Encoding encoding = Encoding.GetEncoding(name);
						text += encoding.GetString(array, 0, i);
					}
					result = text;
				}
				catch (Exception e2)
				{
					DataHelper.WriteFormatExceptionLog(e2, "doPost", false, false);
					result = null;
				}
			}
			return result;
		}

		public static bool IsCanGiveRewardByOccupation(GameClient client, int goodsId)
		{
			bool result;
			if (null == client)
			{
				result = false;
			}
			else
			{
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsId, out systemXmlItem))
				{
					result = false;
				}
				else
				{
					int nOccu = Global.CalcOriginalOccupationID(client.ClientData.Occupation);
					int mainOccupationByGoodsID = Global.GetMainOccupationByGoodsID(goodsId);
					if (mainOccupationByGoodsID == -1)
					{
						result = true;
					}
					else if (Global.IsRoleOccupationMatchGoods(nOccu, goodsId))
					{
						result = (!GameManager.MagicSwordMgr.IsMagicSword(nOccu) || GameManager.MagicSwordMgr.IsCanAward2MagicSword(client, goodsId));
					}
					else
					{
						if (GameManager.MagicSwordMgr.IsMagicSword(nOccu))
						{
							if (GameManager.MagicSwordMgr.IsMagicSwordAngelWeapon(client, goodsId))
							{
								return true;
