						}
						else if (GameManager.SummonerMgr.IsSummoner(nOccu))
						{
							if (GameManager.SummonerMgr.IsSummonerWeapon(client, goodsId))
							{
								return true;
							}
						}
						result = false;
					}
				}
			}
			return result;
		}

