		public static void UpdateRoleLoginRecord(GameClient client)
		{
			int offsetDayNow = Global.GetOffsetDayNow();
			string roleParamByName = Global.GetRoleParamByName(client, "RoleLoginRecorde");
			int num = 0;
			string text = "";
			string[] array = (roleParamByName == null) ? null : roleParamByName.Split(new char[]
			{
				','
			});
			if (array != null && array.Length == 2)
			{
				num = Convert.ToInt32(array[0]);
				text = array[1];
			}
			if (num >= offsetDayNow)
			{
				LingDiCaiJiManager.getInstance().InitRoleLingDiCaiJiData(client, false);
				YaoSaiBossManager.getInstance().OnLogin(client, false);
				YaoSaiMissionManager.getInstance().OnLogin(client, false);
			}
			else
			{
				if (num > 0)
				{
					for (int i = num + 1; i < offsetDayNow; i++)
					{
						text = "0" + text;
					}
				}
				text = "1" + text;
				if (text.Length > Global.RoleLoginRecordDayCount)
				{
					text = text.Substring(0, Global.RoleLoginRecordDayCount);
				}
				string valueString = string.Format("{0},{1}", offsetDayNow, text);
				LingDiCaiJiManager.getInstance().InitRoleLingDiCaiJiData(client, true);
				YaoSaiBossManager.getInstance().OnLogin(client, true);
				YaoSaiMissionManager.getInstance().OnLogin(client, true);
				Global.SaveRoleParamsStringToDB(client, "RoleLoginRecorde", valueString, true);
				Global.SaveRoleParamsInt32ValueToDB(client, "10175", 0, true);
				int num2 = Global.GetRoleParamsInt32FromDB(client, "10167");
				int num3 = (num2 > 10) ? 10 : 0;
				num2 %= 10;
				if (num2 == 3)
				{
					Global.SaveRoleParamsInt32ValueToDB(client, "10167", 2 + num3, true);
				}
			}
		}

		public static bool CheckRoleIsLoginByTime(GameClient client, DateTime beginTime, DateTime endTime)
		{
			int offsetDay = Global.GetOffsetDay(beginTime);
			int offsetDay2 = Global.GetOffsetDay(endTime);
			int offsetDay3 = Global.GetOffsetDay(Global.GetKaiFuTime());
			string roleParamByName = Global.GetRoleParamByName(client, "RoleLoginRecorde");
			int num = 0;
			string text = "";
			string[] array = (roleParamByName == null) ? null : roleParamByName.Split(new char[]
			{
				','
			});
			if (array != null && array.Length == 2)
			{
				num = Convert.ToInt32(array[0]);
				text = array[1];
			}
			int length = text.Length;
			bool result;
			if (length <= 0)
			{
				result = false;
			}
			else
			{
				int num2 = offsetDay;
				while (num2 <= offsetDay2 && num2 <= num)
				{
					if (num2 < offsetDay3)
					{
						return true;
					}
					int num3 = num - num2;
					if (num3 < length)
					{
						if ('1' == text[num3])
						{
							return true;
						}
					}
					num2++;
				}
				result = false;
			}
			return result;
		}

