		public static bool AutoRevive(GameClient client)
		{
			bool result;
			if (null == client)
			{
				result = false;
			}
			else
			{
				long num = TimeUtil.NOW();
				long roleParamsInt64FromDB = Global.GetRoleParamsInt64FromDB(client, "LastAutoReviveTicks");
				if (roleParamsInt64FromDB > 0L && num - roleParamsInt64FromDB < (long)(MerlinSystemParamsConfigData._ReviveCDTime * 1000))
				{
					result = false;
				}
				else
				{
					int num2 = (int)(RoleAlgorithm.GetAutoRevivePercent(client) * 10000.0);
					if (num2 <= 0)
					{
						result = false;
					}
					else
					{
						int randomNumber = Global.GetRandomNumber(0, 10001);
						if (randomNumber > num2)
						{
							result = false;
						}
						else if (!Global.IsAutoReviveMap(client.ClientData.MapCode))
						{
							result = false;
						}
						else
						{
							Global.SaveRoleParamsInt64ValueToDB(client, "LastAutoReviveTicks", num, true);
							Global.ClientRealive(client, client.ClientData.PosX, client.ClientData.PosY, client.ClientData.RoleDirection);
							result = true;
						}
					}
				}
			}
			return result;
		}

		public static bool CancelTask(GameClient client, int dbID, int taskID)
		{
			string strcmd = StringUtil.substitute("{0}:{1}:{2}", new object[]
			{
				client.ClientData.RoleID,
				dbID,
				taskID
			});
			string[] array = Global.ExecuteDBCmd(154, strcmd, client.ServerId);
			bool result;
			if (array == null || array.Length < 1 || array[0] == "-1")
			{
				result = false;
			}
			else
			{
				if (null != client.ClientData.TaskDataList)
				{
					ProcessTask.ClearTaskGoods(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, taskID);
					lock (client.ClientData.TaskDataList)
					{
						for (int i = 0; i < client.ClientData.TaskDataList.Count; i++)
						{
							if (client.ClientData.TaskDataList[i].DoingTaskID == taskID)
							{
								client.ClientData.TaskDataList.RemoveAt(i);
								break;
							}
						}
					}
				}
				SystemXmlItem systemXmlItem = null;
				if (GameManager.SystemTasksMgr.SystemXmlItemDict.TryGetValue(taskID, out systemXmlItem))
				{
					int intValue = systemXmlItem.GetIntValue("SourceNPC", -1);
					if (-1 != intValue)
					{
						int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue, 0);
						GameManager.ClientMgr.NotifyUpdateNPCTaskSate(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, intValue + 2130706432, state);
					}
					int intValue2 = systemXmlItem.GetIntValue("DestNPC", -1);
					if (-1 != intValue2 && intValue != intValue2)
					{
						int state = Global.ComputeNPCTaskState(client, client.ClientData.TaskDataList, intValue2, 0);
						GameManager.ClientMgr.NotifyUpdateNPCTaskSate(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, intValue2 + 2130706432, state);
					}
					GameManager.ClientMgr.NotifyDailyTaskData(client);
				}
				result = true;
			}
			return result;
		}

