		public static bool AutoUpChangeLifeAndLevel(GameClient client, int nDestChangeLifeCount, int nDestLevel)
		{
			bool result;
			if (null == client)
			{
				LogManager.WriteLog(2, string.Format("client不存在，服务器无法驱动转生", new object[0]), null, true);
				result = false;
			}
			else
			{
				int roleID = client.ClientData.RoleID;
				try
				{
					int level = client.ClientData.Level;
					int changeLifeCount = client.ClientData.ChangeLifeCount;
					if (changeLifeCount >= nDestChangeLifeCount && level >= nDestLevel)
					{
						return false;
					}
					if (nDestLevel <= 0 && nDestLevel > Data.LevelUpExperienceList.Length - 1)
					{
						LogManager.WriteLog(2, string.Format("等级越界，服务器无法驱动转生，RoleID{0}", roleID), null, true);
						return false;
					}
					int num = (int)GameManager.systemParamsList.GetParamValueIntByName("ChangeLifeMaxValue", -1);
					if (nDestChangeLifeCount > num)
					{
						LogManager.WriteLog(2, string.Format("转生次数已达上限，服务器无法驱动转生，RoleID{0}", roleID), null, true);
						return false;
					}
					if (nDestChangeLifeCount < changeLifeCount)
					{
						LogManager.WriteLog(2, string.Format("要转生次数低于当前转生次数，服务器无法驱动转生，RoleID{0}", roleID), null, true);
						return false;
					}
					if (nDestChangeLifeCount == changeLifeCount && nDestLevel <= level)
					{
						LogManager.WriteLog(2, string.Format("转生次数相同，但目标等级低于当前等级，服务器无法驱动转生，RoleID{0}", roleID), null, true);
						return false;
					}
					while (client.ClientData.ChangeLifeCount < nDestChangeLifeCount || client.ClientData.Level < nDestLevel)
					{
						if (client.ClientData.ChangeLifeCount < nDestChangeLifeCount)
						{
							int level2 = client.ClientData.Level;
							for (int i = level2; i < Data.LevelUpExperienceList.Length - 1; i++)
							{
								long curRoleLvUpNeedExp = GameManager.ClientMgr.GetCurRoleLvUpNeedExp(client);
								if (curRoleLvUpNeedExp <= 0L)
								{
									LogManager.WriteLog(2, string.Format("经验表数据错误，升级所需经验为0，服务器无法驱动转生，RoleID{0}", roleID), null, true);
									return false;
								}
								GameManager.ClientMgr.ProcessRoleExperience(client, curRoleLvUpNeedExp, true, true, false, "none");
							}
							if (!Global.ProcessChangeLifeByServer(client))
							{
								LogManager.WriteLog(2, string.Format("执行转身过程中出现错误，服务器无法驱动转生，RoleID{0}", roleID), null, true);
								return false;
							}
						}
						else if (client.ClientData.Level < nDestLevel)
						{
							int level2 = client.ClientData.Level;
							for (int i = level2; i < nDestLevel; i++)
							{
								long curRoleLvUpNeedExp = GameManager.ClientMgr.GetCurRoleLvUpNeedExp(client);
								if (curRoleLvUpNeedExp <= 0L)
								{
									LogManager.WriteLog(2, string.Format("经验表数据错误，升级所需经验为0，服务器无法驱动转生，RoleID{0}", roleID), null, true);
									return false;
								}
								GameManager.ClientMgr.ProcessRoleExperience(client, curRoleLvUpNeedExp, true, true, false, "none");
							}
						}
					}
					GameManager.DBCmdMgr.AddDBCmd(10002, string.Format("{0}:{1}:{2}", client.ClientData.RoleID, client.ClientData.Level, client.ClientData.Experience), null, client.ServerId);
					return true;
				}
				catch (Exception e)
				{
					DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(client.ClientSocket), false, false);
				}
				result = false;
			}
			return result;
		}

		public static bool ProcessChangeLifeByServer(GameClient client)
		{
			try
			{
				if (null == client)
				{
					LogManager.WriteLog(2, string.Format("client不存在，服务器无法驱动转生", new object[0]), null, true);
					return false;
				}
				int roleID = client.ClientData.RoleID;
				int num = (int)GameManager.systemParamsList.GetParamValueIntByName("ChangeLifeMaxValue", -1);
				if (client.ClientData.ChangeLifeCount >= num)
				{
					LogManager.WriteLog(2, string.Format("已达到最高转生等级，服务器无法驱动转生{0}", roleID), null, true);
					return false;
				}
				int num2 = client.ClientData.ChangeLifeCount + 1;
				Dictionary<int, ChangeLifeDataInfo> dictionary = new Dictionary<int, ChangeLifeDataInfo>();
				if (!GameManager.ChangeLifeMgr.m_ChangeLifeInfoList.TryGetValue(client.ClientData.Occupation, out dictionary) || dictionary == null)
				{
					LogManager.WriteLog(2, string.Format("配置错误1，服务器无法驱动转生{0}", roleID), null, true);
					return false;
				}
				ChangeLifeDataInfo changeLifeDataInfo = new ChangeLifeDataInfo();
				if (!dictionary.TryGetValue(num2, out changeLifeDataInfo) || changeLifeDataInfo == null)
				{
					LogManager.WriteLog(2, string.Format("配置错误2，服务器无法驱动转生{0}", roleID), null, true);
					return false;
				}
				int level = client.ClientData.Level;
				if (level < changeLifeDataInfo.NeedLevel)
				{
					LogManager.WriteLog(2, string.Format("等级不足，服务器无法驱动转生{0}", roleID), null, true);
					return false;
				}
				TCPOutPacket tcpoutPacket = null;
				string strcmd = string.Format("{0}:{1}", roleID, num2);
				TCPProcessCmdResults tcpprocessCmdResults = Global.RequestToDBServer2(Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, 509, strcmd, out tcpoutPacket, client.ServerId);
				if (TCPProcessCmdResults.RESULT_FAILED == tcpprocessCmdResults)
				{
					LogManager.WriteLog(2, string.Format("与DBServer通讯失败, 服务器无法驱动转生{0}:CMD={1}", roleID, 509), null, true);
					return false;
				}
				string @string = new UTF8Encoding().GetString(tcpoutPacket.GetPacketBytes(), 6, tcpoutPacket.PacketDataSize - 6);
				Global.PushBackTcpOutPacket(tcpoutPacket);
				string[] array = @string.Split(new char[]
				{
					':'
				});
				if (array[1] == "-1")
				{
					LogManager.WriteLog(2, string.Format("转生时 DBServer发生错误, 服务器无法驱动转生{0}:CMD={1}", roleID, 509), null, true);
					return false;
				}
				client.ClientData.ChangeLifeCount++;
				long experience = client.ClientData.Experience;
				client.ClientData.Level = 1;
				client.ClientData.Experience = 0L;
				HuodongCachingMgr.ProcessGetUpLevelGift(client, false);
				if (experience <= 0L)
				{
					GameManager.ClientMgr.NotifySelfExperience(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, experience);
				}
				else
				{
					GameManager.ClientMgr.ProcessRoleExperience(client, experience, false, true, false, "none");
				}
				GameManager.ChangeLifeMgr.InitPlayerChangeLifePorperty(client);
				GameManager.ClientMgr.NotifyUpdateEquipProps(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client);
				GameManager.ClientMgr.NotifyOthersLifeChanged(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, client, true, true, 7);
				Global.AutoLearnSkills(client);
				if (changeLifeDataInfo.AwardGoodsDataList != null)
				{
					for (int i = 0; i < changeLifeDataInfo.AwardGoodsDataList.Count; i++)
					{
						Global.AddGoodsDBCommand(Global._TCPManager.TcpOutPacketPool, client, changeLifeDataInfo.AwardGoodsDataList[i].GoodsID, changeLifeDataInfo.AwardGoodsDataList[i].GCount, 0, "", 0, 1, 0, "", true, 1, "转生奖励物品", "1900-01-01 12:00:00", 0, 0, 0, 0, 0, 0, 0, null, null, 0, true);
					}
				}
				ChengJiuManager.OnRoleChangeLife(client);
				SpreadManager.getInstance().SpreadIsLevel(client);
				FundManager.FundChangeLife(client);
				return true;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(client.ClientSocket), false, false);
			}
			return false;
		}

